  'bg-amber-400/30 border-amber-400/60 text-amber-200',
  'bg-emerald-400/30 border-emerald-400/60 text-emerald-200',
  'bg-rose-400/30 border-rose-400/60 text-rose-200',
  'bg-cyan-400/30 border-cyan-400/60 text-cyan-200',
  'bg-orange-400/30 border-orange-400/60 text-orange-200',
  'bg-indigo-400/30 border-indigo-400/60 text-indigo-200',
];

type Props = {
  columns: number;
  gap: number;
  rowHeight: number;
  denseFill: boolean;
  items: KangurLessonGridItem[];
  focusedItemId?: string | null;
  onFocusItem?: (itemId: string) => void;
};

export function GridLayoutCanvas({
  columns,
  items,
  focusedItemId,
  onFocusItem,
}: Props): React.JSX.Element {
  if (items.length === 0) {
    return (
      <div className='flex h-16 items-center justify-center rounded-xl border border-dashed border-border/60 text-xs text-muted-foreground'>
        No items yet — add grid items below.
      </div>
    );
  }

  // Build a CSS-grid string representation using inline style.
  const gridStyle: React.CSSProperties = {
    display: 'grid',
    gridTemplateColumns: `repeat(${columns}, minmax(0, 1fr))`,
    gap: '4px',
  };

  return (
    <div className='rounded-xl border border-border/60 bg-card/30 p-3'>
      <div className='mb-1.5 text-[10px] font-semibold uppercase tracking-wide text-muted-foreground'>
        Layout preview · {columns} column{columns !== 1 ? 's' : ''} · {items.length} item
        {items.length !== 1 ? 's' : ''}
      </div>
      <div style={gridStyle}>
        {items.map((item, index) => {
          const color = ITEM_COLORS[index % ITEM_COLORS.length] ?? ITEM_COLORS[0];
          const colSpan = Math.min(item.colSpan, columns);

          const itemStyle: React.CSSProperties = {
            gridColumn: item.columnStart
              ? `${item.columnStart} / span ${colSpan}`
              : `span ${colSpan}`,
            gridRow: item.rowStart
              ? `${item.rowStart} / span ${item.rowSpan}`
              : `span ${item.rowSpan}`,
            minHeight: '36px',
          };

          const isFocused = focusedItemId === item.id;

          return (
            <button
              key={item.id}
              type='button'
              style={itemStyle}
              onClick={(): void => onFocusItem?.(item.id)}
              className={cn(
                'flex flex-col items-center justify-center rounded-lg border px-2 py-1.5 text-center text-[10px] font-medium transition focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 focus-visible:ring-offset-2 ring-offset-background',
                color,
                isFocused && 'ring-2 ring-white/60',
                onFocusItem ? 'cursor-pointer hover:brightness-110' : 'cursor-default'
              )}
              aria-label={`Grid item ${index + 1}: ${item.block.type}`}
            >
              <span className='font-semibold'>#{index + 1}</span>
              <span className='opacity-80'>{item.block.type}</span>
              {colSpan > 1 || item.rowSpan > 1 ? (
                <span className='mt-0.5 opacity-60'>
                  {colSpan}×{item.rowSpan}
                </span>
              ) : null}
            </button>
          );
        })}
      </div>
    </div>
  );
}

'use client';

import Image from 'next/image';
import React, { useEffect, useState } from 'react';

import { MediaLibraryPanel } from '@/features/cms/public';
import {
  isSvgImageSource,
  normalizeSvgImageSource,
} from '@/features/kangur/lesson-documents/utils';
import type { KangurLessonInlineBlock } from '@/features/kangur/shared/contracts/kangur';
import { Badge, Button, FormField, Input, SelectSimple, Textarea } from '@/features/kangur/shared/ui';
import { cn } from '@/features/kangur/shared/utils';

import { ALIGNMENT_OPTIONS, MEDIA_FIT_OPTIONS } from '../constants';
import { clamp, parseNumberInput } from '../utils';
import { SvgCodeEditor, extractSvgViewBox } from './SvgCodeEditor';

const LazyDocumentWysiwygEditor = React.lazy(() =>
  import('@/shared/lib/document-editor/public').then((mod) => ({
    default: mod.DocumentWysiwygEditor,
  }))
);

const SVG_IMAGE_SOURCE_HELPER_TEXT = 'Only SVG files can be used in Kangur lesson image blocks.';

const isSvgUploadFile = (file: File): boolean => {
  const fileType = file.type.trim().toLowerCase();
  return fileType === 'image/svg+xml' || file.name.trim().toLowerCase().endsWith('.svg');
};

export function InlineEditorCard(props: {
  block: KangurLessonInlineBlock;
  onChange: (nextValue: KangurLessonInlineBlock) => void;
  heading: string;
  accent?: 'text' | 'svg' | 'image';
}): React.JSX.Element {
  const { block, onChange, heading, accent = 'text' } = props;
  const [showMediaLibrary, setShowMediaLibrary] = useState(false);
  const imageSource = block.type === 'image' ? block.src : '';
  const [imageSourceDraft, setImageSourceDraft] = useState(imageSource);
  const [imageSourceError, setImageSourceError] = useState<string | null>(null);

  useEffect(() => {
    setImageSourceDraft(imageSource);
    setImageSourceError(null);
  }, [block.id, imageSource]);

  const commitImageSource = (nextValue: string): void => {
    if (block.type !== 'image') return;

    const trimmed = nextValue.trim();
    if (!trimmed) {
      setImageSourceDraft('');
      setImageSourceError(null);
      if (block.src) {
        onChange({ ...block, src: '' });
      }
      return;
    }

    const normalized = normalizeSvgImageSource(trimmed);
    if (!normalized) {
      setImageSourceDraft(block.src);
      setImageSourceError(SVG_IMAGE_SOURCE_HELPER_TEXT);
      return;
    }

    setImageSourceDraft(normalized);
    setImageSourceError(null);
    if (normalized !== block.src) {
      onChange({ ...block, src: normalized });
    }
  };

  return (
    <div
      className={cn(
        'rounded-2xl border p-4',
        accent === 'svg'
          ? 'border-sky-200/80 bg-sky-50/60'
          : accent === 'image'
            ? 'border-amber-200/80 bg-amber-50/60'
            : 'border-indigo-200/80 bg-indigo-50/50'
      )}
    >
      <div className='mb-3 flex items-center justify-between gap-2'>
        <div className='text-sm font-semibold text-slate-800'>{heading}</div>
        <Badge variant='outline' className='text-[10px] uppercase tracking-wide'>
          {block.type}
        </Badge>
      </div>

      {block.type === 'text' ? (
        <div className='space-y-3'>
          <FormField label='Alignment'>
            <SelectSimple
              size='sm'
              value={block.align}
              onValueChange={(nextValue: string): void => {
                if (nextValue !== 'left' && nextValue !== 'center' && nextValue !== 'right') return;
                onChange({ ...block, align: nextValue });
              }}
              options={ALIGNMENT_OPTIONS}
              triggerClassName='h-9'
             ariaLabel='Alignment' title='Alignment'/>
          </FormField>

          <FormField label='Text Content'>
            <React.Suspense
              fallback={
                <div className='min-h-[200px] rounded-lg border border-border/40 bg-card/20 p-4 text-sm text-muted-foreground'>
                  Loading editor...
                </div>
              }
            >
              <LazyDocumentWysiwygEditor
                value={block.html}
                onChange={(nextValue): void => {
                  onChange({ ...block, html: nextValue });
                }}
                placeholder='Write the lesson text here...'
              />
            </React.Suspense>
          </FormField>

          <FormField label='Narration Override'>
            <Textarea
              value={block.ttsText ?? ''}
              onChange={(event): void => {
                onChange({ ...block, ttsText: event.target.value });
              }}
              placeholder='Optional spoken version for this block'
              className='min-h-[100px]'
             aria-label='Optional spoken version for this block' title='Optional spoken version for this block'/>
          </FormField>
        </div>
      ) : block.type === 'svg' ? (
        <div className='space-y-3'>
          <div className='grid gap-3 md:grid-cols-2'>
            <FormField label='Title'>
              <Input
                value={block.title}
                onChange={(event): void => {
                  onChange({ ...block, title: event.target.value });
                }}
                placeholder='Optional SVG title'
                className='h-9'
               aria-label='Optional SVG title' title='Optional SVG title'/>
            </FormField>
            <FormField label='Alignment'>
              <SelectSimple
                size='sm'
                value={block.align}
                onValueChange={(nextValue: string): void => {
                  if (nextValue !== 'left' && nextValue !== 'center' && nextValue !== 'right')
                    return;
                  onChange({ ...block, align: nextValue });
                }}
                options={ALIGNMENT_OPTIONS}
                triggerClassName='h-9'
               ariaLabel='Alignment' title='Alignment'/>
            </FormField>
          </div>

          <div className='grid gap-3 md:grid-cols-3'>
            <FormField label='ViewBox'>
              <Input
                value={block.viewBox}
                onChange={(event): void => {
                  onChange({ ...block, viewBox: event.target.value });
                }}
                placeholder='0 0 100 100'
                className='h-9'
               aria-label='0 0 100 100' title='0 0 100 100'/>
            </FormField>

            <FormField label='Fit'>
              <SelectSimple
                size='sm'
                value={block.fit}
                onValueChange={(nextValue: string): void => {
                  if (nextValue !== 'contain' && nextValue !== 'cover' && nextValue !== 'none')
                    return;
                  onChange({ ...block, fit: nextValue });
                }}
                options={MEDIA_FIT_OPTIONS}
                triggerClassName='h-9'
               ariaLabel='Fit' title='Fit'/>
            </FormField>

            <FormField label='Max Width'>
              <Input
                type='number'
                min={120}
                max={1200}
                value={String(block.maxWidth)}
                onChange={(event): void => {
                  onChange({
                    ...block,
                    maxWidth: clamp(
                      parseNumberInput(event.target.value, block.maxWidth),
                      120,
                      1200
                    ),
                  });
                }}
                className='h-9'
               aria-label='Max Width' title='Max Width'/>
            </FormField>
          </div>

          <div className='space-y-1.5'>
            <div className='text-xs font-semibold uppercase tracking-wide text-muted-foreground'>
              SVG Markup
            </div>
            <SvgCodeEditor
              value={block.markup}
              onChange={(nextMarkup): void => {
                const detectedViewBox = extractSvgViewBox(nextMarkup);
                onChange({
                  ...block,
                  markup: nextMarkup,
                  viewBox: detectedViewBox ?? block.viewBox,
                });
              }}
              previewSize='lg'
              placeholder='<svg viewBox="0 0 200 120" xmlns="http://www.w3.org/2000/svg">\n  <!-- SVG content -->\n</svg>'
            />
          </div>

          <FormField label='Narration Description'>
            <Textarea
              value={block.ttsDescription ?? ''}
              onChange={(event): void => {
                onChange({ ...block, ttsDescription: event.target.value });
              }}
              placeholder='Optional spoken description of this illustration'
              className='min-h-[100px]'
             aria-label='Optional spoken description of this illustration' title='Optional spoken description of this illustration'/>
          </FormField>
        </div>
      ) : (
        <div className='space-y-3'>
          <div className='grid gap-3 md:grid-cols-2'>
            <FormField label='Title'>
              <Input
                value={block.title}
                onChange={(event): void => {
                  onChange({ ...block, title: event.target.value });
                }}
                placeholder='Optional image title'
                className='h-9'
               aria-label='Optional image title' title='Optional image title'/>
            </FormField>
            <FormField label='Alt Text'>
              <Input
                value={block.altText ?? ''}
                onChange={(event): void => {
                  onChange({ ...block, altText: event.target.value });
                }}
                placeholder='Describe the image for accessibility'
                className='h-9'
               aria-label='Describe the image for accessibility' title='Describe the image for accessibility'/>
            </FormField>
          </div>

          <div className='grid gap-3 md:grid-cols-3'>
            <FormField label='Alignment'>
              <SelectSimple
                size='sm'
                value={block.align}
                onValueChange={(nextValue: string): void => {
                  if (nextValue !== 'left' && nextValue !== 'center' && nextValue !== 'right')
                    return;
                  onChange({ ...block, align: nextValue });
                }}
                options={ALIGNMENT_OPTIONS}
                triggerClassName='h-9'
               ariaLabel='Alignment' title='Alignment'/>
            </FormField>

            <FormField label='Fit'>
              <SelectSimple
                size='sm'
                value={block.fit}
                onValueChange={(nextValue: string): void => {
                  if (nextValue !== 'contain' && nextValue !== 'cover' && nextValue !== 'none')
                    return;
                  onChange({ ...block, fit: nextValue });
                }}
                options={MEDIA_FIT_OPTIONS}
                triggerClassName='h-9'
               ariaLabel='Fit' title='Fit'/>
            </FormField>

            <FormField label='Max Width'>
              <Input
                type='number'
                min={120}
                max={1200}
                value={String(block.maxWidth)}
                onChange={(event): void => {
                  onChange({
                    ...block,
                    maxWidth: clamp(
                      parseNumberInput(event.target.value, block.maxWidth),
                      120,
                      1200
                    ),
                  });
                }}
                className='h-9'
               aria-label='Max Width' title='Max Width'/>
            </FormField>
          </div>

          <FormField label='Caption'>
            <Textarea
              value={block.caption ?? ''}
              onChange={(event): void => {
                onChange({ ...block, caption: event.target.value });
              }}
              placeholder='Optional caption under the image'
              className='min-h-[90px]'
             aria-label='Optional caption under the image' title='Optional caption under the image'/>
          </FormField>

          <FormField label='Narration Description'>
            <Textarea
              value={block.ttsDescription ?? ''}
              onChange={(event): void => {
                onChange({ ...block, ttsDescription: event.target.value });
              }}
              placeholder='Optional spoken description of this image'
              className='min-h-[100px]'
             aria-label='Optional spoken description of this image' title='Optional spoken description of this image'/>
          </FormField>

          <FormField label='Image Source (SVG only)'>
            <div className='space-y-2'>
              <Input
                value={imageSourceDraft}
                onChange={(event): void => {
                  setImageSourceDraft(event.target.value);
                  setImageSourceError(null);
                }}
                onBlur={(): void => commitImageSource(imageSourceDraft)}
                placeholder='/uploads/...svg or https://...svg'
                className='h-9'
               aria-label='/uploads/...svg or https://...svg' title='/uploads/...svg or https://...svg'/>
              <div className='text-xs text-slate-600'>
                {imageSourceError ?? SVG_IMAGE_SOURCE_HELPER_TEXT}
              </div>
              <div className='flex flex-wrap gap-2'>
                <Button
                  type='button'
                  size='sm'
                  variant='outline'
                  className='h-8 px-3'
                  onClick={(): void => setShowMediaLibrary(true)}
                >
                  Choose from library
                </Button>
                {block.src.trim() ? (
                  <Button
                    type='button'
                    size='sm'
                    variant='outline'
                    className='h-8 px-3'
                    onClick={(): void => {
                      setImageSourceDraft('');
                      setImageSourceError(null);
                      onChange({ ...block, src: '' });
                    }}
                  >
                    Clear source
                  </Button>
                ) : null}
              </div>
            </div>
          </FormField>

          {isSvgImageSource(block.src) ? (
            <div className='overflow-hidden rounded-2xl border border-amber-200 bg-white/80 p-3'>
              <Image
                src={block.src}
                alt={block.altText?.trim() || block.title.trim() || 'Lesson illustration'}
                width={1200}
                height={260}
                unoptimized
                className='max-h-[260px] w-full rounded-xl object-contain'
              />
            </div>
          ) : null}

          <MediaLibraryPanel
            open={showMediaLibrary}
            onOpenChange={setShowMediaLibrary}
            selectionMode='single'
            autoConfirmSelection
            title='SVG Library'
            accept='.svg,image/svg+xml'
            supportedFormatsLabel='SVG files'
            uploadButtonLabel='Upload SVG files'
            filepathFilter={isSvgImageSource}
            filterUploadFiles={(files): File[] => files.filter((file) => isSvgUploadFile(file))}
            invalidSelectionMessage={SVG_IMAGE_SOURCE_HELPER_TEXT}
            invalidUploadMessage={SVG_IMAGE_SOURCE_HELPER_TEXT}
            onSelect={(filepaths): void => {
              const nextSrc = filepaths[0];
              if (!nextSrc) return;
              commitImageSource(nextSrc);
              setShowMediaLibrary(false);
            }}
          />
        </div>
      )}
    </div>
  );
}

