'use client';

import { useEffect, useMemo, useState } from 'react';
import { validateKangurAiTutorOnboardingContent } from '@/features/kangur/ai-tutor/onboarding-validation';
import {
  buildKangurAiTutorContentTranslationStatusBySectionKey,
  type KangurAiTutorContentTranslatableSectionKey,
} from '@/features/kangur/server/ai-tutor-content-locale-scaffold';
import {
  parseKangurAiTutorContent,
  type KangurAiTutorContent,
} from '@/features/kangur/shared/contracts/kangur-ai-tutor-content';
import type {
  KangurAiTutorTranslationStatusDto,
} from '@/shared/contracts/kangur-ai-tutor-locale-scaffold';
import { PROMPT_ENGINE_SETTINGS_KEY } from '@/shared/contracts/prompt-engine';
import { VALIDATOR_PATTERN_LISTS_KEY, parseValidatorPatternLists } from '@/shared/contracts/validator';
import { api } from '@/shared/lib/api-client';
import { getEnabledSiteLocaleCodes } from '@/shared/lib/i18n/site-locale';
import { parsePromptEngineSettings } from '@/shared/lib/prompt-engine/settings';
import { useSettingsStore } from '@/features/kangur/shared/providers/SettingsStoreProvider';
import { useToast } from '@/features/kangur/shared/ui';
import {
  withKangurClientError,
  withKangurClientErrorSync,
} from '@/features/kangur/observability/client';

export const AI_TUTOR_CONTENT_EDITOR_LOCALE = 'pl';
export const AI_TUTOR_CONTENT_TRANSLATION_LOCALES = getEnabledSiteLocaleCodes().filter(
  (locale) => locale !== AI_TUTOR_CONTENT_EDITOR_LOCALE
);
const EMPTY_AI_TUTOR_CONTENT_EDITOR_VALUE = '';

export type SectionTranslationFilterStatus = Extract<
  KangurAiTutorTranslationStatusDto,
  'manual' | 'scaffolded' | 'source-copy'
>;

const stringifyAiTutorContent = (content: KangurAiTutorContent): string =>
  `${JSON.stringify(content, null, 2)}\n`;

export function useKangurAiTutorContentSettingsState() {
  const settingsStore = useSettingsStore();
  const { toast } = useToast();

  const [aiTutorContentEditorValue, setAiTutorContentEditorValue] = useState<string>(
    () => EMPTY_AI_TUTOR_CONTENT_EDITOR_VALUE
  );
  const [persistedAiTutorContentEditorValue, setPersistedAiTutorContentEditorValue] =
    useState<string>(() => EMPTY_AI_TUTOR_CONTENT_EDITOR_VALUE);
  const [isAiTutorContentLoading, setIsAiTutorContentLoading] = useState(true);
  const [isAiTutorContentSaving, setIsAiTutorContentSaving] = useState(false);
  const [translationContentsByLocale, setTranslationContentsByLocale] = useState<
    Record<string, KangurAiTutorContent | null>
  >({});
  const [isAiTutorContentTranslationStatusLoading, setIsAiTutorContentTranslationStatusLoading] =
    useState(true);
  const [activeTranslationStatusFilters, setActiveTranslationStatusFilters] = useState<
    SectionTranslationFilterStatus[]
  >([]);

  const rawValidatorPatternLists = settingsStore.get(VALIDATOR_PATTERN_LISTS_KEY);
  const rawPromptEngineSettings = settingsStore.get(PROMPT_ENGINE_SETTINGS_KEY);

  const loadTranslationContents = async (): Promise<Record<string, KangurAiTutorContent | null>> => {
    if (AI_TUTOR_CONTENT_TRANSLATION_LOCALES.length === 0) {
      return {};
    }

    const localizedContents = await Promise.all(
      AI_TUTOR_CONTENT_TRANSLATION_LOCALES.map(async (locale) => {
        const content = await withKangurClientError(
          {
            source: 'kangur.admin.ai-tutor-content',
            action: 'load-translation-content',
            description: 'Loads localized AI Tutor content to derive translation status badges.',
            context: { locale },
          },
          async () => {
            const response = await api.get<KangurAiTutorContent>('/api/kangur/ai-tutor/content', {
              params: { locale },
              logError: false,
            });
            return parseKangurAiTutorContent(response);
          },
          {
            fallback: null,
            onError: () => {},
          }
        );

        return [locale, content] as const;
      })
    );

    return Object.fromEntries(localizedContents);
  };

  useEffect(() => {
    let cancelled = false;

    void (async () => {
      setIsAiTutorContentLoading(true);
      setIsAiTutorContentTranslationStatusLoading(true);
      const [content, localizedContents] = await Promise.all([
        withKangurClientError(
          {
            source: 'kangur.admin.ai-tutor-content',
            action: 'load-content',
            description: 'Loads AI Tutor content for the admin editor.',
            context: { locale: AI_TUTOR_CONTENT_EDITOR_LOCALE },
          },
          async () => {
            const response = await api.get<KangurAiTutorContent>('/api/kangur/ai-tutor/content', {
              params: { locale: AI_TUTOR_CONTENT_EDITOR_LOCALE },
              logError: false,
            });
            return parseKangurAiTutorContent(response);
          },
          {
            fallback: null,
            onError: (error) => {
              if (!cancelled) {
                toast(
                  error instanceof Error ? error.message : 'Failed to load AI Tutor content.',
                  { variant: 'error' }
                );
              }
            },
          }
        ),
        loadTranslationContents(),
      ]);

      if (!cancelled && content) {
        const nextValue = stringifyAiTutorContent(content);
        setAiTutorContentEditorValue(nextValue);
        setPersistedAiTutorContentEditorValue(nextValue);
      }

      if (!cancelled) {
        setTranslationContentsByLocale(localizedContents);
      }

      if (!cancelled) {
        setIsAiTutorContentLoading(false);
        setIsAiTutorContentTranslationStatusLoading(false);
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [toast]);

  const parsedAiTutorContentState = useMemo<
    { content: KangurAiTutorContent | null; error: string | null }
  >(() => {
    if (aiTutorContentEditorValue.trim().length === 0) {
      return {
        content: null,
        error: null,
      };
    }

    return withKangurClientErrorSync(
      {
        source: 'kangur.admin.ai-tutor-content',
        action: 'parse-content-json',
        description: 'Parses AI Tutor content JSON from the editor.',
      },
      () => ({
        content: parseKangurAiTutorContent(JSON.parse(aiTutorContentEditorValue) as unknown),
        error: null,
      }),
      {
        fallback: {
          content: null,
          error: 'Invalid AI Tutor content JSON.',
        } as { content: KangurAiTutorContent | null; error: string | null },
      }
    );
  }, [aiTutorContentEditorValue]);

  const aiTutorContentValidation = useMemo(
    () =>
      parsedAiTutorContentState.content
        ? validateKangurAiTutorOnboardingContent({
          content: parsedAiTutorContentState.content,
          patternLists: parseValidatorPatternLists(rawValidatorPatternLists),
          promptEngineSettings: parsePromptEngineSettings(rawPromptEngineSettings),
        })
        : null,
    [parsedAiTutorContentState.content, rawPromptEngineSettings, rawValidatorPatternLists]
  );

  const aiTutorContentDirty =
    aiTutorContentEditorValue.trim() !== persistedAiTutorContentEditorValue.trim();
  const aiTutorContentBlockingIssues = aiTutorContentValidation?.blockingIssues ?? [];
  const hasAiTutorContentBlockingIssues = aiTutorContentBlockingIssues.length > 0;

  const translationStatusesByLocale = useMemo(() => {
    const sourceContent = parsedAiTutorContentState.content;
    if (!sourceContent) {
      return new Map<string, Map<KangurAiTutorContentTranslatableSectionKey, KangurAiTutorTranslationStatusDto>>();
    }

    const map = new Map<string, Map<KangurAiTutorContentTranslatableSectionKey, KangurAiTutorTranslationStatusDto>>();
    Object.entries(translationContentsByLocale).forEach(([locale, content]) => {
      if (!content) {
        return;
      }
      map.set(
        locale,
        buildKangurAiTutorContentTranslationStatusBySectionKey({
          locale,
          sourceContent,
          localizedContent: content,
        })
      );
    });
    return map;
  }, [parsedAiTutorContentState.content, translationContentsByLocale]);

  const handleSaveAiTutorContent = async (): Promise<void> => {
    const { content } = parsedAiTutorContentState;
    if (!content) {
      return;
    }

    setIsAiTutorContentSaving(true);
    try {
      await withKangurClientError(
        {
          source: 'kangur.admin.ai-tutor-content',
          action: 'save-content',
          description: 'Saves AI Tutor content from the admin editor.',
          context: { locale: AI_TUTOR_CONTENT_EDITOR_LOCALE },
        },
        async () => {
          await api.post('/api/kangur/ai-tutor/content', {
            locale: AI_TUTOR_CONTENT_EDITOR_LOCALE,
            content,
          });
          return true;
        },
        {
          onError: (error) => {
            toast(error instanceof Error ? error.message : 'Failed to save AI Tutor content.', {
              variant: 'error',
            });
          },
        }
      );

      setPersistedAiTutorContentEditorValue(aiTutorContentEditorValue);
      toast('AI Tutor content saved successfully.', { variant: 'success' });
    } finally {
      setIsAiTutorContentSaving(false);
    }
  };

  return {
    aiTutorContentEditorValue,
    setAiTutorContentEditorValue,
    isAiTutorContentLoading,
    isAiTutorContentSaving,
    isAiTutorContentTranslationStatusLoading,
    activeTranslationStatusFilters,
    setActiveTranslationStatusFilters,
    parsedAiTutorContentState,
    aiTutorContentValidation,
    aiTutorContentDirty,
    aiTutorContentBlockingIssues,
    hasAiTutorContentBlockingIssues,
    translationStatusesByLocale,
    handleSaveAiTutorContent,
  };
}

'use client';

import { type ReactNode, useMemo } from 'react';

import {
  summarizeKangurAiTutorContentTranslationStatuses,
  type KangurAiTutorContentTranslatableSectionKey,
} from '@/features/kangur/server/ai-tutor-content-locale-scaffold';
import type {
  KangurAiTutorTranslationStatusDto,
} from '@/shared/contracts/kangur-ai-tutor-locale-scaffold';
import { Alert, Badge, Button, FormField, FormSection, Textarea } from '@/features/kangur/shared/ui';
import { KANGUR_GRID_RELAXED_CLASSNAME } from '@/features/kangur/ui/design/tokens';

import {
  KangurAdminCard,
  KangurAdminInsetCard,
} from './KangurAdminCard';
import {
  AI_TUTOR_CONTENT_TRANSLATION_LOCALES,
  type SectionTranslationFilterStatus,
  useKangurAiTutorContentSettingsState,
} from './KangurAiTutorContentSettingsPanel.hooks';

const SETTINGS_SECTION_CLASS_NAME = 'border-border/60 bg-card/35 shadow-sm';
const AI_TUTOR_HOME_ONBOARDING_STEP_FIELDS = [
  { key: 'home_actions', label: 'Home actions' },
  { key: 'home_quest', label: 'Home quest' },
  { key: 'priority_assignments', label: 'Priority assignments' },
  { key: 'leaderboard', label: 'Leaderboard' },
  { key: 'progress', label: 'Progress' },
] as const;

const AI_TUTOR_CONTENT_SECTION_CARD_KEYS = [
  { key: 'guestIntro', label: 'Guest intro' },
  { key: 'homeOnboarding', label: 'Home onboarding' },
  { key: 'guidedCallout', label: 'Guided callout' },
] as const satisfies ReadonlyArray<{
  key: KangurAiTutorContentTranslatableSectionKey;
  label: string;
}>;

const AI_TUTOR_CONTENT_TRANSLATION_FILTER_OPTIONS = [
  { status: 'manual', label: 'Manual' },
  { status: 'scaffolded', label: 'Scaffolded' },
  { status: 'source-copy', label: 'Source copy' },
] as const satisfies ReadonlyArray<{
  status: SectionTranslationFilterStatus;
  label: string;
}>;

const getTranslationStatusBadgeVariant = (
  status: KangurAiTutorTranslationStatusDto
): 'outline' | 'secondary' | 'warning' => {
  switch (status) {
    case 'manual': return 'secondary';
    case 'missing':
    case 'source-copy': return 'warning';
    case 'source-locale':
    case 'scaffolded':
    default: return 'outline';
  }
};

const getTranslationStatusFilterButtonVariant = (
  status: SectionTranslationFilterStatus,
  isActive: boolean
): 'outline' | 'secondary' | 'info' | 'warning' => {
  if (!isActive) return 'outline';
  switch (status) {
    case 'manual': return 'secondary';
    case 'scaffolded': return 'info';
    case 'source-copy':
    default: return 'warning';
  }
};

const formatTranslationStatusLabel = (
  locale: string,
  status: KangurAiTutorTranslationStatusDto
): string => {
  switch (status) {
    case 'manual': return `${locale.toUpperCase()} manual`;
    case 'scaffolded': return `${locale.toUpperCase()} scaffolded`;
    case 'source-copy': return `${locale.toUpperCase()} source copy`;
    case 'missing': return `${locale.toUpperCase()} missing`;
    case 'source-locale':
    default: return `${locale.toUpperCase()} source`;
  }
};

export function KangurAiTutorContentSettingsPanel(): React.JSX.Element {
  const state = useKangurAiTutorContentSettingsState();
  const {
    aiTutorContentEditorValue,
    setAiTutorContentEditorValue,
    isAiTutorContentLoading,
    isAiTutorContentSaving,
    isAiTutorContentTranslationStatusLoading,
    activeTranslationStatusFilters,
    setActiveTranslationStatusFilters,
    parsedAiTutorContentState,
    aiTutorContentDirty,
    aiTutorContentBlockingIssues,
    hasAiTutorContentBlockingIssues,
    translationStatusesByLocale,
    handleSaveAiTutorContent,
  } = state;

  const translationSummaryByLocale = useMemo(() => {
    const summary = new Map<string, ReturnType<typeof summarizeKangurAiTutorContentTranslationStatuses>>();
    translationStatusesByLocale.forEach((statuses, locale) => {
      summary.set(locale, summarizeKangurAiTutorContentTranslationStatuses(statuses.values()));
    });
    return summary;
  }, [translationStatusesByLocale]);

  const toggleTranslationStatusFilter = (status: SectionTranslationFilterStatus): void => {
    setActiveTranslationStatusFilters((prev) =>
      prev.includes(status) ? prev.filter((s) => s !== status) : [...prev, status]
    );
  };

  const renderSectionTranslationStatus = (
    sectionKey: KangurAiTutorContentTranslatableSectionKey
  ): ReactNode => {
    if (isAiTutorContentTranslationStatusLoading) return null;
    return (
      <div className='flex flex-wrap gap-1.5'>
        {Array.from(translationStatusesByLocale.entries()).map(([locale, statuses]) => {
          const status = statuses.get(sectionKey);
          if (!status) return null;
          const filterStatus = status as SectionTranslationFilterStatus;
          if (activeTranslationStatusFilters.length > 0 && !activeTranslationStatusFilters.includes(filterStatus)) return null;
          return (
            <Badge key={locale} variant={getTranslationStatusBadgeVariant(status)} className='px-1.5 py-0 text-[10px] uppercase font-bold tracking-wider'>
              {formatTranslationStatusLabel(locale, status)}
            </Badge>
          );
        })}
      </div>
    );
  };

  return (
    <KangurAdminCard
      title='AI Tutor Content'
      description='Manage localized content, onboarding steps, and system prompts for the AI Tutor.'
      headerActions={
        <Button
          onClick={() => void handleSaveAiTutorContent()}
          disabled={
            isAiTutorContentSaving ||
            !aiTutorContentDirty ||
            hasAiTutorContentBlockingIssues ||
            !parsedAiTutorContentState.content
          }
          loading={isAiTutorContentSaving}
          size='sm'
        >
          {isAiTutorContentSaving ? 'Saving...' : 'Save Content'}
        </Button>
      }
    >
      <div className='flex flex-col kangur-panel-gap'>
        <Alert variant='info' title='Translation Monitor'>
          <p className='text-sm'>The following locales are monitored for translation status: <strong>{AI_TUTOR_CONTENT_TRANSLATION_LOCALES.join(', ').toUpperCase()}</strong>.</p>
          <div className='mt-3 flex flex-wrap gap-4'>
            {Array.from(translationSummaryByLocale.entries()).map(([locale, summary]) => (
              <div key={locale} className='flex items-center gap-2'>
                <Badge variant='outline' className='font-bold'>{locale.toUpperCase()}</Badge>
                <span className='text-xs text-muted-foreground'>
                  Manual: <strong>{summary.manual}</strong> • Scaffolded: <strong>{summary.scaffolded}</strong> • Copy: <strong>{summary['source-copy']}</strong>
                </span>
              </div>
            ))}
          </div>
        </Alert>

        <div className='flex items-center justify-between gap-4'>
          <div className='flex items-center gap-2'>
            <span className='text-xs font-bold text-muted-foreground uppercase'>Filters:</span>
            {AI_TUTOR_CONTENT_TRANSLATION_FILTER_OPTIONS.map((option) => (
              <Button
                key={option.status}
                onClick={() => toggleTranslationStatusFilter(option.status)}
                variant={getTranslationStatusFilterButtonVariant(option.status, activeTranslationStatusFilters.includes(option.status))}
                size='xs'
                className='h-7 px-2.5 text-[10px] font-bold uppercase tracking-wider'
              >
                {option.label}
              </Button>
            ))}
          </div>
        </div>

        <div className='grid grid-cols-1 gap-6 lg:grid-cols-2'>
          <FormSection title='Editor (PL Source)' description='JSON source for AI Tutor content.' className={SETTINGS_SECTION_CLASS_NAME}>
            <FormField label='Content JSON' error={parsedAiTutorContentState.error || undefined}>
              <Textarea
                value={aiTutorContentEditorValue}
                onChange={(e) => setAiTutorContentEditorValue(e.target.value)}
                rows={24}
                className='font-mono text-[13px] leading-relaxed'
                disabled={isAiTutorContentLoading}
              />
            </FormField>
          </FormSection>

          <div className='space-y-6'>
            <FormSection title='Validation & Insights' description='Automated checks for the current content.' className={SETTINGS_SECTION_CLASS_NAME}>
              {isAiTutorContentLoading ? (
                <Alert
                  variant='info'
                  title='Loading content'
                  description='Waiting for the Mongo-backed AI Tutor content store.'
                />
              ) : parsedAiTutorContentState.error ? (
                <Alert
                  variant='error'
                  title='Invalid content JSON'
                  description={parsedAiTutorContentState.error}
                />
              ) : !parsedAiTutorContentState.content ? (
                <Alert
                  variant='info'
                  title='No content loaded'
                  description='Reload the Mongo-backed AI Tutor content store or paste JSON to begin editing.'
                />
              ) : aiTutorContentBlockingIssues.length > 0 ? (
                <div className='space-y-3'>
                  {aiTutorContentBlockingIssues.map((issue, idx) => (
                    <Alert key={idx} variant='error' title={issue.title} description={issue.message} />
                  ))}
                </div>
              ) : (
                <Alert variant='success' title='Validation Passed' description='Current content JSON is valid and consistent with patterns.' />
              )}
            </FormSection>

            <div className='space-y-4'>
              <h4 className='text-sm font-bold text-muted-foreground uppercase tracking-wider'>Translatable Sections</h4>
              <div className={KANGUR_GRID_RELAXED_CLASSNAME}>
                {AI_TUTOR_CONTENT_SECTION_CARD_KEYS.map((section) => (
                  <KangurAdminInsetCard key={section.key}>
                    <div className='flex flex-col gap-2'>
                      <span className='text-xs font-bold text-slate-700'>{section.label}</span>
                      {renderSectionTranslationStatus(section.key)}
                    </div>
                  </KangurAdminInsetCard>
                ))}
              </div>
            </div>

            <div className='space-y-4'>
              <h4 className='text-sm font-bold text-muted-foreground uppercase tracking-wider'>Onboarding Steps</h4>
              <div className='grid grid-cols-1 gap-3 sm:grid-cols-2'>
                {AI_TUTOR_HOME_ONBOARDING_STEP_FIELDS.map((field) => (
                  <KangurAdminInsetCard key={field.key}>
                    <div className='flex flex-col gap-2'>
                      <div className='flex items-center justify-between'>
                        <span className='text-xs font-bold text-slate-700'>{field.label}</span>
                        {parsedAiTutorContentState.content?.homeOnboarding.steps[field.key] ? (
                          <Badge variant='success' className='h-4 px-1 text-[9px]'>Live</Badge>
                        ) : (
                          <Badge variant='outline' className='h-4 px-1 text-[9px]'>Missing</Badge>
                        )}
                      </div>
                      {renderSectionTranslationStatus('homeOnboarding')}
                    </div>
                  </KangurAdminInsetCard>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </KangurAdminCard>
  );
}

'use client';

import {
  type ChangeEvent,
  useCallback,
  useState,
} from 'react';

import type { ChatMessageDto } from '@/shared/contracts/chatbot';
import { api } from '@/shared/lib/api-client';

interface ConversationSession {
  learnerId: string;
  surface: string | null;
  contentId: string | null;
  messages: ChatMessageDto[];
  sessionId: string;
  messageCount?: number;
}

interface LoadingState {
  isLoading: boolean;
  error: string | null;
}

export const KangurAiTutorConversationReplay = (): JSX.Element => {
  const [learnerId, setLearnerId] = useState('');
  const [surface, setSurface] = useState('');
  const [contentId, setContentId] = useState('');
  const [limit, setLimit] = useState(50);
  const [session, setSession] = useState<ConversationSession | null>(null);
  const [loadingState, setLoadingState] = useState<LoadingState>({
    isLoading: false,
    error: null,
  });
  const [selectedMessageIndex, setSelectedMessageIndex] = useState<number | null>(null);

  const handleLoadConversation = useCallback(async () => {
    if (!learnerId.trim()) {
      setLoadingState({
        isLoading: false,
        error: 'Learner ID is required.',
      });
      return;
    }

    setLoadingState({ isLoading: true, error: null });

    try {
      const queryParams = new URLSearchParams({
        learnerId: learnerId.trim(),
        limit: limit.toString(),
      });

      if (surface.trim()) {
        queryParams.set('surface', surface.trim());
      }
      if (contentId.trim()) {
        queryParams.set('contentId', contentId.trim());
      }

      const response = await api.get<ConversationSession>(
        `/api/kangur/ai-tutor/chat/admin-history?${queryParams.toString()}`
      );

      setSession(response);
      setLoadingState({ isLoading: false, error: null });
      setSelectedMessageIndex(null);
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Failed to load conversation.';
      setLoadingState({
        isLoading: false,
        error: message,
      });
      setSession(null);
    }
  }, [learnerId, surface, contentId, limit]);

  const handleLearnerIdChange = (e: ChangeEvent<HTMLInputElement>): void => {
    setLearnerId(e.target.value);
  };

  const handleSurfaceChange = (e: ChangeEvent<HTMLInputElement>): void => {
    setSurface(e.target.value);
  };

  const handleContentIdChange = (e: ChangeEvent<HTMLInputElement>): void => {
    setContentId(e.target.value);
  };

  const handleLimitChange = (e: ChangeEvent<HTMLInputElement>): void => {
    setLimit(Math.max(1, Math.min(100, parseInt(e.target.value) || 50)));
  };

  const selectedMessage = selectedMessageIndex !== null ? session?.messages[selectedMessageIndex] : null;
  const selectedMessageMetadataPanel = selectedMessage?.metadata ? (
    <div style={{ marginBottom: '12px' }}>
      <div style={{ fontSize: '12px', color: '#666', marginBottom: '4px', fontWeight: 'bold' }}>
        Metadata
      </div>
      <pre
        style={{
          padding: '12px',
          backgroundColor: '#fafafa',
          borderRadius: '4px',
          fontSize: '12px',
          overflow: 'auto',
          margin: 0,
        }}
      >
        {JSON.stringify(selectedMessage.metadata, null, 2)}
      </pre>
    </div>
  ) : null;

  return (
    <div style={{ padding: '16px', fontFamily: 'system-ui, -apple-system, sans-serif' }}>
      <h2>AI Tutor Conversation Replay</h2>

      <div style={{ marginBottom: '24px', padding: '16px', backgroundColor: '#f5f5f5', borderRadius: '8px' }}>
        <h3 style={{ marginTop: 0 }}>Search Parameters</h3>

        <div style={{ marginBottom: '12px' }}>
          <label style={{ display: 'block', marginBottom: '4px', fontWeight: 'bold' }}>
            Learner ID *
            <input
              type='text'
              aria-label='Learner ID'
              placeholder='e.g., learner-123'
              value={learnerId}
              onChange={handleLearnerIdChange}
              style={{
                width: '100%',
                padding: '8px',
                border: '1px solid #ccc',
                borderRadius: '4px',
                fontFamily: 'monospace',
                boxSizing: 'border-box',
                marginTop: '4px',
              }}
            />
          </label>
        </div>

        <div style={{ marginBottom: '12px', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
          <div>
            <label style={{ display: 'block', marginBottom: '4px', fontWeight: 'bold' }}>
              Surface (optional)
              <input
                type='text'
                aria-label='Surface'
                placeholder='e.g., lesson'
                value={surface}
                onChange={handleSurfaceChange}
                style={{
                  width: '100%',
                  padding: '8px',
                  border: '1px solid #ccc',
                  borderRadius: '4px',
                  fontFamily: 'monospace',
                  boxSizing: 'border-box',
                  marginTop: '4px',
                }}
              />
            </label>
          </div>

          <div>
            <label style={{ display: 'block', marginBottom: '4px', fontWeight: 'bold' }}>
              Content ID (optional)
              <input
                type='text'
                aria-label='Content ID'
                placeholder='e.g., lesson-456'
                value={contentId}
                onChange={handleContentIdChange}
                style={{
                  width: '100%',
                  padding: '8px',
                  border: '1px solid #ccc',
                  borderRadius: '4px',
                  fontFamily: 'monospace',
                  boxSizing: 'border-box',
                  marginTop: '4px',
                }}
              />
            </label>
          </div>
        </div>

        <div style={{ marginBottom: '16px' }}>
          <label style={{ display: 'block', marginBottom: '4px', fontWeight: 'bold' }}>
            Message Limit (max 100)
            <input
              type='number'
              aria-label='Message Limit'
              min='1'
              max='100'
              value={limit}
              onChange={handleLimitChange}
              style={{
                width: '100%',
                padding: '8px',
                border: '1px solid #ccc',
                borderRadius: '4px',
                fontFamily: 'monospace',
                boxSizing: 'border-box',
                marginTop: '4px',
              }}
            />
          </label>
        </div>

        <button
          onClick={() => {
            void handleLoadConversation();
          }}
          disabled={loadingState.isLoading}
          style={{
            padding: '8px 16px',
            backgroundColor: '#007bff',
            color: '#fff',
            border: 'none',
            borderRadius: '4px',
            cursor: loadingState.isLoading ? 'not-allowed' : 'pointer',
            fontWeight: 'bold',
            opacity: loadingState.isLoading ? 0.6 : 1,
          }}
        >
          {loadingState.isLoading ? 'Loading...' : 'Load Conversation'}
        </button>

        {loadingState.error && (
          <div
            style={{
              marginTop: '12px',
              padding: '12px',
              backgroundColor: '#f8d7da',
              color: '#721c24',
              borderRadius: '4px',
              border: '1px solid #f5c6cb',
            }}
          >
            {loadingState.error}
          </div>
        )}
      </div>

      {session && (
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '24px' }}>
          {/* Message List */}
          <div style={{ border: '1px solid #ddd', borderRadius: '8px', overflow: 'hidden' }}>
            <div
              style={{
                padding: '12px',
                backgroundColor: '#f9f9f9',
                borderBottom: '1px solid #ddd',
                fontWeight: 'bold',
              }}
            >
              Messages ({session.messages.length})
            </div>
            <div style={{ maxHeight: '600px', overflowY: 'auto' }}>
              {session.messages.length === 0 ? (
                <div style={{ padding: '12px', color: '#666', fontStyle: 'italic' }}>No messages found</div>
              ) : (
                session.messages.map((message, index) => (
                  <button
                    key={index}
                    onClick={() => setSelectedMessageIndex(index)}
                    style={{
                      width: '100%',
                      padding: '12px',
                      border: 'none',
                      borderBottom: '1px solid #eee',
                      backgroundColor:
                        selectedMessageIndex === index ? '#e3f2fd' : index % 2 === 0 ? '#fafafa' : '#fff',
                      textAlign: 'left',
                      cursor: 'pointer',
                      transition: 'background-color 0.2s',
                    }}
                    onMouseEnter={(e) => {
                      if (selectedMessageIndex !== index) {
                        e.currentTarget.style.backgroundColor = '#f0f0f0';
                      }
                    }}
                    onMouseLeave={(e) => {
                      if (selectedMessageIndex !== index) {
                        e.currentTarget.style.backgroundColor = index % 2 === 0 ? '#fafafa' : '#fff';
                      }
                    }}
                  >
                    <div style={{ fontWeight: 'bold', fontSize: '12px', color: '#666', marginBottom: '4px' }}>
                      {message.role.toUpperCase()} • {new Date(message.timestamp).toLocaleTimeString()}
                    </div>
                    <div style={{ fontSize: '13px', color: '#333', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {message.content.slice(0, 60)}...
                    </div>
                  </button>
                ))
              )}
            </div>
          </div>

          {/* Message Detail */}
          <div style={{ border: '1px solid #ddd', borderRadius: '8px', overflow: 'hidden' }}>
            {selectedMessage ? (
              <>
                <div
                  style={{
                    padding: '12px',
                    backgroundColor: selectedMessage.role === 'user' ? '#e8f5e9' : '#f3e5f5',
                    borderBottom: '1px solid #ddd',
                    fontWeight: 'bold',
                  }}
                >
                  {selectedMessage.role === 'user' ? '👤 User Message' : '🤖 Assistant Message'}
                </div>
                <div style={{ padding: '16px', maxHeight: '500px', overflowY: 'auto' }}>
                  <div style={{ marginBottom: '12px', padding: '8px', backgroundColor: '#f5f5f5', borderRadius: '4px' }}>
                    <div style={{ fontSize: '12px', color: '#666', marginBottom: '4px' }}>Timestamp</div>
                    <div style={{ fontFamily: 'monospace', fontSize: '12px' }}>
                      {new Date(selectedMessage.timestamp).toLocaleString()}
                    </div>
                  </div>

                  <div style={{ marginBottom: '12px' }}>
                    <div style={{ fontSize: '12px', color: '#666', marginBottom: '4px', fontWeight: 'bold' }}>
                      Content
                    </div>
                    <div
                      style={{
                        padding: '12px',
                        backgroundColor: '#fafafa',
                        borderRadius: '4px',
                        fontFamily: 'monospace',
                        fontSize: '13px',
                        whiteSpace: 'pre-wrap',
                        wordBreak: 'break-word',
                        lineHeight: '1.5',
                      }}
                    >
                      {selectedMessage.content}
                    </div>
                  </div>

                  {selectedMessageMetadataPanel}
                </div>
              </>
            ) : (
              <div
                style={{
                  padding: '24px',
                  textAlign: 'center',
                  color: '#999',
                  fontStyle: 'italic',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  minHeight: '400px',
                }}
              >
                Select a message to view details
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

import type { KangurAiTutorNativeGuideEntry } from '@/features/kangur/shared/contracts/kangur-ai-tutor-native-guide';
import type {
  KangurAiTutorLocaleTranslationStatusDto,
  KangurAiTutorTranslationStatusDto,
} from '@/shared/contracts/kangur-ai-tutor-locale-scaffold';
import { Badge, Card } from '@/features/kangur/shared/ui';

type Props = {
  entries: KangurAiTutorNativeGuideEntry[];
  selectedEntryId: string | null;
  onSelect: (entryId: string) => void;
  entryValidationCounts: Map<string, { total: number; blocking: number }>;
  translationStatusByEntryId: Map<string, KangurAiTutorLocaleTranslationStatusDto[]>;
  className: string;
};

const getTranslationStatusBadgeVariant = (
  status: KangurAiTutorTranslationStatusDto
): 'outline' | 'secondary' | 'warning' => {
  switch (status) {
    case 'manual':
      return 'secondary';
    case 'missing':
    case 'source-copy':
      return 'warning';
    case 'source-locale':
    case 'scaffolded':
    default:
      return 'outline';
  }
};

const formatTranslationStatusLabel = (
  locale: string,
  status: KangurAiTutorTranslationStatusDto
): string => {
  switch (status) {
    case 'manual':
      return `${locale.toUpperCase()} manual`;
    case 'scaffolded':
      return `${locale.toUpperCase()} scaffolded`;
    case 'source-copy':
      return `${locale.toUpperCase()} source copy`;
    case 'missing':
      return `${locale.toUpperCase()} missing`;
    case 'source-locale':
    default:
      return `${locale.toUpperCase()} source`;
  }
};

export function KangurAiTutorNativeGuideEntryList({
  entries,
  selectedEntryId,
  onSelect,
  entryValidationCounts,
  translationStatusByEntryId,
  className,
}: Props): React.JSX.Element {
  const cardClassName = className;

  return (
    <Card variant='subtle' padding='md' className={cardClassName}>
      <div className='flex items-center justify-between gap-2'>
        <div className='text-sm font-semibold text-foreground'>Guide entries</div>
        <Badge variant='outline'>{entries.length}</Badge>
      </div>
      <div className='mt-3 space-y-2'>
        {entries.map((entry) => {
          const isSelected = entry.id === selectedEntryId;
          const entryIssueSummary = entryValidationCounts.get(entry.id) ?? {
            total: 0,
            blocking: 0,
          };
          const translationStatuses = translationStatusByEntryId.get(entry.id) ?? [];
          return (
            <button
              key={entry.id}
              type='button'
              onClick={() => onSelect(entry.id)}
              aria-pressed={isSelected}
              aria-label={`Select ${entry.title}`}
              className={`w-full rounded-2xl border px-3 py-3 text-left transition focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 focus-visible:ring-offset-2 ring-offset-background ${
                isSelected
                  ? 'border-primary/40 bg-card shadow-sm ring-1 ring-primary/15'
                  : 'border-border/60 bg-background/50 hover:bg-card/60'
              }`}
            >
              <div className='flex items-center justify-between gap-2'>
                <div className='truncate text-sm font-semibold text-foreground'>{entry.title}</div>
                <Badge variant={entry.enabled ? 'secondary' : 'outline'}>
                  {entry.enabled ? 'On' : 'Off'}
                </Badge>
              </div>
              <p className='mt-1 line-clamp-2 text-xs text-muted-foreground'>
                {entry.shortDescription || 'No short description yet.'}
              </p>
              <div className='mt-2 flex flex-wrap gap-2'>
                {entry.surface ? (
                  <Badge variant='outline'>{entry.surface}</Badge>
                ) : (
                  <Badge variant='outline'>all surfaces</Badge>
                )}
                {entry.focusKind ? <Badge variant='outline'>{entry.focusKind}</Badge> : null}
                {entryIssueSummary.total > 0 ? (
                  <Badge variant={entryIssueSummary.blocking > 0 ? 'warning' : 'outline'}>
                    {entryIssueSummary.total} issue
                    {entryIssueSummary.total === 1 ? '' : 's'}
                  </Badge>
                ) : null}
                {translationStatuses.map(({ locale, status }) => (
                  <Badge
                    key={`${entry.id}-${locale}`}
                    variant={getTranslationStatusBadgeVariant(status)}
                  >
                    {formatTranslationStatusLabel(locale, status)}
                  </Badge>
                ))}
              </div>
            </button>
          );
        })}
      </div>
    </Card>
  );
}

