'use client';

import { useId, useMemo, useState } from 'react';

import {
  KANGUR_DOC_CATALOG,
  KANGUR_DOCUMENTATION_LIBRARY,
} from '@/shared/lib/documentation/catalogs/kangur';
import { Badge, Card, CompactEmptyState, ListPanel, PanelStats, SearchInput } from '@/features/kangur/shared/ui';
import { cn } from '@/features/kangur/shared/utils';
import { KANGUR_GRID_RELAXED_CLASSNAME } from '@/features/kangur/ui/design/tokens';

import { KANGUR_ADMIN_CARD_CLASS_NAME } from './KangurAdminCard';

type GroupedTooltipDocs = {
  section: string;
  entries: typeof KANGUR_DOC_CATALOG;
};

const formatAudience = (
  value: (typeof KANGUR_DOCUMENTATION_LIBRARY)[number]['audience']
): string => {
  switch (value) {
    case 'learner':
      return 'Learner';
    case 'parent':
      return 'Parent';
    case 'admin':
      return 'Admin';
    case 'shared':
    default:
      return 'Shared';
  }
};

const matchesQuery = (parts: Array<string | undefined>, query: string): boolean => {
  if (!query) return true;
  const normalized = query.toLowerCase();
  return parts.some((part) => (part ?? '').toLowerCase().includes(normalized));
};

export function KangurDocumentationCenter(): React.JSX.Element {
  const [query, setQuery] = useState('');
  const normalizedQuery = query.trim().toLowerCase();
  const searchInputId = useId();
  const indexHeadingId = useId();
  const indexDescriptionId = useId();
  const resultsStatusId = useId();

  const visibleGuides = useMemo(
    () =>
      KANGUR_DOCUMENTATION_LIBRARY.filter((guide) =>
        matchesQuery(
          [
            guide.title,
            guide.summary,
            guide.docPath,
            guide.audience,
            guide.sectionsCovered.join(' '),
          ],
          normalizedQuery
        )
      ),
    [normalizedQuery]
  );

  const groupedTooltipDocs = useMemo<GroupedTooltipDocs[]>(() => {
    const visibleEntries = KANGUR_DOC_CATALOG.filter((entry) =>
      matchesQuery(
        [
          entry.title,
          entry.summary,
          entry.section,
          entry.docPath,
          entry.aliases.join(' '),
          entry.tags?.join(' ') ?? '',
          entry.uiTargets?.join(' ') ?? '',
        ],
        normalizedQuery
      )
    );

    const grouped = new Map<string, typeof KANGUR_DOC_CATALOG>();

    for (const entry of visibleEntries) {
      const existing = grouped.get(entry.section) ?? [];
      existing.push(entry);
      grouped.set(entry.section, existing);
    }

    return Array.from(grouped.entries())
      .map(([section, entries]) => ({
        section,
        entries: [...entries].sort((left, right) => left.title.localeCompare(right.title)),
      }))
      .sort((left, right) => left.section.localeCompare(right.section));
  }, [normalizedQuery]);

  const visibleTooltipDocCount = useMemo(
    () => groupedTooltipDocs.reduce((count, group) => count + group.entries.length, 0),
    [groupedTooltipDocs]
  );

  const stats = useMemo(
    () => [
      { key: 'guides', label: 'Guides', value: String(visibleGuides.length) },
      { key: 'docs', label: 'Tooltip Docs', value: String(visibleTooltipDocCount) },
      { key: 'sections', label: 'Sections', value: String(groupedTooltipDocs.length) },
    ],
    [groupedTooltipDocs.length, visibleGuides.length, visibleTooltipDocCount]
  );

  const resultSummary = normalizedQuery
    ? `Showing ${visibleGuides.length} guides and ${visibleTooltipDocCount} tooltip documents across ${groupedTooltipDocs.length} sections for "${query.trim()}".`
    : `Showing ${visibleGuides.length} guides and ${visibleTooltipDocCount} tooltip documents across ${groupedTooltipDocs.length} sections in the Kangur documentation center.`;

  return (
    <div className='space-y-6' data-doc-id='settings_documentation_library'>
      <div id={resultsStatusId} role='status' aria-live='polite' aria-atomic='true' className='sr-only'>
        {resultSummary}
      </div>

      <Card
        variant='subtle'
        padding='lg'
        className={KANGUR_ADMIN_CARD_CLASS_NAME}
        aria-labelledby={indexHeadingId}
        aria-describedby={indexDescriptionId}
      >
        <div className='space-y-4'>
          <div>
            <h2 id={indexHeadingId} className='text-sm font-semibold text-foreground'>
              Kangur Documentation Index
            </h2>
            <p id={indexDescriptionId} className='mt-1 text-sm text-muted-foreground'>
              Search the central Kangur guides and the tooltip catalog that feeds the learner and
              admin UI.
            </p>
          </div>
          <div role='search' aria-label='Search Kangur documentation'>
            <label htmlFor={searchInputId} className='sr-only'>
              Search Kangur documentation
            </label>
            <SearchInput
              id={searchInputId}
              type='search'
              value={query}
              onChange={(event) => setQuery(event.target.value)}
              onClear={() => setQuery('')}
              placeholder='Search Kangur docs, sections, or tooltip ids'
              size='sm'
              variant='subtle'
              aria-describedby={resultsStatusId}
              data-doc-id='settings_documentation_library'
            />
          </div>
          <PanelStats stats={stats} className='grid-cols-1 sm:grid-cols-3 lg:grid-cols-3' />
        </div>
      </Card>

      <div
        className={cn(
          KANGUR_GRID_RELAXED_CLASSNAME,
          'xl:grid-cols-[minmax(0,0.95fr)_minmax(0,1.05fr)]'
        )}
      >
        <ListPanel
          header={
            <div>
              <h2 className='text-xl font-semibold text-foreground'>Guide Library</h2>
              <p className='mt-1 text-sm text-muted-foreground'>
                Canonical Kangur guides that back the tooltip catalog and admin reference copy.
              </p>
            </div>
          }
          className={KANGUR_ADMIN_CARD_CLASS_NAME}
          contentClassName='space-y-4'
        >
          {visibleGuides.length > 0 ? (
            <div className='grid gap-3 md:grid-cols-2'>
              {visibleGuides.map((guide) => (
                <Card
                  key={guide.id}
                  variant='subtle'
                  padding='md'
                  className='rounded-2xl border-border/60 bg-card/55 shadow-sm'
                >
                  <div className='flex items-start justify-between gap-3'>
                    <div>
                      <h3 className='text-sm font-semibold text-foreground'>{guide.title}</h3>
                      <p className='mt-1 text-sm text-muted-foreground'>{guide.summary}</p>
                    </div>
                    <Badge variant='secondary'>{formatAudience(guide.audience)}</Badge>
                  </div>
                  <div className='mt-3 flex flex-wrap gap-2'>
                    <Badge variant='outline'>{guide.docPath}</Badge>
                    {guide.sectionsCovered.map((section) => (
                      <Badge key={section} variant='outline'>
                        {section}
                      </Badge>
                    ))}
                  </div>
                </Card>
              ))}
            </div>
          ) : (
            <CompactEmptyState
              title='No Kangur guide matched the current search.'
              description='Try a broader phrase, a guide title, or a documentation path.'
              className='rounded-2xl border-border/60 bg-background/30'
             />
          )}
        </ListPanel>

        <ListPanel
          header={
            <div>
              <h2 className='text-xl font-semibold text-foreground'>Tooltip Catalog</h2>
              <p className='mt-1 text-sm text-muted-foreground'>
                Grouped documentation entries that map directly to Kangur UI surfaces.
              </p>
            </div>
          }
          className={KANGUR_ADMIN_CARD_CLASS_NAME}
          contentClassName='space-y-4'
        >
          {groupedTooltipDocs.length > 0 ? (
            <div className='space-y-4'>
              {groupedTooltipDocs.map((group, groupIndex) => (
                <Card
                  key={group.section}
                  variant='subtle'
                  padding='md'
                  className='rounded-2xl border-border/60 bg-card/55 shadow-sm'
                  aria-labelledby={`kangur-doc-tooltip-section-${groupIndex}-title`}
                >
                  <div className='flex items-center justify-between gap-3'>
                    <h3
                      id={`kangur-doc-tooltip-section-${groupIndex}-title`}
                      className='text-sm font-semibold text-foreground'
                    >
                      {group.section}
                    </h3>
                    <Badge variant='outline'>{group.entries.length} docs</Badge>
                  </div>
                  <div className='mt-3 space-y-3'>
                    {group.entries.map((entry) => (
                      <Card
                        key={entry.id}
                        variant='subtle'
                        padding='sm'
                        className={cn(
                          'rounded-xl border-border/60 bg-background/55 shadow-none',
                          'transition-colors hover:bg-background/70'
                        )}
                      >
                        <div className='flex flex-wrap items-start justify-between gap-3'>
                          <div>
                            <h4 className='text-sm font-semibold text-foreground'>{entry.title}</h4>
                            <p className='mt-1 text-sm text-muted-foreground'>{entry.summary}</p>
                          </div>
                          <Badge variant='outline'>{entry.id}</Badge>
                        </div>
                        <div className='mt-3 flex flex-wrap gap-2'>
                          <Badge variant='outline'>{entry.docPath}</Badge>
                          {entry.uiTargets?.slice(0, 3).map((target) => (
                            <Badge key={target} variant='outline'>
                              {target}
                            </Badge>
                          ))}
                        </div>
                      </Card>
                    ))}
                  </div>
                </Card>
              ))}
            </div>
          ) : (
            <CompactEmptyState
              title='No Kangur tooltip documentation matched the current search.'
              description='Try a guide name, tooltip id, or UI target to widen the result set.'
              className='rounded-2xl border-border/60 bg-background/30'
             />
          )}
        </ListPanel>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useMemo, useState } from 'react';

import { KangurDocsTooltipEnhancer } from '@/features/kangur/docs/tooltips';
import {
  KANGUR_HELP_SETTINGS_KEY,
  areKangurDocsTooltipsEnabled,
  parseKangurHelpSettings,
  type KangurHelpSettings,
} from '@/features/kangur/docs/help-settings';
import { useUpdateSetting } from '@/shared/hooks/use-settings';
import { useSettingsStore } from '@/features/kangur/shared/providers/SettingsStoreProvider';
import { Badge, Button, FormSection, Switch, useToast } from '@/features/kangur/shared/ui';
import { serializeSetting } from '@/features/kangur/shared/utils/settings-json';
import { withKangurClientError } from '@/features/kangur/observability/client';
import { KANGUR_GRID_RELAXED_CLASSNAME } from '@/features/kangur/ui/design/tokens';

import { KangurAdminCard } from './KangurAdminCard';

const DOCS_TOOLTIP_SURFACES: Array<{
  key: keyof KangurHelpSettings['docsTooltips'];
  label: string;
  description: string;
  docId: string;
}> = [
  {
    key: 'homeEnabled',
    label: 'Home',
    description: 'Game home screen, quick-start practice, and practice shell controls.',
    docId: 'settings_docs_tooltips_home_toggle',
  },
  {
    key: 'lessonsEnabled',
    label: 'Lessons',
    description: 'Lesson library, document-mode lessons, and lesson navigation controls.',
    docId: 'settings_docs_tooltips_lessons_toggle',
  },
  {
    key: 'testsEnabled',
    label: 'Tests',
    description: 'Test-suite list and active suite playback controls.',
    docId: 'settings_docs_tooltips_tests_toggle',
  },
  {
    key: 'profileEnabled',
    label: 'Learner Profile',
    description: 'Learner progress summary, recommendations, and profile shortcuts.',
    docId: 'settings_docs_tooltips_profile_toggle',
  },
  {
    key: 'parentDashboardEnabled',
    label: 'Parent Dashboard',
    description: 'Learner switching, progress tabs, and assignment review on the parent surface.',
    docId: 'settings_docs_tooltips_parent_dashboard_toggle',
  },
  {
    key: 'adminEnabled',
    label: 'Admin',
    description: 'Documentation-driven tooltips inside Kangur admin routes, including this page.',
    docId: 'settings_docs_tooltips_admin_toggle',
  },
] as const;

const areHelpSettingsEqual = (left: KangurHelpSettings, right: KangurHelpSettings): boolean =>
  left.docsTooltips.enabled === right.docsTooltips.enabled &&
  left.docsTooltips.homeEnabled === right.docsTooltips.homeEnabled &&
  left.docsTooltips.lessonsEnabled === right.docsTooltips.lessonsEnabled &&
  left.docsTooltips.testsEnabled === right.docsTooltips.testsEnabled &&
  left.docsTooltips.profileEnabled === right.docsTooltips.profileEnabled &&
  left.docsTooltips.parentDashboardEnabled === right.docsTooltips.parentDashboardEnabled &&
  left.docsTooltips.adminEnabled === right.docsTooltips.adminEnabled;

export function KangurDocumentationTooltipSettingsPanel(): React.JSX.Element {
  const settingsStore = useSettingsStore();
  const updateSetting = useUpdateSetting();
  const { toast } = useToast();
  const rawHelpSettings = settingsStore.get(KANGUR_HELP_SETTINGS_KEY);
  const persistedHelpSettings = useMemo(
    () => parseKangurHelpSettings(rawHelpSettings),
    [rawHelpSettings]
  );
  const [helpSettings, setHelpSettings] = useState<KangurHelpSettings>(persistedHelpSettings);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    setHelpSettings(persistedHelpSettings);
  }, [persistedHelpSettings]);

  const isDirty = !areHelpSettingsEqual(helpSettings, persistedHelpSettings);
  const adminDocsEnabled = areKangurDocsTooltipsEnabled(helpSettings, 'admin');

  const handleSave = async (): Promise<void> => {
    if (!isDirty) {
      return;
    }

    setIsSaving(true);
    const didSave = await withKangurClientError(
      {
        source: 'kangur.admin.docs-tooltips',
        action: 'save-settings',
        description: 'Saves documentation tooltip settings.',
      },
      async () => {
        await updateSetting.mutateAsync({
          key: KANGUR_HELP_SETTINGS_KEY,
          value: serializeSetting(helpSettings),
        });
        return true;
      },
      {
        fallback: false,
        onError: (error) => {
          toast(error instanceof Error ? error.message : 'Failed to save Kangur tooltip settings.', {
            variant: 'error',
          });
        },
      }
    );

    if (didSave) {
      toast('Kangur documentation tooltip settings saved.', {
        variant: 'success',
      });
    }
    setIsSaving(false);
  };

  return (
    <>
      <KangurDocsTooltipEnhancer enabled={adminDocsEnabled} rootId='kangur-documentation-content' />
      <FormSection
        title='Docs & Tooltips'
        description='These toggles control documentation-driven tooltips. Tooltip text is sourced only from the central Kangur documentation files.'
        variant='subtle'
      >
        <KangurAdminCard>
          <div className='flex items-center justify-between gap-4'>
            <div>
              <div className='flex items-center gap-2'>
                <div className='text-sm font-semibold text-foreground'>Enable Kangur docs tooltips</div>
                <Badge variant={helpSettings.docsTooltips.enabled ? 'secondary' : 'outline'}>
                  {helpSettings.docsTooltips.enabled ? 'Enabled' : 'Disabled'}
                </Badge>
              </div>
              <p className='mt-1 text-sm text-muted-foreground'>
                Master switch for learner and admin tooltip help generated from the Kangur
                documentation catalog.
              </p>
            </div>
            <Switch
              checked={helpSettings.docsTooltips.enabled}
              onCheckedChange={(checked) =>
                setHelpSettings((current) => ({
                  ...current,
                  docsTooltips: {
                    ...current.docsTooltips,
                    enabled: checked,
                  },
                }))
              }
              data-doc-id='settings_docs_tooltips_master_toggle'
              aria-label='Enable Kangur docs tooltips'
            />
          </div>
        </KangurAdminCard>

        <div className={`${KANGUR_GRID_RELAXED_CLASSNAME} lg:grid-cols-2`}>
          {DOCS_TOOLTIP_SURFACES.map((surface) => (
            <KangurAdminCard key={surface.key}>
              <div className='flex items-start justify-between gap-4'>
                <div>
                  <div className='flex items-center gap-2'>
                    <div className='text-sm font-semibold text-foreground'>{surface.label}</div>
                    <Badge variant={helpSettings.docsTooltips[surface.key] ? 'secondary' : 'outline'}>
                      {helpSettings.docsTooltips[surface.key] ? 'On' : 'Off'}
                    </Badge>
                  </div>
                  <p className='mt-1 text-sm text-muted-foreground'>{surface.description}</p>
                </div>
                <Switch
                  checked={helpSettings.docsTooltips[surface.key]}
                  onCheckedChange={(checked) =>
                    setHelpSettings((current) => ({
                      ...current,
                      docsTooltips: {
                        ...current.docsTooltips,
                        [surface.key]: checked,
                      },
                    }))
                  }
                  data-doc-id={surface.docId}
                  aria-label={`${surface.label} docs tooltips`}
                />
              </div>
            </KangurAdminCard>
          ))}
        </div>

        <KangurAdminCard>
          <div className='flex items-center justify-between gap-4'>
            <div>
              <div className='flex items-center gap-2'>
                <div className='text-sm font-semibold text-foreground'>Current admin preview</div>
                <Badge variant={adminDocsEnabled ? 'secondary' : 'outline'}>
                  {adminDocsEnabled ? 'Enabled' : 'Disabled'}
                </Badge>
              </div>
              <p className='mt-1 text-sm text-muted-foreground'>
                Tooltips on this page follow the in-progress settings state before you save.
              </p>
            </div>
            <Button
              type='button'
              variant='outline'
              size='sm'
              disabled={!isDirty || isSaving}
              onClick={() => {
                void handleSave();
              }}
            >
              {isSaving ? 'Saving…' : 'Save tooltip settings'}
            </Button>
          </div>
        </KangurAdminCard>
      </FormSection>
    </>
  );
}

