import { useKangurPageContentMutations } from '../hooks/useKangurPageContentMutations';
import {
  KANGUR_ADMIN_INSET_CARD_CLASS_NAME,
  KangurAdminCard,
  KangurAdminInsetCard,
} from './KangurAdminCard';
import { KangurPageContentEntryEditor } from './KangurPageContentEntryEditor';
import { KangurPageContentEntryList } from './KangurPageContentEntryList';
import { KangurPageContentManifestCoverage } from './KangurPageContentManifestCoverage';

const AI_TUTOR_PAGE_CONTENT_EDITOR_LOCALE = 'pl';
const SETTINGS_SECTION_CLASS_NAME = 'border-border/60 bg-card/35 shadow-sm';

export function KangurPageContentSettingsPanel(): React.JSX.Element {
  const {
    editorValue,
    setEditorValue,
    isLoading,
    isSaving,
    selectedEntryId,
    setSelectedEntryId,
    selectedFragmentId,
    setSelectedFragmentId,
    isDirty,
    parsedState,
    selectedEntry,
    loadStore,
    handleSave,
    handleAddEntry,
    handleDuplicateSelectedEntry,
    handleDeleteSelectedEntry,
    handleMoveSelectedEntry,
    handleResetToDefaults,
    updateSelectedEntry,
    updateSelectedFragment,
    handleAddFragment,
    handleDuplicateSelectedFragment,
    handleDeleteSelectedFragment,
    handleMoveSelectedFragment,
  } = useKangurPageContentMutations();

  return (
    <FormSection
      title='AI Tutor Page Content'
      description='Edit the canonical Mongo section records that connect page anchors, content ids, and linked native-guide explanations.'
      className={SETTINGS_SECTION_CLASS_NAME}
    >
      <KangurAdminCard>
        <div className='flex flex-col gap-3 md:flex-row md:items-start md:justify-between'>
          <div>
            <div className='flex items-center gap-2'>
              <div className='text-sm font-semibold text-foreground'>Canonical section layer</div>
              <Badge variant='secondary'>Locale {AI_TUTOR_PAGE_CONTENT_EDITOR_LOCALE}</Badge>
            </div>
            <p className='mt-1 text-sm text-muted-foreground'>
              Each record is a canonical Kangur page or section node. The tutor uses these ids for
              section targeting, while the knowledge graph links them to native guides.
            </p>
          </div>
          <div className='flex flex-wrap gap-2'>
            <Button
              variant='outline'
              size='sm'
              onClick={() => {
                void loadStore();
              }}
              disabled={isLoading || isSaving}
            >
              {isLoading ? 'Loading...' : 'Reload page content'}
            </Button>
            <Button variant='outline' size='sm' onClick={handleAddEntry} disabled={isSaving}>
              Add section
            </Button>
            <Button
              variant='ghost'
              size='sm'
              onClick={handleResetToDefaults}
              disabled={isSaving}
            >
              Reset to defaults
            </Button>
            <Button
              size='sm'
              onClick={() => {
                void handleSave();
              }}
              disabled={
                isLoading ||
                isSaving ||
                !isDirty ||
                Boolean(parsedState.error) ||
                !parsedState.store
              }
            >
              {isSaving ? 'Saving page content...' : 'Save page content'}
            </Button>
          </div>
        </div>

        {parsedState.error ? (
          <Alert variant='error' title='Invalid page-content JSON' className='mt-4'>
            {parsedState.error}
          </Alert>
        ) : null}

        {parsedState.store ? (
          <KangurPageContentManifestCoverage store={parsedState.store} />
        ) : isLoading ? (
          <Alert variant='info' title='Loading page content from Mongo' className='mt-4'>
            Waiting for the canonical Kangur page-content store.
          </Alert>
        ) : null}

        {!parsedState.store && !parsedState.error && !isLoading ? (
          <Alert variant='info' title='No page content loaded' className='mt-4'>
            Reload the Mongo-backed page-content store or reset to defaults to begin editing.
          </Alert>
        ) : null}

        {parsedState.store ? (
          <div
            className={`${KANGUR_GRID_RELAXED_CLASSNAME} mt-4 xl:grid-cols-[320px_minmax(0,1fr)]`}
          >
            <KangurPageContentEntryList
              entries={parsedState.store.entries}
              selectedEntryId={selectedEntryId}
              onSelect={setSelectedEntryId}
              className={KANGUR_ADMIN_INSET_CARD_CLASS_NAME}
            />

            {selectedEntry ? (
              <KangurPageContentEntryEditor
                entry={selectedEntry}
                onUpdateEntry={updateSelectedEntry}
                onDuplicateEntry={handleDuplicateSelectedEntry}
                onDeleteEntry={handleDeleteSelectedEntry}
                onMoveEntry={handleMoveSelectedEntry}
                isSaving={isSaving}
                canDelete={parsedState.store.entries.length > 1}
                selectedFragmentId={selectedFragmentId}
                onSelectFragment={setSelectedFragmentId}
                onUpdateFragment={updateSelectedFragment}
                onAddFragment={handleAddFragment}
                onDuplicateFragment={handleDuplicateSelectedFragment}
                onDeleteFragment={handleDeleteSelectedFragment}
                onMoveFragment={handleMoveSelectedFragment}
                className={KANGUR_ADMIN_INSET_CARD_CLASS_NAME}
                insetCardClassName={KANGUR_ADMIN_INSET_CARD_CLASS_NAME}
              />
            ) : (
              <KangurAdminInsetCard>
                <div className='rounded-2xl border border-dashed border-border/60 px-4 py-8 text-sm text-muted-foreground text-center'>
                  Select a page-content entry from the list to start editing.
                </div>
              </KangurAdminInsetCard>
            )}
          </div>
        ) : null}

        <KangurAdminInsetCard className='mt-4'>
          <FormField
            label='Page content JSON'
            description='Raw mirror of the full canonical section document. Use this for bulk edits or direct structural changes.'
          >
            <Textarea
              value={editorValue}
              onChange={(event) => setEditorValue(event.target.value)}
              rows={20}
              aria-label='Page content JSON'
              spellCheck={false}
              className='font-mono text-xs'
              title='Page content JSON'
            />
          </FormField>
          <div className='mt-2 text-xs text-muted-foreground text-center'>
            {isDirty ? 'Unsaved page-content changes' : 'Page content in sync'}
          </div>
        </KangurAdminInsetCard>
      </KangurAdminCard>
    </FormSection>
  );
}

'use client';

import React, { createContext, useContext } from 'react';

import {
  KANGUR_PARENT_VERIFICATION_RESEND_COOLDOWN_SECONDS_MIN,
  KANGUR_PARENT_VERIFICATION_RESEND_COOLDOWN_SECONDS_MAX,
} from '@/features/kangur/settings';
import {
  Alert,
  Badge,
  Button,
  FormField,
  FormSection,
  Input,
  ToggleRow,
} from '@/features/kangur/shared/ui';
import { withKangurClientErrorSync } from '@/features/kangur/observability/client';

import { KangurAdminCard } from './KangurAdminCard';

const formatShortTimestamp = (value: string): string => {
  return withKangurClientErrorSync(
    {
      source: 'kangur.admin.settings',
      action: 'format-timestamp',
      description: 'Formats a timestamp for settings display.',
      context: { value },
    },
    () =>
      new Intl.DateTimeFormat('pl-PL', {
        dateStyle: 'medium',
        timeStyle: 'short',
      }).format(new Date(value)),
    { fallback: value }
  );
};

interface KangurParentVerificationSettingsContextValue {
  requireEmailVerification: boolean;
  setRequireEmailVerification: (value: boolean) => void;
  requireCaptcha: boolean;
  setRequireCaptcha: (value: boolean) => void;
  notificationsEnabled: boolean;
  setNotificationsEnabled: (value: boolean) => void;
  notificationsDisabledUntilInput: string;
  setNotificationsDisabledUntilInput: (value: string) => void;
  resendCooldownInput: string;
  setResendCooldownInput: (value: string) => void;
  notificationsPausedUntil: string | null;
}

const KangurParentVerificationSettingsContext = createContext<KangurParentVerificationSettingsContextValue | null>(null);

function useParentVerificationSettings() {
  const context = useContext(KangurParentVerificationSettingsContext);
  if (!context) {
    throw new Error('useParentVerificationSettings must be used within a KangurParentVerificationSettingsPanel');
  }
  return context;
}

function RequireEmailVerificationToggle() {
  const { requireEmailVerification, setRequireEmailVerification } = useParentVerificationSettings();
  return (
    <FormField
      label='Wymagaj potwierdzenia e-maila rodzica'
      description='Disable to activate parent accounts immediately without email verification.'
    >
      <ToggleRow
        label={requireEmailVerification ? 'Włączone' : 'Wyłączone'}
        description={
          requireEmailVerification
            ? 'Parents must confirm their email before signing in.'
            : 'New parent accounts are activated immediately.'
        }
        checked={requireEmailVerification}
        onCheckedChange={setRequireEmailVerification}
        variant='switch'
        className='border-none bg-muted/20 px-3 py-2 hover:bg-muted/30'
      />
    </FormField>
  );
}

function RequireCaptchaToggle() {
  const { requireCaptcha, setRequireCaptcha } = useParentVerificationSettings();
  return (
    <FormField
      label='Wymagaj Captcha przy zakładaniu konta'
      description='Disable to skip the Turnstile check during parent signup.'
    >
      <ToggleRow
        label={requireCaptcha ? 'Włączona' : 'Wyłączona'}
        description={
          requireCaptcha
            ? 'Captcha runs when Turnstile keys are configured.'
            : 'Parent signup skips the Captcha check.'
        }
        checked={requireCaptcha}
        onCheckedChange={setRequireCaptcha}
        variant='switch'
        className='border-none bg-muted/20 px-3 py-2 hover:bg-muted/30'
      />
    </FormField>
  );
}

function NotificationsEnabledToggle() {
  const { notificationsEnabled, setNotificationsEnabled } = useParentVerificationSettings();
  return (
    <FormField
      label='Wysyłka e-maili potwierdzających'
      description='Disable to pause delivery of parent email confirmations.'
    >
      <ToggleRow
        label={notificationsEnabled ? 'Włączona' : 'Wyłączona'}
        description={
          notificationsEnabled
            ? 'Notifications are active for new parent verifications.'
            : 'Parent confirmation emails will not be sent.'
        }
        checked={notificationsEnabled}
        onCheckedChange={setNotificationsEnabled}
        variant='switch'
        className='border-none bg-muted/20 px-3 py-2 hover:bg-muted/30'
      />
    </FormField>
  );
}

function NotificationsDisabledUntilInput() {
  const { notificationsDisabledUntilInput, setNotificationsDisabledUntilInput, notificationsPausedUntil } = useParentVerificationSettings();
  return (
    <FormField
      label='Wstrzymaj wysyłkę do'
      description='Temporarily pause confirmation emails until the chosen time (local). Leave blank to send normally.'
    >
      <Input
        type='datetime-local'
        value={notificationsDisabledUntilInput}
        onChange={(event) =>
          setNotificationsDisabledUntilInput(event.target.value)
        }
        aria-label='Wstrzymaj wysyłkę do'
        title='Wstrzymaj wysyłkę do'
      />
      <div className='mt-2 flex flex-wrap items-center gap-2'>
        <Button
          type='button'
          variant='ghost'
          size='sm'
          onClick={() => setNotificationsDisabledUntilInput('')}
        >
          Clear pause
        </Button>
        {notificationsPausedUntil ? (
          <Badge variant='outline'>
            Wstrzymane do {formatShortTimestamp(notificationsPausedUntil)}
          </Badge>
        ) : null}
      </div>
    </FormField>
  );
}

function ResendCooldownInput() {
  const { resendCooldownInput, setResendCooldownInput } = useParentVerificationSettings();
  return (
    <>
      <FormField
        label='Czas oczekiwania na ponowne wysłanie e-maila (sekundy)'
        description='Controls how long to wait before another verification email can be sent to the same address.'
      >
        <Input
          type='number'
          min={KANGUR_PARENT_VERIFICATION_RESEND_COOLDOWN_SECONDS_MIN}
          max={KANGUR_PARENT_VERIFICATION_RESEND_COOLDOWN_SECONDS_MAX}
          step={1}
          value={resendCooldownInput}
          onChange={(event) => setResendCooldownInput(event.target.value)}
          aria-label='Czas oczekiwania na ponowne wysłanie e-maila (sekundy)'
          inputMode='numeric'
          title='Czas oczekiwania na ponowne wysłanie e-maila (sekundy)'
        />
      </FormField>
      <p className='text-xs text-muted-foreground'>
        Akceptowany zakres: {KANGUR_PARENT_VERIFICATION_RESEND_COOLDOWN_SECONDS_MIN}–
        {KANGUR_PARENT_VERIFICATION_RESEND_COOLDOWN_SECONDS_MAX} s.
      </p>
    </>
  );
}

interface KangurParentVerificationSettingsPanelProps extends KangurParentVerificationSettingsContextValue {
  className?: string;
}

export function KangurParentVerificationSettingsPanel(props: KangurParentVerificationSettingsPanelProps): React.JSX.Element {
  const { className, ...contextValue } = props;
  return (
    <KangurParentVerificationSettingsContext.Provider value={contextValue}>
      <FormSection
        title='Parent verification email'
        description='Configure resend throttling for parent account verification emails.'
        className={className}
        gridClassName='gap-4 lg:grid-cols-[minmax(0,1.2fr)_minmax(0,0.8fr)]'
      >
        <KangurAdminCard>
          <div className='space-y-4'>
            <RequireEmailVerificationToggle />
            <RequireCaptchaToggle />
            <NotificationsEnabledToggle />
            <NotificationsDisabledUntilInput />
            <ResendCooldownInput />
          </div>
        </KangurAdminCard>
        <div className='space-y-3'>
          <Alert variant='default' title='Scope'>
            Applies to parent create-account and resend-verification actions across login pages and public
            enrollment flow.
          </Alert>
          <Alert variant='default' title='Security'>
            Shorter values increase retry attempts and email traffic. Longer values reduce request spam but
            also slow account confirmation.
          </Alert>
        </div>
      </FormSection>
    </KangurParentVerificationSettingsContext.Provider>
  );
}

import { ArrowDown, ArrowUp, Copy, Trash2 } from 'lucide-react';
import React from 'react';

import type { KangurTestQuestion } from '@/features/kangur/shared/contracts/kangur-tests';
import { Badge, Button } from '@/features/kangur/shared/ui';
import { KANGUR_STACK_RELAXED_CLASSNAME } from '@/features/kangur/ui/design/tokens';

import {
  hasIllustration,
  hasRichChoiceContent,
  usesRichQuestionPresentation,
} from '../../test-suites/questions';
import type { QuestionAuthoringSummary } from '../question-authoring-insights';
import type { QuestionManagerCopy } from '../question-manager.copy';

interface KangurQuestionListItemProps {
  copy: QuestionManagerCopy['listItem'];
  question: KangurTestQuestion;
  index: number;
  absoluteIndex: number;
  canReorder: boolean;
  isSaving: boolean;
  questionSummary: QuestionAuthoringSummary | null;
  queuePosition?: number | null;
  onMoveUp: () => void;
  onMoveDown: () => void;
  onEdit: () => void;
  onDuplicate: () => void;
  onDelete: () => void;
}

export function KangurQuestionListItem(
  props: KangurQuestionListItemProps
): React.JSX.Element {
  const {
    copy,
    question,
    index,
    absoluteIndex,
    canReorder,
    isSaving,
    questionSummary,
    queuePosition,
    onMoveUp,
    onMoveDown,
    onEdit,
    onDuplicate,
    onDelete,
  } = props;
  const workflowLabel = copy.workflowLabels[question.editorial.workflowStatus];

  return (
    <div className={`${KANGUR_STACK_RELAXED_CLASSNAME} group rounded-2xl border border-border/50 bg-card/35 p-4 transition hover:border-cyan-400/30 hover:bg-card/50 sm:flex-row sm:items-start sm:p-5`}>
      <div className='flex shrink-0 flex-row gap-1.5 rounded-xl border border-border/50 bg-background/25 p-1 sm:flex-col'>
        <Button
          type='button'
          size='sm'
          variant='ghost'
          className='h-5 px-1'
          onClick={onMoveUp}
          disabled={!canReorder || absoluteIndex === 0 || isSaving}
          aria-label={copy.moveUp}
          title={copy.moveUp}
        >
          <ArrowUp className='size-3' />
        </Button>
        <Button
          type='button'
          size='sm'
          variant='ghost'
          className='h-5 px-1'
          onClick={onMoveDown}
          disabled={!canReorder || absoluteIndex < 0 || isSaving}
          aria-label={copy.moveDown}
          title={copy.moveDown}
        >
          <ArrowDown className='size-3' />
        </Button>
      </div>

      <div className='min-w-0 flex-1'>
        <div className='mb-2.5 flex flex-wrap items-center gap-1.5'>
          <span className='text-xs font-semibold text-gray-400'>#{index + 1}</span>
          {absoluteIndex >= 0 ? (
            <Badge variant='outline' className='h-4 px-1 text-[9px] text-slate-300'>
              {copy.order(absoluteIndex + 1)}
            </Badge>
          ) : null}
          {queuePosition ? (
            <Badge variant='outline' className='h-4 px-1 text-[9px] text-cyan-300 border-cyan-400/40'>
              {copy.queue(queuePosition)}
            </Badge>
          ) : null}
          <Badge variant='outline' className='h-4 px-1 text-[9px]'>
            {copy.points(question.pointValue)}
          </Badge>
          <Badge
            variant='outline'
            className='h-4 px-1 text-[9px] text-emerald-300 border-emerald-400/40'
          >
            ✓ {question.correctChoiceLabel}
          </Badge>
          {hasIllustration(question) ? (
            <Badge
              variant='outline'
              className='h-4 px-1 text-[9px] text-violet-300 border-violet-400/40'
            >
              {copy.svg}
            </Badge>
          ) : null}
          {hasRichChoiceContent(question) ? (
            <Badge
              variant='outline'
              className='h-4 px-1 text-[9px] text-sky-300 border-sky-400/40'
            >
              {copy.choiceUi}
            </Badge>
          ) : null}
          {usesRichQuestionPresentation(question) ? (
            <Badge
              variant='outline'
              className='h-4 px-1 text-[9px] text-cyan-300 border-cyan-400/40'
            >
              {copy.layout}
            </Badge>
          ) : null}
          {questionSummary?.status === 'needs-review' ? (
            <Badge
              variant='outline'
              className='h-4 px-1 text-[9px] text-amber-300 border-amber-400/40'
            >
              {copy.review}
            </Badge>
          ) : null}
          {questionSummary?.status === 'needs-fix' ? (
            <Badge
              variant='outline'
              className='h-4 px-1 text-[9px] text-rose-300 border-rose-400/40'
            >
              {copy.fix}
            </Badge>
          ) : null}
          <Badge
            variant='outline'
            className={
              question.editorial.workflowStatus === 'published'
                ? 'h-4 px-1 text-[9px] text-emerald-300 border-emerald-400/40'
                : question.editorial.workflowStatus === 'ready'
                  ? 'h-4 px-1 text-[9px] text-cyan-300 border-cyan-400/40'
                  : 'h-4 px-1 text-[9px] text-slate-300 border-slate-400/40'
            }
          >
            {workflowLabel}
          </Badge>
        </div>
        <p className='line-clamp-2 text-sm leading-6 text-gray-200 sm:text-[15px]'>
          {question.prompt || copy.emptyPrompt}
        </p>
      </div>

      <div className='flex shrink-0 items-center justify-end gap-1 rounded-xl border border-border/50 bg-background/25 p-1 sm:justify-start'>
        <button
          type='button'
          className='inline-flex items-center justify-center rounded-lg p-2.5 text-gray-400 hover:bg-sky-500/20 hover:text-sky-200 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 focus-visible:ring-offset-2 ring-offset-background'
          onClick={onEdit}
          title={copy.editQuestion}
          disabled={isSaving}
        >
          <span className='sr-only'>{copy.edit}</span>
          <svg className='size-3.5' fill='none' viewBox='0 0 24 24' stroke='currentColor'>
            <path
              strokeLinecap='round'
              strokeLinejoin='round'
              strokeWidth={2}
              d='M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z'
            />
          </svg>
        </button>
        <button
          type='button'
          className='inline-flex items-center justify-center rounded-lg p-2.5 text-gray-400 hover:bg-gray-700/60 hover:text-white focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 focus-visible:ring-offset-2 ring-offset-background'
          onClick={onDuplicate}
          title={copy.duplicateQuestion}
          disabled={isSaving}
          aria-label={copy.duplicateQuestion}
        >
          <Copy className='size-3.5' />
        </button>
        <button
          type='button'
          className='inline-flex items-center justify-center rounded-lg p-2.5 text-gray-400 hover:bg-red-500/20 hover:text-red-300 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 focus-visible:ring-offset-2 ring-offset-background'
          onClick={onDelete}
          title={copy.deleteQuestion}
          disabled={isSaving}
          aria-label={copy.deleteQuestion}
        >
          <Trash2 className='size-3.5' />
        </button>
      </div>
    </div>
  );
}

import React from 'react';

import type { LabeledOptionDto } from '@/shared/contracts/base';
import { Button, Input } from '@/features/kangur/shared/ui';

import type { QuestionManagerCopy } from '../question-manager.copy';
import type { QuestionListFilter, QuestionListSort } from '../question-manager-view';

interface KangurQuestionsFilterTriageProps {
  copy: QuestionManagerCopy['filters'];
  searchQuery: string;
  onSearchChange: (value: string) => void;
  sortMode: QuestionListSort;
  onSortChange: (value: QuestionListSort) => void;
  listFilter: QuestionListFilter;
  onFilterChange: (value: QuestionListFilter) => void;
  filterOptions: Array<LabeledOptionDto<QuestionListFilter>>;
  sortOptions: Array<LabeledOptionDto<QuestionListSort>>;
}

export function KangurQuestionsFilterTriage(
  props: KangurQuestionsFilterTriageProps
): React.JSX.Element {
  const {
    copy,
    searchQuery,
    onSearchChange,
    sortMode,
    onSortChange,
    listFilter,
    onFilterChange,
    filterOptions,
    sortOptions,
  } = props;
  return (
    <div className='rounded-[28px] border border-border/60 bg-card/25 p-4 sm:p-5'>
      <div className='mb-3 text-[10px] font-semibold uppercase tracking-[0.2em] text-muted-foreground'>
        {copy.panelTitle}
      </div>
      <div className='grid gap-3.5 lg:grid-cols-[minmax(0,1fr)_auto] lg:items-end'>
        <Input
          type='search'
          value={searchQuery}
          onChange={(event): void => onSearchChange(event.target.value)}
          placeholder={copy.searchPlaceholder}
          aria-label={copy.searchAriaLabel}
          className='h-10 text-sm'
          title={copy.searchPlaceholder}
        />
        <div className='grid gap-3 lg:min-w-[26rem] lg:grid-cols-2'>
          <div className='space-y-2'>
            <div className='text-[10px] font-semibold uppercase tracking-[0.18em] text-muted-foreground'>
              {copy.sortLabel}
            </div>
            <div className='flex flex-wrap items-center gap-2'>
              {sortOptions.map((option) => {
                const isActive = option.value === sortMode;
                return (
                  <Button
                    key={option.value}
                    type='button'
                    size='sm'
                    variant='outline'
                    className={
                      isActive
                        ? 'h-8 rounded-full border-cyan-400/50 bg-cyan-500/15 px-3 text-[11px] text-cyan-100'
                        : 'h-8 rounded-full px-3 text-[11px]'
                    }
                    onClick={(): void => onSortChange(option.value)}
                  >
                    {option.label}
                  </Button>
                );
              })}
            </div>
          </div>
          <div className='space-y-2'>
            <div className='text-[10px] font-semibold uppercase tracking-[0.18em] text-muted-foreground'>
              {copy.filterLabel}
            </div>
            <div className='flex flex-wrap items-center gap-2'>
              {filterOptions.map((option) => {
                const isActive = option.value === listFilter;
                return (
                  <Button
                    key={option.value}
                    type='button'
                    size='sm'
                    variant='outline'
                    className={
                      isActive
                        ? 'h-8 rounded-full border-sky-400/50 bg-sky-500/15 px-3 text-[11px] text-sky-100'
                        : 'h-8 rounded-full px-3 text-[11px]'
                    }
                    onClick={(): void => onFilterChange(option.value)}
                  >
                    {option.label}
                  </Button>
                );
              })}
            </div>
          </div>
        </div>
      </div>
      {listFilter !== 'all' || sortMode !== 'manual' ? (
        <div className='mt-3 text-[11px] text-muted-foreground'>
          {copy.reorderHint}
        </div>
      ) : null}
    </div>
  );
}

