              illustration.layout === 'row'
                ? 'flex flex-wrap'
                : illustration.layout === 'grid-2x2'
                  ? 'grid grid-cols-2'
                  : 'grid grid-cols-3'
            )}
          >
            {illustration.panels.map((panel) => (
              <div
                key={panel.id}
                className={cn(illustration.layout === 'row' ? 'min-w-[280px] flex-1' : '')}
              >
