const getTranslationStatusBadgeVariant = (status: string): 'outline' | 'secondary' | 'warning' => {
  switch (status) {
    case 'manual':
      return 'secondary';
    case 'missing':
    case 'source-copy':
      return 'warning';
    default:
      return 'outline';
  }
};

const formatTranslationStatusLabel = (locale: string, status: string): string => {
  switch (status) {
    case 'manual':
      return `${locale.toUpperCase()} manual`;
    case 'scaffolded':
      return `${locale.toUpperCase()} scaffolded`;
    case 'source-copy':
      return `${locale.toUpperCase()} source copy`;
    case 'missing':
      return `${locale.toUpperCase()} missing`;
    default:
      return `${locale.toUpperCase()} source`;
  }
};

export function RenderValidationIssues({
  issues,
}: {
  issues: KangurAiTutorOnboardingValidationIssue[];
}): React.JSX.Element | null {
  if (issues.length === 0) {
    return null;
  }

  return (
    <div className='space-y-2'>
      {issues.map((issue, index) => (
        <div
          key={`${issue.ruleId ?? issue.title}-${issue.field}-${index}`}
          className={`rounded-xl border px-3 py-2 text-xs ${
            issue.blocking
              ? 'border-rose-500/30 bg-rose-500/10 text-rose-950'
              : 'border-amber-500/30 bg-amber-500/10 text-amber-950'
          }`}
        >
          <div className='font-semibold'>{issue.title}</div>
          <div className='mt-0.5'>{issue.message}</div>
        </div>
      ))}
    </div>
  );
}

