import * as React from 'react';

import {
  Alert,
  Button,
  CompactEmptyState,
  FormSection,
  MetadataItem,
  StatusBadge,
} from '@/features/kangur/shared/ui';

import { useKnowledgeGraphObservability } from './KnowledgeGraphObservabilityContext';
import {
  describeKnowledgeGraphStatus,
  formatDateTime,
  formatKnowledgeGraphReadiness,
  formatNumber,
  resolveKnowledgeGraphBadgeStatus,
} from './utils';

export function KnowledgeGraphStatusSection(): React.JSX.Element {
  const {
    knowledgeGraphStatus,
    knowledgeGraphStatusIsRefreshing,
    knowledgeGraphIsSyncing,
    knowledgeGraphSyncFeedback,
    knowledgeGraphStatusError: error,
    refreshKnowledgeGraphStatus: onRefresh,
    syncKnowledgeGraph: onSync,
  } = useKnowledgeGraphObservability();

  const isRefreshing = knowledgeGraphStatusIsRefreshing;
  const isSyncing = knowledgeGraphIsSyncing;
  const syncFeedback = knowledgeGraphSyncFeedback;

  if (knowledgeGraphStatus.mode === 'disabled') {
    return (
      <div id='knowledge-graph-status'>
        <FormSection title='Knowledge Graph Status' variant='subtle'>
          <CompactEmptyState
            title='Neo4j graph status disabled'
            description={knowledgeGraphStatus.message}
            action={
              <Button variant='outline' size='sm' onClick={onRefresh} disabled={isRefreshing}>
                Refresh graph status
              </Button>
            }
           />
        </FormSection>
      </div>
    );
  }

  if (knowledgeGraphStatus.mode === 'error') {
    return (
      <div id='knowledge-graph-status'>
        <FormSection title='Knowledge Graph Status' variant='subtle'>
          <div className='space-y-3'>
            <Alert variant='error'>
              <div className='font-semibold'>Neo4j connection error</div>
              <p className='mt-1 text-xs opacity-90'>{knowledgeGraphStatus.message}</p>
            </Alert>
            <Button variant='outline' size='sm' onClick={onRefresh} disabled={isRefreshing}>
              Retry status check
            </Button>
          </div>
        </FormSection>
      </div>
    );
  }

  // mode is 'status'
  const status = knowledgeGraphStatus;

  return (
    <div id='knowledge-graph-status'>
      <FormSection title='Knowledge Graph Status' variant='subtle'>
        {error ? (
          <Alert variant='warning' className='mb-4'>
            {error.message}
          </Alert>
        ) : null}

        <div className='space-y-4'>
          <div className='flex flex-wrap items-start justify-between gap-4'>
            <div className='space-y-1.5'>
              <div className='flex flex-wrap items-center gap-3'>
                <StatusBadge
                  status={resolveKnowledgeGraphBadgeStatus(status)}
                  label={formatKnowledgeGraphReadiness(status.semanticReadiness)}
                />
                <div className='text-sm font-semibold text-white'>{status.graphKey}</div>
              </div>
              <p className='max-w-2xl text-xs leading-relaxed text-gray-400'>
                {describeKnowledgeGraphStatus(status)}
              </p>
            </div>

            <div className='flex flex-wrap items-center gap-2'>
              {syncFeedback ? (
                <div
                  className={
                    syncFeedback.tone === 'success' ? 'text-xs text-emerald-400' : 'text-xs text-rose-400'
                  }
                >
                  {syncFeedback.message}
                </div>
              ) : null}
              <Button
                variant='outline'
                size='sm'
                onClick={onSync}
                disabled={isSyncing || isRefreshing}
              >
                {isSyncing ? 'Syncing...' : 'Sync Graph'}
              </Button>
              <Button variant='ghost' size='sm' onClick={onRefresh} disabled={isRefreshing}>
                {isRefreshing ? 'Refreshing...' : 'Refresh Status'}
              </Button>
            </div>
          </div>

          <div className='grid gap-3 sm:grid-cols-2 xl:grid-cols-4'>
            <MetadataItem label='Locale' value={status.locale || '—'} variant='card' />
            <MetadataItem
              label='Last Sync'
              value={formatDateTime(status.syncedAt)}
              variant='card'
            />
            <MetadataItem
              label='Live Nodes'
              value={formatNumber(status.liveNodeCount)}
              variant='card'
            />
            <MetadataItem
              label='Live Edges'
              value={formatNumber(status.liveEdgeCount)}
              variant='card'
            />
            <MetadataItem
              label='Synced Nodes'
              value={formatNumber(status.syncedNodeCount)}
              variant='card'
            />
            <MetadataItem
              label='Synced Edges'
              value={formatNumber(status.syncedEdgeCount)}
              variant='card'
            />
            <MetadataItem
              label='Embeddings'
              value={formatNumber(status.embeddingNodeCount)}
              variant='card'
            />
            <MetadataItem
              label='Vector Index'
              value={status.vectorIndexPresent ? 'Online' : 'Missing'}
              variant='card'
            />
          </div>
        </div>
      </FormSection>
    </div>
  );
}

import { type JSX } from 'react';

import { Button, Card, CompactEmptyState, FormSection, MetadataItem, StatusBadge } from '@/features/kangur/shared/ui';

import { useObservabilitySummaryContext } from '../../AdminKangurObservabilityPage';
import { useKnowledgeGraphObservability } from './KnowledgeGraphObservabilityContext';
import { formatDateTime } from './utils';

export function RecentAnalyticsEvents(): JSX.Element {
  const {
    summary: {
      analytics: { recent: events },
    },
  } = useObservabilitySummaryContext();
  const {
    knowledgeGraphPreviewReplayCandidates: replayCandidates,
    knowledgeGraphPreviewDraft: draft,
    replayAnalyticsEventInKnowledgeGraphPreview: onReplayEvent,
  } = useKnowledgeGraphObservability();

  const activeReplayEventId = draft.replayEventId;
  const replayCandidateById = new Map(
    replayCandidates.map((candidate) => [candidate.id, candidate] as const)
  );

  return (
    <div id='recent-analytics-events'>
      <FormSection title='Recent Analytics Events' variant='subtle'>
        {events.length === 0 ? (
          <CompactEmptyState
            title='No recent analytics events'
            description='Client telemetry has not recorded a recent Kangur event in this window.'
           />
        ) : (
          <div className='space-y-2'>
            {events.map((event) => {
              const replayCandidate = replayCandidateById.get(event.id) ?? null;
              const isLoadedInPreview = replayCandidate?.id === activeReplayEventId;

              return (
                <Card
                  key={event.id}
                  variant='subtle'
                  padding='sm'
                  className='border-border/60 bg-card/40'
                >
                  <div className='flex items-start justify-between gap-3'>
                    <div className='min-w-0'>
                      <div className='truncate text-sm font-semibold text-white'>
                        {event.name ?? event.type}
                      </div>
                      <div className='mt-1 truncate text-xs text-gray-400'>{event.path || '—'}</div>
                    </div>
                    <StatusBadge status={event.type === 'pageview' ? 'info' : 'active'} />
                  </div>
                  <div className='mt-3 grid gap-2 sm:grid-cols-3'>
                    <MetadataItem label='At' value={formatDateTime(event.ts)} variant='minimal' />
                    <MetadataItem
                      label='Visitor'
                      value={event.visitorId || '—'}
                      variant='minimal'
                      mono
                    />
                    <MetadataItem
                      label='Session'
                      value={event.sessionId || '—'}
                      variant='minimal'
                      mono
                    />
                  </div>
                  {replayCandidate ? (
                    <div className='mt-4 flex flex-wrap items-center justify-between gap-3 border-t border-border/50 pt-3'>
                      <div className='min-w-0 flex-1 space-y-1'>
                        <div className='text-[11px] font-semibold uppercase tracking-[0.18em] text-gray-500'>
                          Replayable tutor prompt
                        </div>
                        <p className='truncate text-xs text-gray-300'>
                          {replayCandidate.latestUserMessage}
                        </p>
                      </div>
                      <Button
                        variant={isLoadedInPreview ? 'outline' : 'ghost'}
                        size='sm'
                        onClick={() => onReplayEvent(replayCandidate.id)}
                      >
                        {isLoadedInPreview ? 'Loaded in graph preview' : 'Replay in graph preview'}
                      </Button>
                    </div>
                  ) : null}
                </Card>
              );
            })}
          </div>
        )}
      </FormSection>
    </div>
  );
}

