export const buildKnowledgeGraphPreviewReplayCandidates = (
  events: readonly KangurRecentAnalyticsEvent[]
): KnowledgeGraphPreviewReplayCandidate[] =>
  events
    .filter((event) =>
      event.name === 'kangur_ai_tutor_message_sent' ||
      event.name === 'kangur_ai_tutor_message_succeeded' ||
      event.name === 'kangur_ai_tutor_message_failed'
    )
    .map((event) => {
      const meta =
        event.meta && typeof event.meta === 'object' && !Array.isArray(event.meta)
          ? event.meta
          : null;
      const latestUserMessage = readKnowledgeGraphPreviewReplayString(meta, 'latestUserMessage');
      const surface = readKnowledgeGraphPreviewReplayString(meta, 'surface');
      const contentId = readKnowledgeGraphPreviewReplayString(meta, 'contentId');
      const title = readKnowledgeGraphPreviewReplayString(meta, 'title');
      const description = readKnowledgeGraphPreviewReplayString(meta, 'description');
      const promptMode = readKnowledgeGraphPreviewReplayString(meta, 'promptMode');
      const interactionIntent = readKnowledgeGraphPreviewReplayString(meta, 'interactionIntent');
      const focusKind = readKnowledgeGraphPreviewReplayString(meta, 'focusKind');
      const focusId = readKnowledgeGraphPreviewReplayString(meta, 'focusId');
      const focusLabel = readKnowledgeGraphPreviewReplayString(meta, 'focusLabel');
      const questionId = readKnowledgeGraphPreviewReplayString(meta, 'questionId');
      const assignmentId = readKnowledgeGraphPreviewReplayString(meta, 'assignmentId');
      const selectedText = readKnowledgeGraphPreviewReplayString(meta, 'selectedText');
      const answerRevealed = readKnowledgeGraphPreviewReplayBoolean(meta, 'answerRevealed');
      const displaySurface =
        surface && surface in KNOWLEDGE_GRAPH_PREVIEW_SURFACE_LABELS
          ? KNOWLEDGE_GRAPH_PREVIEW_SURFACE_LABELS[surface as KangurAiTutorSurface]
          : 'General';
      const displayPromptMode =
        promptMode && promptMode in KNOWLEDGE_GRAPH_PREVIEW_PROMPT_MODE_LABELS
          ? KNOWLEDGE_GRAPH_PREVIEW_PROMPT_MODE_LABELS[promptMode as KangurAiTutorPromptMode]
          : 'Chat';
      const displayTarget =
        focusLabel || title || selectedText || latestUserMessage.slice(0, 48) || event.path || event.id;
      const eventLabel =
        event.name === 'kangur_ai_tutor_message_sent'
          ? 'Sent'
          : event.name === 'kangur_ai_tutor_message_succeeded'
            ? 'Succeeded'
            : 'Failed';

      return {
        id: event.id,
        eventName: event.name ?? 'kangur_ai_tutor_message_sent',
        ts: event.ts,
        path: event.path,
        surface,
        promptMode,
        focusKind,
        focusLabel,
        latestUserMessage,
        draft: createKnowledgeGraphPreviewDraftFromReplayCandidate({
          eventId: event.id,
          latestUserMessage,
          surface,
          contentId,
          title,
          description,
          promptMode,
          interactionIntent,
          focusKind,
          focusId,
          focusLabel,
          questionId,
          assignmentId,
          answerRevealed:
            answerRevealed === null ? '' : answerRevealed ? 'true' : 'false',
          selectedText,
        }),
        option: {
          value: event.id,
          label: `${eventLabel} • ${displaySurface} • ${displayPromptMode} • ${displayTarget}`,
          group: 'Recent AI Tutor messages',
        },
      };
    })
    .filter((candidate) => candidate.latestUserMessage.length > 0);

'use client';

import { useCallback, useMemo, useState } from 'react';
import { useLocale } from 'next-intl';
import { useUpdateSetting } from '@/shared/hooks/use-settings';
import { useToast } from '@/features/kangur/shared/ui';
import type { ThemeSettings } from '@/shared/contracts/cms-theme';
import {
  KANGUR_DAILY_THEME_SETTINGS_KEY,
  KANGUR_DAWN_THEME_SETTINGS_KEY,
  KANGUR_NIGHTLY_THEME_SETTINGS_KEY,
  KANGUR_SUNSET_THEME_SETTINGS_KEY,
  type KangurThemeMode,
} from '@/features/kangur/appearance/theme-settings';
import {
  getKangurThemePanelCopy,
  resolveKangurThemeSettingsLocale,
} from '../kangur-theme-settings.copy';
import { serializeSetting } from '@/features/kangur/shared/utils/settings-json';
import { withKangurClientError } from '@/features/kangur/observability/client';
import { stableStringify } from '@/shared/utils/stable-stringify';

export function useKangurThemeSettingsState(
  initialDaily: ThemeSettings,
  initialNightly: ThemeSettings,
  initialDawn: ThemeSettings,
  initialSunset: ThemeSettings
) {
  const locale = useLocale();
  const normalizedLocale = resolveKangurThemeSettingsLocale(locale);
  const copy = getKangurThemePanelCopy(normalizedLocale);
  const { toast } = useToast();
  const updateSetting = useUpdateSetting();

  const [mode, setMode] = useState<KangurThemeMode>('daily');
  const [drafts, setDrafts] = useState<Record<KangurThemeMode, ThemeSettings>>({
    daily: initialDaily,
    nightly: initialNightly,
    dawn: initialDawn,
    sunset: initialSunset,
  });
  const [isSaving, setIsSaving] = useState(false);

  const currentDraft = drafts[mode];
  const initialThemes = useMemo(() => ({
    daily: initialDaily,
    nightly: initialNightly,
    dawn: initialDawn,
    sunset: initialSunset,
  }), [initialDaily, initialNightly, initialDawn, initialSunset]);

  const hasUnsavedChanges = useMemo(
    () => stableStringify(drafts[mode]) !== stableStringify(initialThemes[mode]),
    [drafts, initialThemes, mode]
  );

  const updateDraft = useCallback((next: ThemeSettings) => {
    setDrafts((prev) => ({ ...prev, [mode]: next }));
  }, [mode]);

  const saveTheme = useCallback(async () => {
    setIsSaving(true);
    const settingKey =
      mode === 'daily'
        ? KANGUR_DAILY_THEME_SETTINGS_KEY
        : mode === 'nightly'
          ? KANGUR_NIGHTLY_THEME_SETTINGS_KEY
          : mode === 'dawn'
            ? KANGUR_DAWN_THEME_SETTINGS_KEY
            : KANGUR_SUNSET_THEME_SETTINGS_KEY;

    try {
      await withKangurClientError(
        {
          source: 'admin.theme-settings',
          action: 'save-theme',
          description: `Saving ${mode} theme settings.`,
        },
        async () => await updateSetting.mutateAsync({
          key: settingKey,
          value: serializeSetting(drafts[mode]),
        })
      );
      toast(copy.saveSuccess, { variant: 'success' });
    } catch (err) {
      toast(copy.saveError, { variant: 'error', error: err });
    } finally {
      setIsSaving(false);
    }
  }, [copy.saveError, copy.saveSuccess, drafts, mode, toast, updateSetting]);

  const resetTheme = useCallback(() => {
    setDrafts((prev) => ({ ...prev, [mode]: initialThemes[mode] }));
  }, [initialThemes, mode]);

  return {
    copy,
    locale: normalizedLocale,
    mode,
    setMode,
    currentDraft,
    updateDraft,
    isSaving,
    saveTheme,
    resetTheme,
    hasUnsavedChanges,
    drafts,
  };
}

