import { useMemo, useState } from 'react';
import type { KangurLesson, KangurLessonAgeGroup } from '@/features/kangur/shared/contracts/kangur';
import type { KangurLessonAuthoringFilter } from '../../types';
import { matchesKangurLessonAuthoringFilter, getKangurLessonAuthoringFilterCounts } from '../../content-creator-insights';
import { KANGUR_AGE_GROUPS } from '@/features/kangur/lessons/lesson-catalog-metadata';

export function useLessonsManagerFiltering(lessons: KangurLesson[], lessonDocuments: Record<string, any>) {
  const [authoringFilter, setAuthoringFilter] = useState<KangurLessonAuthoringFilter>('all');
  const [ageGroupFilter, setAgeGroupFilter] = useState<'all' | KangurLessonAgeGroup>('all');

  const authoringFilteredLessons = useMemo(
    () => lessons.filter((lesson) => matchesKangurLessonAuthoringFilter(authoringFilter, lesson, lessonDocuments)),
    [authoringFilter, lessonDocuments, lessons]
  );

  const filteredLessons = useMemo(
    () => authoringFilteredLessons.filter((lesson) => ageGroupFilter === 'all' ? true : lesson.ageGroup === ageGroupFilter),
    [ageGroupFilter, authoringFilteredLessons]
  );

  const authoringFilterCounts = useMemo(() => getKangurLessonAuthoringFilterCounts(lessons, lessonDocuments), [lessonDocuments, lessons]);

  const ageGroupCounts = useMemo(
    () => new Map(KANGUR_AGE_GROUPS.map((group) => [group.id, authoringFilteredLessons.filter((lesson) => lesson.ageGroup === group.id).length])),
    [authoringFilteredLessons]
  );

  const activeAgeGroupLabel = ageGroupFilter === 'all' ? 'All ages' : KANGUR_AGE_GROUPS.find((group) => group.id === ageGroupFilter)?.label ?? ageGroupFilter;

  return {
    authoringFilter, setAuthoringFilter,
    ageGroupFilter, setAgeGroupFilter,
    authoringFilteredLessons,
    filteredLessons,
    authoringFilterCounts,
    ageGroupCounts,
    activeAgeGroupLabel
  };
}

import { useCallback } from 'react';
import type { KangurLesson, KangurLessonTemplate } from '@/features/kangur/shared/contracts/kangur';
import type { KangurLessonTemplateComponentContent } from '@/shared/contracts/kangur-lesson-templates';
import { useToast } from '@/features/kangur/shared/ui';
import { withKangurClientError } from '@/features/kangur/observability/client';
import { buildLessonsManagerErrorReport } from '../../AdminKangurLessonsManagerPage.shared';
import { 
  upsertLesson, 
  sanitizeSvgMarkup, 
  toLocalizedLessonFormData, 
  resolveLessonComponentContentJson,
  createInitialLessonFormData,
} from '../../utils';
import { 
  createStarterKangurLessonDocument, 
  removeKangurLessonDocument, 
  resolveKangurLessonDocumentPages, 
  updateKangurLessonDocumentPages, 
  updateKangurLessonDocumentTimestamp, 
  createDefaultKangurLessonDocument, 
  createKangurLessonSvgBlock, 
  hasKangurLessonDocumentContent 
} from '../../../lesson-documents';
import { 
  createKangurLessonId,
  KANGUR_LESSON_SORT_ORDER_GAP, 
  parseKangurLessonTemplateComponentContentJson, 
  canonicalizeKangurLessons, 
  appendMissingKangurLessonsByComponent, 
  KANGUR_LESSON_COMPONENT_OPTIONS, 
  appendMissingGeometryKangurLessons, 
  appendMissingLogicalThinkingKangurLessons 
} from '../../../settings';
import { importLegacyKangurLessonDocument } from '../../../lessons/import-legacy';
import { clearLessonContentEditorDraft } from '../../lesson-content-editor-drafts';
import type { LessonFormData } from '../../types';
import type { UseLessonsUiStateReturn } from './useLessonsUiState';
import type { UseMutationResult } from '@tanstack/react-query';

export function useLessonsManagerHandlers(params: {
  lessons: KangurLesson[];
  lessonDocuments: Record<string, any>;
  lessonById: Map<string, KangurLesson>;
  lessonTemplateMap: Map<string, KangurLessonTemplate>;
  templatesQueryData: KangurLessonTemplate[] | undefined;
  updateLessons: UseMutationResult<any, any, any>;
  updateLessonDocuments: UseMutationResult<any, any, any>;
  updateTemplates: UseMutationResult<any, any, any>;
  ui: UseLessonsUiStateReturn;
  isPrimaryContentLocale: boolean;
  showComponentContentEditor: boolean;
}) {
  const { toast } = useToast();
  const { 
    lessons, lessonDocuments, lessonById, lessonTemplateMap, templatesQueryData, 
    updateLessons, updateLessonDocuments, updateTemplates, ui, isPrimaryContentLocale, showComponentContentEditor 
  } = params;

  const handleCloseModal = (): void => {
    ui.setShowModal(false);
    ui.setEditingLesson(null);
    ui.setFormData(createInitialLessonFormData());
    ui.setComponentContentJson('');
  };

  const handleCreate = (): void => {
    ui.setFormData(createInitialLessonFormData());
    ui.setComponentContentJson('');
    ui.setEditingLesson(null);
    ui.setShowModal(true);
  };

  const handleEdit = useCallback(
    (lesson: KangurLesson): void => {
      const template = lessonTemplateMap.get(lesson.componentId);
      ui.setFormData(toLocalizedLessonFormData(lesson, template));
      ui.setComponentContentJson(resolveLessonComponentContentJson(lesson.componentId, template));
      ui.setEditingLesson(lesson);
      ui.setShowModal(true);
    },
    [lessonTemplateMap, ui]
  );

  const handleEditContent = useCallback(
    (lesson: KangurLesson): void => {
      const document = lessonDocuments[lesson.id];
      ui.setContentDraft(document ?? createStarterKangurLessonDocument(lesson.componentId));
      ui.setEditingContentLesson(lesson);
      ui.setShowContentModal(true);
    },
    [lessonDocuments, ui]
  );

  const openLessonContentEditor = useCallback(
    (lesson: KangurLesson, document?: any): void => {
      ui.setContentDraft(document ?? lessonDocuments[lesson.id] ?? createStarterKangurLessonDocument(lesson.componentId));
      ui.setEditingContentLesson(lesson);
      ui.setShowContentModal(true);
    },
    [lessonDocuments, ui]
  );

  const handleComponentChange = useCallback(
    (componentId: string): void => {
      const nextComponentId = componentId as LessonFormData['componentId'];
      ui.setFormData((current: LessonFormData) => ({ ...current, componentId: nextComponentId }));
      ui.setComponentContentJson(resolveLessonComponentContentJson(nextComponentId, lessonTemplateMap.get(nextComponentId)));
    },
    [lessonTemplateMap, ui]
  );

  const buildPersistedLessonRecord = useCallback(
    (lessonId: string, source: LessonFormData | KangurLesson, sortOrder: number): KangurLesson => {
      const existingLesson = lessonById.get(lessonId);
      const useExisting = !isPrimaryContentLocale && Boolean(existingLesson);

      const pick = <K extends keyof KangurLesson>(key: K): KangurLesson[K] => 
        (useExisting && existingLesson[key] !== undefined) ? existingLesson[key] : (source as any)[key];

      return {
        id: lessonId,
        componentId: source.componentId,
        contentMode: source.contentMode,
        subject: source.subject,
        ageGroup: source.ageGroup,
        title: pick('title'),
        description: pick('description'),
        emoji: pick('emoji'),
        color: pick('color'),
        activeBg: pick('activeBg'),
        sortOrder,
        enabled: source.enabled,
        sectionId: existingLesson?.sectionId,
        subsectionId: existingLesson?.subsectionId,
      };
    },
    [isPrimaryContentLocale, lessonById]
  );

  const saveLocalizedLessonTemplate = useCallback(
    async (source: LessonFormData | KangurLesson, componentContent?: KangurLessonTemplateComponentContent): Promise<void> => {
      const existingTemplate = lessonTemplateMap.get(source.componentId);
      const nextTemplate: KangurLessonTemplate = {
        componentId: source.componentId,
        subject: source.subject,
        ageGroup: source.ageGroup,
        label: existingTemplate?.label ?? source.title,
        title: source.title,
        description: source.description,
        emoji: source.emoji,
        color: source.color,
        activeBg: source.activeBg,
        sortOrder: existingTemplate?.sortOrder ?? 0,
        componentContent: componentContent === undefined ? existingTemplate?.componentContent : componentContent,
      };
      const nextTemplates = [...(templatesQueryData ?? [])]
        .filter((template) => template.componentId !== source.componentId)
        .concat(nextTemplate)
        .sort((left, right) =>
          left.sortOrder === right.sortOrder
            ? left.componentId.localeCompare(right.componentId)
            : left.sortOrder - right.sortOrder
        );
      await updateTemplates.mutateAsync(nextTemplates);
    },
    [lessonTemplateMap, templatesQueryData, updateTemplates]
  );

  const handleSave = async (): Promise<void> => {
    await withKangurClientError(
      buildLessonsManagerErrorReport('lesson-save', 'Saves lesson metadata.', {
        lessonId: ui.editingLesson?.id,
        componentId: ui.formData.componentId,
      }),
      async () => {
        const lessonId = ui.editingLesson?.id ?? createKangurLessonId(ui.formData.componentId);
        const sortOrder = ui.editingLesson?.sortOrder ?? (lessons.length > 0 ? Math.max(...lessons.map((l) => l.sortOrder)) + KANGUR_LESSON_SORT_ORDER_GAP : 0);
        const nextLesson = buildPersistedLessonRecord(lessonId, ui.formData, sortOrder);
        const nextLessons = upsertLesson(lessons, nextLesson);
        const shouldOpenContentEditor = ui.formData.contentMode === 'document' && ui.editingLesson?.contentMode !== 'document';
        await updateLessons.mutateAsync(nextLessons);

        const componentContent = showComponentContentEditor ? parseKangurLessonTemplateComponentContentJson(ui.formData.componentId, ui.componentContentJson) : undefined;
        await saveLocalizedLessonTemplate(ui.formData, componentContent);

        toast('Lesson saved', { variant: 'success' });
        handleCloseModal();
        if (shouldOpenContentEditor) {
          openLessonContentEditor(nextLesson, lessonDocuments[lessonId] ?? createStarterKangurLessonDocument(nextLesson.componentId));
        }
      }
    );
  };

  const handleDelete = async (): Promise<void> => {
    if (!ui.lessonToDelete) return;
    await withKangurClientError(
      buildLessonsManagerErrorReport('lesson-delete', 'Deletes a lesson and its content document.', { lessonId: ui.lessonToDelete.id }),
      async () => {
        const nextLessons = lessons.filter((lesson) => lesson.id !== ui.lessonToDelete.id);
        await updateLessons.mutateAsync(nextLessons);
        const nextDocuments = removeKangurLessonDocument(lessonDocuments, ui.lessonToDelete.id);
        await updateLessonDocuments.mutateAsync(nextDocuments);
        toast('Lesson deleted', { variant: 'success' });
        ui.setLessonToDelete(null);
      }
    );
  };

  const handleSaveContent = async (): Promise<void> => {
    if (!ui.editingContentLesson) return;
    await withKangurClientError(
      buildLessonsManagerErrorReport('lesson-content-save', 'Saves the lesson document editor content.', { lessonId: ui.editingContentLesson.id }),
      async () => {
        const pages = resolveKangurLessonDocumentPages(ui.contentDraft);
        const nextDocument = updateKangurLessonDocumentPages(ui.contentDraft, pages);
        const nextLesson = buildPersistedLessonRecord(ui.editingContentLesson.id, ui.editingContentLesson, ui.editingContentLesson.sortOrder);
        const baseLessons = lessonById.has(ui.editingContentLesson.id) ? lessons : upsertLesson(lessons, ui.editingContentLesson);
        const nextLessons = upsertLesson(baseLessons, nextLesson);
        await updateLessons.mutateAsync(nextLessons);
        await saveLocalizedLessonTemplate(nextLesson);
        await updateLessonDocuments.mutateAsync({ ...lessonDocuments, [ui.editingContentLesson.id]: nextDocument });
        clearLessonContentEditorDraft(ui.editingContentLesson.id);
        toast('Content saved', { variant: 'success' });
        ui.setShowContentModal(false);
        ui.setEditingContentLesson(null);
      }
    );
  };

  const handleClearContent = async (): Promise<void> => {
    if (!ui.editingContentLesson) return;
    await withKangurClientError(
      buildLessonsManagerErrorReport('lesson-content-clear', 'Clears the lesson document and restores component mode.', { lessonId: ui.editingContentLesson.id }),
      async () => {
        const nextLesson = buildPersistedLessonRecord(ui.editingContentLesson.id, { ...ui.editingContentLesson, contentMode: 'component' }, ui.editingContentLesson.sortOrder);
        const nextLessons = upsertLesson(lessons, nextLesson);
        const nextDocuments = removeKangurLessonDocument(lessonDocuments, ui.editingContentLesson.id);
        await updateLessons.mutateAsync(nextLessons);
        await updateLessonDocuments.mutateAsync(nextDocuments);
        clearLessonContentEditorDraft(ui.editingContentLesson.id);
        ui.setContentDraft(createDefaultKangurLessonDocument());
        toast('Content cleared', { variant: 'success' });
        ui.setShowContentModal(false);
        ui.setEditingContentLesson(null);
      }
    );
  };

  const handleCanonicalize = async (): Promise<void> => {
    await withKangurClientError(
      buildLessonsManagerErrorReport('lessons-canonicalize', 'Canonicalizes lesson ordering and identifiers.'),
      async () => {
        const nextLessons = canonicalizeKangurLessons(lessons);
        await updateLessons.mutateAsync(nextLessons);
        toast('Lessons canonicalized', { variant: 'success' });
      }
    );
  };

  const handleImportLegacy = useCallback(
    async (lesson: KangurLesson): Promise<void> => {
      await withKangurClientError(
        buildLessonsManagerErrorReport('lesson-legacy-import', 'Imports legacy lesson content into the editor.', { lessonId: lesson.id, componentId: lesson.componentId }),
        async () => {
          const result = importLegacyKangurLessonDocument(lesson.componentId);
          if (!result) {
            toast('Legacy importer not found', { variant: 'error' });
            return;
          }
          await updateLessonDocuments.mutateAsync({ ...lessonDocuments, [lesson.id]: result.document });
          if (ui.editingContentLesson?.id === lesson.id) {
            ui.setContentDraft(result.document);
          }
          toast('Legacy content imported', { variant: 'success' });
        }
      );
    },
    [lessons, lessonDocuments, ui, toast, updateLessonDocuments]
  );

  const handleSaveQuickSvg = async (markup: string): Promise<void> => {
    if (!ui.svgModalLesson) return;
    await withKangurClientError(
      buildLessonsManagerErrorReport('lesson-quick-svg-save', 'Adds a quick SVG block to the lesson document.', { lessonId: ui.svgModalLesson.id }),
      async () => {
        const block = { ...createKangurLessonSvgBlock(), markup: sanitizeSvgMarkup(markup) };
        const document = lessonDocuments[ui.svgModalLesson.id] ?? createDefaultKangurLessonDocument();
        const pages = resolveKangurLessonDocumentPages(document);
        const firstPage = pages[0] ?? { id: 'p1', sectionKey: '', title: '', description: '', blocks: [] };
        const nextPages = [{ ...firstPage, blocks: [...firstPage.blocks, block] }, ...pages.slice(1)];
        const nextDocument = updateKangurLessonDocumentTimestamp(updateKangurLessonDocumentPages(document, nextPages));
        await updateLessonDocuments.mutateAsync({ ...lessonDocuments, [ui.svgModalLesson.id]: nextDocument });
        toast('SVG added to lesson', { variant: 'success' });
        ui.setSvgModalLesson(null);
        ui.setSvgModalInitialMarkup('');
      }
    );
  };

  const handleAppendMissing = async (): Promise<void> => {
    await withKangurClientError(
      buildLessonsManagerErrorReport('lessons-append-missing', 'Adds missing lessons for the known component catalog.'),
      async () => {
        const result = appendMissingKangurLessonsByComponent(lessons, KANGUR_LESSON_COMPONENT_OPTIONS.map((o) => o.value));
        await updateLessons.mutateAsync(result.lessons);
        toast(`Added ${result.addedCount} missing lessons`, { variant: 'success' });
      }
    );
  };

  const handleAddGeometryPack = async (): Promise<void> => {
    await withKangurClientError(
      buildLessonsManagerErrorReport('lessons-append-geometry', 'Adds missing geometry lessons from the Kangur lesson catalog.'),
      async () => {
        const result = appendMissingGeometryKangurLessons(lessons);
        await updateLessons.mutateAsync(result.lessons);
        toast(`Added ${result.addedCount} geometry lessons`, { variant: 'success' });
      }
    );
  };

  const handleAddLogicalThinkingPack = async (): Promise<void> => {
    await withKangurClientError(
      buildLessonsManagerErrorReport('lessons-append-logical-thinking', 'Adds missing logical thinking lessons from the Kangur lesson catalog.'),
      async () => {
        const result = appendMissingLogicalThinkingKangurLessons(lessons);
        await updateLessons.mutateAsync(result.lessons);
        toast(`Added ${result.addedCount} logical thinking lessons`, { variant: 'success' });
      }
    );
  };

  const handleImportAllLessonsToEditor = async (): Promise<void> => {
    await withKangurClientError(
      buildLessonsManagerErrorReport('lessons-import-all', 'Imports all eligible lessons into modular editor drafts.'),
      async () => {
        const nextDocuments = { ...lessonDocuments };
        const importedLessonIds = new Set<string>();

        lessons.forEach((lesson) => {
          const needsImport = lesson.contentMode !== 'document' && !hasKangurLessonDocumentContent(lessonDocuments[lesson.id]);
          if (!needsImport) return;
          const result = importLegacyKangurLessonDocument(lesson.componentId);
          if (!result) return;
          nextDocuments[lesson.id] = result.document;
          importedLessonIds.add(lesson.id);
        });

        if (importedLessonIds.size === 0) {
          toast('No lessons need importing right now.', { variant: 'info' });
          return;
        }

        const nextLessons = lessons.map((lesson) => importedLessonIds.has(lesson.id) ? { ...lesson, contentMode: 'document' as const } : lesson);
        await updateLessonDocuments.mutateAsync(nextDocuments);
        await updateLessons.mutateAsync(nextLessons);
        toast(`Imported ${importedLessonIds.size} lessons to modular editor.`, { variant: 'success' });
      }
    );
  };

  return {
    handleCloseModal, handleCreate, handleEdit, handleEditContent, openLessonContentEditor,
    handleComponentChange, handleSave, handleDelete, handleSaveContent, handleClearContent,
    handleCanonicalize, handleImportLegacy, handleSaveQuickSvg,
    handleAppendMissing, handleAddGeometryPack, handleAddLogicalThinkingPack, handleImportAllLessonsToEditor
  };
}

import { useMemo } from 'react';
import {
  useKangurLessonDocuments,
  useKangurLessonTemplates,
  useKangurLessons,
  useUpdateKangurLessonDocuments,
  useUpdateKangurLessonTemplates,
  useUpdateKangurLessons,
} from '@/features/kangur/hooks';
import type { KangurLesson, KangurLessonTemplate } from '@/features/kangur/shared/contracts/kangur';

export type UseLessonsStateReturn = ReturnType<typeof useLessonsState>;

export function useLessonsState(contentLocale: string) {
  const lessonsQuery = useKangurLessons();
  const lessonDocumentsQuery = useKangurLessonDocuments({ locale: contentLocale });
  const templatesQuery = useKangurLessonTemplates({ locale: contentLocale });
  const updateLessons = useUpdateKangurLessons();
  const updateLessonDocuments = useUpdateKangurLessonDocuments(contentLocale);
  const updateTemplates = useUpdateKangurLessonTemplates(contentLocale);

  const isLoading = lessonsQuery.isLoading || lessonDocumentsQuery.isLoading || templatesQuery.isLoading;

  const lessonTemplateMap = useMemo(
    () => new Map((templatesQuery.data ?? []).map((t) => [t.componentId, t])),
    [templatesQuery.data],
  );

  const lessons = useMemo((): KangurLesson[] => lessonsQuery.data ?? [], [lessonsQuery.data]);
  const lessonDocuments = useMemo(() => lessonDocumentsQuery.data ?? {}, [lessonDocumentsQuery.data]);
  const lessonById = useMemo(() => new Map(lessons.map((lesson): [string, KangurLesson] => [lesson.id, lesson])), [lessons]);

  return {
    lessonsQuery,
    lessonDocumentsQuery,
    templatesQuery,
    updateLessons,
    updateLessonDocuments,
    updateTemplates,
    isLoading,
    lessonTemplateMap,
    lessons,
    lessonDocuments,
    lessonById,
  };
}

import { useState } from 'react';
import type { KangurLesson, KangurLessonAgeGroup } from '@/features/kangur/shared/contracts/kangur';
import type { LessonFormData, LessonTreeMode, KangurLessonAuthoringFilter } from '../../types';
import { createDefaultKangurLessonDocument } from '@/features/kangur/lesson-documents';
import { createInitialLessonFormData, readPersistedTreeMode } from '../../utils';

export type UseLessonsUiStateReturn = ReturnType<typeof useLessonsUiState>;

export function useLessonsUiState() {
  const [showModal, setShowModal] = useState(false);
  const [showContentModal, setShowContentModal] = useState(false);
  const [editingLesson, setEditingLesson] = useState<KangurLesson | null>(null);
  const [editingContentLesson, setEditingContentLesson] = useState<KangurLesson | null>(null);
  const [lessonToDelete, setLessonToDelete] = useState<KangurLesson | null>(null);
  const [formData, setFormData] = useState<LessonFormData>(() => createInitialLessonFormData());
  const [componentContentJson, setComponentContentJson] = useState('');
  const [contentDraft, setContentDraft] = useState(createDefaultKangurLessonDocument);
  const [treeMode, setTreeMode] = useState<LessonTreeMode>(() => readPersistedTreeMode());
  const [svgModalLesson, setSvgModalLesson] = useState<KangurLesson | null>(null);
  const [svgModalInitialMarkup, setSvgModalInitialMarkup] = useState('');
  const [orderedTreeSearchQuery, setOrderedTreeSearchQuery] = useState('');
  const [catalogTreeSearchQuery, setCatalogTreeSearchQuery] = useState('');
  const [authoringFilter, setAuthoringFilter] = useState<KangurLessonAuthoringFilter>('all');
  const [ageGroupFilter, setAgeGroupFilter] = useState<'all' | KangurLessonAgeGroup>('all');

  return {
    showModal, setShowModal,
    showContentModal, setShowContentModal,
    editingLesson, setEditingLesson,
    editingContentLesson, setEditingContentLesson,
    lessonToDelete, setLessonToDelete,
    formData, setFormData,
    componentContentJson, setComponentContentJson,
    contentDraft, setContentDraft,
    treeMode, setTreeMode,
    svgModalLesson, setSvgModalLesson,
    svgModalInitialMarkup, setSvgModalInitialMarkup,
    orderedTreeSearchQuery, setOrderedTreeSearchQuery,
    catalogTreeSearchQuery, setCatalogTreeSearchQuery,
    authoringFilter, setAuthoringFilter,
    ageGroupFilter, setAgeGroupFilter,
  };
}

'use client';

import { useCallback, useRef, useState } from 'react';

import {
  getDragValue,
  resolveVerticalDropPosition,
  setDragData,
} from '@/features/kangur/shared/utils/drag-drop';

const DND_KEY = 'application/x-kangur-block-id';

export type KangurBlockDragState = {
  draggedBlockId: string | null;
  targetBlockId: string | null;
  position: 'before' | 'after' | null;
};

export type BlockDragHandlers = {
  draggable: true;
  onDragStart: (e: React.DragEvent) => void;
  onDragOver: (e: React.DragEvent) => void;
  onDragLeave: (e: React.DragEvent) => void;
  onDrop: (e: React.DragEvent) => void;
  onDragEnd: (e: React.DragEvent) => void;
};

const INITIAL_STATE: KangurBlockDragState = {
  draggedBlockId: null,
  targetBlockId: null,
  position: null,
};

export function useBlockListDnd(options: {
  onReorder: (draggedId: string, targetId: string, position: 'before' | 'after') => void;
}): {
  dragState: KangurBlockDragState;
  getHandlers: (blockId: string) => BlockDragHandlers;
} {
  const { onReorder } = options;
  const [dragState, setDragState] = useState<KangurBlockDragState>(INITIAL_STATE);
  // Ref tracks the dragged ID so onDragOver can read it without capturing stale state.
  // (dataTransfer.getData is blocked by browsers during dragover for security.)
  const draggedIdRef = useRef<string | null>(null);

  const getHandlers = useCallback(
    (blockId: string): BlockDragHandlers => ({
      draggable: true,
      onDragStart: (e: React.DragEvent) => {
        draggedIdRef.current = blockId;
        setDragData(e.dataTransfer, { [DND_KEY]: blockId }, { effectAllowed: 'move' });
        setDragState({ draggedBlockId: blockId, targetBlockId: null, position: null });
      },
      onDragOver: (e: React.DragEvent) => {
        e.preventDefault();
        const draggedId = draggedIdRef.current;
        if (!draggedId || draggedId === blockId) return;
        const rect = e.currentTarget.getBoundingClientRect();
        const position = resolveVerticalDropPosition(e.clientY, rect, { thresholdRatio: 0.4 });
        if (!position) return;
        e.dataTransfer.dropEffect = 'move';
        setDragState((prev) => {
          if (prev.targetBlockId === blockId && prev.position === position) return prev;
          return { draggedBlockId: draggedId, targetBlockId: blockId, position };
        });
      },
      onDragLeave: (e: React.DragEvent) => {
        if (e.currentTarget.contains(e.relatedTarget as Node)) return;
        setDragState((prev) =>
          prev.targetBlockId === blockId
            ? { ...prev, targetBlockId: null, position: null }
            : prev
        );
      },
      onDrop: (e: React.DragEvent) => {
        e.preventDefault();
        const draggedId = getDragValue(e.dataTransfer, DND_KEY);
        if (!draggedId || draggedId === blockId) {
          draggedIdRef.current = null;
          setDragState(INITIAL_STATE);
          return;
        }
        const rect = e.currentTarget.getBoundingClientRect();
        const position = resolveVerticalDropPosition(e.clientY, rect, { thresholdRatio: 0.4 });
        if (position) {
          onReorder(draggedId, blockId, position);
        }
        draggedIdRef.current = null;
        setDragState(INITIAL_STATE);
      },
      onDragEnd: () => {
        draggedIdRef.current = null;
        setDragState(INITIAL_STATE);
      },
    }),
    [onReorder]
  );

  return { dragState, getHandlers };
}

'use client';

import { useCallback } from 'react';

import {
  cloneKangurLessonPage,
  cloneKangurLessonRootBlock,
  createKangurLessonBlockId,
  createKangurLessonDocumentFromTemplate,
  createKangurLessonPage,
  reorderKangurLessonBlocks,
  resolveKangurLessonDocumentPages,
  updateKangurLessonDocumentPages,
  type KangurLessonDocumentTemplateId,
} from '@/features/kangur/lesson-documents';
import type {
  KangurLessonDocument,
  KangurLessonRootBlock,
  KangurLessonPage,
  KangurLessonGridBlock,
} from '@/features/kangur/shared/contracts/kangur';

import { insertAfterIndex, moveItem, resolvePageSectionOptions } from '../utils';

export function useKangurLessonMutations(
  value: KangurLessonDocument,
  onChange: (document: KangurLessonDocument) => void,
  activePage: KangurLessonPage | null,
  pages: KangurLessonPage[],
  activePageIndex: number,
  setActivePageId: (id: string | null) => void
) {
  const applyPages = useCallback(
    (nextPages: KangurLessonPage[]): void => {
      const nextDocument = updateKangurLessonDocumentPages(value, nextPages);
      onChange({
        ...nextDocument,
        updatedAt: new Date().toISOString(),
      });
    },
    [onChange, value]
  );

  const updatePage = useCallback(
    (pageId: string, updater: (page: KangurLessonPage) => KangurLessonPage): void => {
      applyPages(pages.map((page) => (page.id === pageId ? updater(page) : page)));
    },
    [applyPages, pages]
  );

  const updateDocument = useCallback(
    (nextBlocks: KangurLessonRootBlock[]): void => {
      if (!activePage) return;
      updatePage(activePage.id, (page) => ({
        ...page,
        blocks: nextBlocks,
      }));
    },
    [activePage, updatePage]
  );

  const updateRootBlock = useCallback(
    (blockId: string, nextBlock: KangurLessonRootBlock): void => {
      if (!activePage) return;
      updateDocument(activePage.blocks.map((block) => (block.id === blockId ? nextBlock : block)));
    },
    [activePage, updateDocument]
  );

  const removeRootBlock = useCallback(
    (blockId: string): void => {
      if (!activePage) return;
      updateDocument(activePage.blocks.filter((block) => block.id !== blockId));
    },
    [activePage, updateDocument]
  );

  const moveRootBlock = useCallback(
    (fromIndex: number, toIndex: number): void => {
      if (!activePage) return;
      updateDocument(moveItem(activePage.blocks, fromIndex, toIndex));
    },
    [activePage, updateDocument]
  );

  const handleBlockReorder = useCallback(
    (draggedId: string, targetId: string, position: 'before' | 'after'): void => {
      if (!activePage) return;
      updateDocument(reorderKangurLessonBlocks(activePage.blocks, draggedId, targetId, position));
    },
    [activePage, updateDocument]
  );

  const duplicateRootBlock = useCallback(
    (index: number): void => {
      if (!activePage) return;
      const blockToClone = activePage.blocks[index];
      if (!blockToClone) return;
      updateDocument(
        insertAfterIndex(activePage.blocks, index, cloneKangurLessonRootBlock(blockToClone))
      );
    },
    [activePage, updateDocument]
  );

  const updateGridBlock = useCallback(
    (blockId: string, updater: (block: KangurLessonGridBlock) => KangurLessonGridBlock): void => {
      if (!activePage) return;
      updateDocument(
        activePage.blocks.map((block) => {
          if (block.id !== blockId || block.type !== 'grid') return block;
          return updater(block);
        })
      );
    },
    [activePage, updateDocument]
  );

  const duplicateGridItem = useCallback(
    (blockId: string, itemIndex: number): void => {
      updateGridBlock(blockId, (block) => {
        const itemToClone = block.items[itemIndex];
        if (!itemToClone) return block;
        return {
          ...block,
          items: insertAfterIndex(block.items, itemIndex, {
            ...itemToClone,
            id: createKangurLessonBlockId('lesson-grid-item'),
            block: cloneKangurLessonRootBlock(itemToClone.block) as any,
          }),
        };
      });
    },
    [updateGridBlock]
  );

  const moveGridItem = useCallback(
    (blockId: string, fromIndex: number, toIndex: number): void => {
      updateGridBlock(blockId, (block) => ({
        ...block,
        items: reorderKangurLessonBlocks(block.items as any, block.items[fromIndex]!.id, block.items[toIndex]!.id, fromIndex < toIndex ? 'after' : 'before') as any,
      }));
    },
    [updateGridBlock]
  );

  const removeGridItem = useCallback(
    (blockId: string, itemId: string): void => {
      updateGridBlock(blockId, (block) => ({
        ...block,
        items: block.items.filter((item) => item.id !== itemId),
      }));
    },
    [updateGridBlock]
  );

  const replaceWithDocumentTemplate = useCallback(
    (templateId: KangurLessonDocumentTemplateId): void => {
      const nextDocument = createKangurLessonDocumentFromTemplate(templateId);
      onChange({
        ...nextDocument,
        updatedAt: new Date().toISOString(),
      });
      setActivePageId(resolveKangurLessonDocumentPages(nextDocument)[0]?.id ?? null);
    },
    [onChange, setActivePageId]
  );

  const insertPageAfterActive = useCallback(
    (nextPage: KangurLessonPage): void => {
      if (activePageIndex >= 0) {
        applyPages(insertAfterIndex(pages, activePageIndex, nextPage));
      } else {
        applyPages([...pages, nextPage]);
      }
      setActivePageId(nextPage.id);
    },
    [activePageIndex, applyPages, pages, setActivePageId]
  );

  const addBlankPage = useCallback((): void => {
    const nextPage = createKangurLessonPage('', [], resolvePageSectionOptions(activePage));
    insertPageAfterActive(nextPage);
  }, [activePage, insertPageAfterActive]);

  const addPageFromTemplate = useCallback(
    (templateId: KangurLessonDocumentTemplateId): void => {
      const templatePage =
        resolveKangurLessonDocumentPages(createKangurLessonDocumentFromTemplate(templateId))[0] ??
        createKangurLessonPage('', []);
      const nextPage = {
        ...cloneKangurLessonPage(templatePage),
        ...resolvePageSectionOptions(activePage),
      };
      insertPageAfterActive(nextPage);
    },
    [activePage, insertPageAfterActive]
  );

  const duplicateActivePage = useCallback((): void => {
    if (activePageIndex < 0 || !activePage) return;
    const nextPage = cloneKangurLessonPage(activePage);
    applyPages(insertAfterIndex(pages, activePageIndex, nextPage));
    setActivePageId(nextPage.id);
  }, [activePage, activePageIndex, applyPages, pages, setActivePageId]);

  const moveActivePage = useCallback(
    (toIndex: number): void => {
      if (activePageIndex < 0 || !activePage) return;
      applyPages(moveItem(pages, activePageIndex, toIndex));
      setActivePageId(activePage.id);
    },
    [activePage, activePageIndex, applyPages, pages, setActivePageId]
  );

  const deleteActivePage = useCallback((): void => {
    if (!activePage || pages.length <= 1) return;
    const nextPages = pages.filter((page) => page.id !== activePage.id);
    applyPages(nextPages);
    setActivePageId(nextPages[Math.max(0, activePageIndex - 1)]?.id ?? nextPages[0]?.id ?? null);
  }, [activePage, activePageIndex, applyPages, pages, setActivePageId]);

  return {
    applyPages,
    updatePage,
    updateDocument,
    updateRootBlock,
    removeRootBlock,
    moveRootBlock,
    handleBlockReorder,
    duplicateRootBlock,
    updateGridBlock,
    duplicateGridItem,
    moveGridItem,
    removeGridItem,
    replaceWithDocumentTemplate,
    insertPageAfterActive,
    addBlankPage,
    addPageFromTemplate,
    duplicateActivePage,
    moveActivePage,
    deleteActivePage,
  };
}

