'use client';

import { useCallback, useEffect, useMemo, useState } from 'react';

import { DEFAULT_KANGUR_PAGE_CONTENT_STORE } from '@/features/kangur/ai-tutor/page-content-catalog';
import {
  parseKangurPageContentStore,
  type KangurPageContentEntry,
  type KangurPageContentFragment,
  type KangurPageContentStore,
} from '@/features/kangur/shared/contracts/kangur-page-content';
import { api } from '@/shared/lib/api-client';
import { useToast } from '@/features/kangur/shared/ui';
import {
  withKangurClientError,
  withKangurClientErrorSync,
} from '@/features/kangur/observability/client';
const AI_TUTOR_PAGE_CONTENT_EDITOR_LOCALE = 'pl';
const EMPTY_PAGE_CONTENT_EDITOR_VALUE = '';
const EMPTY_KANGUR_PAGE_CONTENT_STORE = parseKangurPageContentStore({
  locale: AI_TUTOR_PAGE_CONTENT_EDITOR_LOCALE,
  version: DEFAULT_KANGUR_PAGE_CONTENT_STORE.version,
  entries: [],
});

const stringifyPageContentStore = (store: KangurPageContentStore): string =>
  `${JSON.stringify(store, null, 2)}
`;

const normalizeEntries = (entries: KangurPageContentEntry[]): KangurPageContentEntry[] =>
  entries.map((entry, index) => ({
    ...entry,
    sortOrder: (index + 1) * 10,
  }));

const normalizeFragments = (
  fragments: KangurPageContentFragment[]
): KangurPageContentFragment[] =>
  fragments.map((fragment, index) => ({
    ...fragment,
    sortOrder: (index + 1) * 10,
  }));

const createEntryId = (): string =>
  `page-content-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

const createFragmentId = (): string =>
  `fragment-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

const createEmptyEntry = (sortOrder: number): KangurPageContentEntry => ({
  id: createEntryId(),
  pageKey: 'Game',
  screenKey: 'custom',
  surface: 'game',
  route: '/game',
  componentId: 'custom-section',
  widget: 'CustomWidget',
  sourcePath: 'src/features/kangur/ui/pages/Game.tsx',
  title: 'Nowa sekcja',
  summary: 'Krótki opis nowej sekcji Kangur.',
  body: 'Pełny opis nowej sekcji Kangur do uzupełnienia przez administratora.',
  anchorIdPrefix: null,
  focusKind: 'screen',
  contentIdPrefixes: [],
  nativeGuideIds: [],
  triggerPhrases: [],
  fragments: [],
  tags: ['page-content'],
  notes: undefined,
  enabled: true,
  sortOrder,
});

const createEmptyFragment = (sortOrder: number): KangurPageContentFragment => ({
  id: createFragmentId(),
  text: 'Nowy fragment',
  aliases: [],
  explanation: 'Wyjaśnienie wybranego fragmentu dla AI Tutora.',
  nativeGuideIds: [],
  triggerPhrases: [],
  enabled: true,
  sortOrder,
});

type ParsedEditorState = {
  store: KangurPageContentStore | null;
  error: string | null;
};

export function useKangurPageContentMutations() {
  const { toast } = useToast();
  const [editorValue, setEditorValue] = useState(() => EMPTY_PAGE_CONTENT_EDITOR_VALUE);
  const [persistedEditorValue, setPersistedEditorValue] = useState(
    () => EMPTY_PAGE_CONTENT_EDITOR_VALUE
  );
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [selectedEntryId, setSelectedEntryId] = useState<string | null>(null);
  const [selectedFragmentId, setSelectedFragmentId] = useState<string | null>(null);

  const isDirty = editorValue !== persistedEditorValue;

  const parsedState = useMemo<ParsedEditorState>(() => {
    if (editorValue.trim().length === 0) {
      return {
        store: null,
        error: null,
      };
    }

    return withKangurClientErrorSync(
      {
        source: 'kangur.admin.page-content',
        action: 'parse-editor-json',
        description: 'Parses the admin page content editor JSON payload.',
      },
      () => ({
        store: parseKangurPageContentStore(JSON.parse(editorValue)),
        error: null,
      }),
      {
        fallback: {
          store: null,
          error: 'Invalid page-content JSON.',
        } as ParsedEditorState,
      }
    );
  }, [editorValue]);

  const selectedEntry = useMemo(
    () => parsedState.store?.entries.find((entry) => entry.id === selectedEntryId) ?? null,
    [parsedState.store, selectedEntryId]
  );

  const selectedFragment = useMemo(
    () => selectedEntry?.fragments.find((fragment) => fragment.id === selectedFragmentId) ?? null,
    [selectedEntry, selectedFragmentId]
  );

  const loadStore = useCallback(async (): Promise<void> => {
    setIsLoading(true);
    const didLoad = await withKangurClientError(
      {
        source: 'kangur.admin.page-content',
        action: 'load-store',
        description: 'Loads the Kangur page content store for the admin editor.',
        context: { locale: AI_TUTOR_PAGE_CONTENT_EDITOR_LOCALE },
      },
      async () => {
        const store = await api.get<KangurPageContentStore>(
          `/api/kangur/ai-tutor/page-content?locale=${encodeURIComponent(
            AI_TUTOR_PAGE_CONTENT_EDITOR_LOCALE
          )}`,
          {
            cache: 'no-store',
          }
        );
        const parsed = parseKangurPageContentStore(store);
        const serialized = stringifyPageContentStore(parsed);
        setEditorValue(serialized);
        setPersistedEditorValue(serialized);
        setSelectedEntryId(parsed.entries[0]?.id ?? null);
        return true;
      },
      {
        fallback: false,
        onError: (error) => {
          toast(
            error instanceof Error ? error.message : 'Failed to load Kangur page content.',
            {
              variant: 'error',
            }
          );
        },
      }
    );
    if (!didLoad) {
      // keep existing editor state
    }
    setIsLoading(false);
  }, [toast]);

  useEffect(() => {
    void loadStore();
  }, [loadStore]);

  const applyStore = useCallback((nextStore: KangurPageContentStore): void => {
    setEditorValue(stringifyPageContentStore(parseKangurPageContentStore(nextStore)));
  }, []);

  const updateSelectedEntry = useCallback((
    updater: (entry: KangurPageContentEntry) => KangurPageContentEntry
  ): void => {
    if (!parsedState.store || !selectedEntry) {
      return;
    }

    const nextEntry = updater(selectedEntry);
    applyStore({
      ...parsedState.store,
      entries: parsedState.store.entries.map((entry) =>
        entry.id === selectedEntry.id ? nextEntry : entry
      ),
    });
    setSelectedEntryId(nextEntry.id);
  }, [applyStore, parsedState.store, selectedEntry]);

  const handleAddEntry = useCallback((): void => {
    const baseStore = parsedState.store ?? EMPTY_KANGUR_PAGE_CONTENT_STORE;
    const nextEntries = normalizeEntries([
      ...baseStore.entries,
      createEmptyEntry((baseStore.entries.length + 1) * 10),
    ]);
    const nextEntry = nextEntries[nextEntries.length - 1] ?? null;

    applyStore({
      ...baseStore,
      entries: nextEntries,
    });
    setSelectedEntryId(nextEntry?.id ?? null);
  }, [applyStore, parsedState.store]);

  const handleDuplicateSelectedEntry = useCallback((): void => {
    if (!parsedState.store || !selectedEntry) {
      return;
    }

    const duplicate: KangurPageContentEntry = {
      ...selectedEntry,
      id: createEntryId(),
      title: `${selectedEntry.title} kopia`,
      sortOrder: selectedEntry.sortOrder + 1,
    };
    const currentIndex = parsedState.store.entries.findIndex((entry) => entry.id === selectedEntry.id);
    const nextEntries = [...parsedState.store.entries];
    nextEntries.splice(currentIndex + 1, 0, duplicate);
    const normalizedEntries = normalizeEntries(nextEntries);

    applyStore({
      ...parsedState.store,
      entries: normalizedEntries,
    });
    setSelectedEntryId(duplicate.id);
  }, [applyStore, parsedState.store, selectedEntry]);

  const handleDeleteSelectedEntry = useCallback((): void => {
    if (!parsedState.store || !selectedEntry) {
      return;
    }

    const nextEntries = normalizeEntries(
      parsedState.store.entries.filter((entry) => entry.id !== selectedEntry.id)
    );
    applyStore({
      ...parsedState.store,
      entries: nextEntries,
    });
    setSelectedEntryId(nextEntries[0]?.id ?? null);
  }, [applyStore, parsedState.store, selectedEntry]);

  const handleMoveSelectedEntry = useCallback((direction: -1 | 1): void => {
    if (!parsedState.store || !selectedEntry) {
      return;
    }

    const currentIndex = parsedState.store.entries.findIndex((entry) => entry.id === selectedEntry.id);
    const nextIndex = currentIndex + direction;
    if (currentIndex < 0 || nextIndex < 0 || nextIndex >= parsedState.store.entries.length) {
      return;
    }

    const nextEntries = [...parsedState.store.entries];
    const [removed] = nextEntries.splice(currentIndex, 1);
    if (!removed) {
      return;
    }
    nextEntries.splice(nextIndex, 0, removed);
    applyStore({
      ...parsedState.store,
      entries: normalizeEntries(nextEntries),
    });
  }, [applyStore, parsedState.store, selectedEntry]);

  const handleResetToDefaults = useCallback((): void => {
    const serialized = stringifyPageContentStore(DEFAULT_KANGUR_PAGE_CONTENT_STORE);
    setEditorValue(serialized);
    setSelectedEntryId(DEFAULT_KANGUR_PAGE_CONTENT_STORE.entries[0]?.id ?? null);
    setSelectedFragmentId(DEFAULT_KANGUR_PAGE_CONTENT_STORE.entries[0]?.fragments[0]?.id ?? null);
  }, []);

  const updateSelectedFragment = useCallback((
    updater: (fragment: KangurPageContentFragment) => KangurPageContentFragment
  ): void => {
    if (!selectedEntry || !selectedFragment) {
      return;
    }

    const nextFragment = updater(selectedFragment);
    updateSelectedEntry((entry) => ({
      ...entry,
      fragments: entry.fragments.map((fragment) =>
        fragment.id === selectedFragment.id ? nextFragment : fragment
      ),
    }));
    setSelectedFragmentId(nextFragment.id);
  }, [selectedEntry, selectedFragment, updateSelectedEntry]);

  const handleAddFragment = useCallback((): void => {
    if (!selectedEntry) {
      return;
    }

    const nextFragments = normalizeFragments([
      ...selectedEntry.fragments,
      createEmptyFragment((selectedEntry.fragments.length + 1) * 10),
    ]);
    const nextFragment = nextFragments[nextFragments.length - 1] ?? null;
    updateSelectedEntry((entry) => ({
      ...entry,
      fragments: nextFragments,
    }));
    setSelectedFragmentId(nextFragment?.id ?? null);
  }, [selectedEntry, updateSelectedEntry]);

  const handleDuplicateSelectedFragment = useCallback((): void => {
    if (!selectedEntry || !selectedFragment) {
      return;
    }

    const duplicate: KangurPageContentFragment = {
      ...selectedFragment,
      id: createFragmentId(),
      text: `${selectedFragment.text} kopia`,
      sortOrder: selectedFragment.sortOrder + 1,
    };
    const currentIndex = selectedEntry.fragments.findIndex(
      (fragment) => fragment.id === selectedFragment.id
    );
    const nextFragments = [...selectedEntry.fragments];
    nextFragments.splice(currentIndex + 1, 0, duplicate);
    const normalizedFragments = normalizeFragments(nextFragments);
    updateSelectedEntry((entry) => ({
      ...entry,
      fragments: normalizedFragments,
    }));
    setSelectedFragmentId(duplicate.id);
  }, [selectedEntry, selectedFragment, updateSelectedEntry]);

  const handleDeleteSelectedFragment = useCallback((): void => {
    if (!selectedEntry || !selectedFragment) {
      return;
    }

    const nextFragments = normalizeFragments(
      selectedEntry.fragments.filter((fragment) => fragment.id !== selectedFragment.id)
    );
    updateSelectedEntry((entry) => ({
      ...entry,
      fragments: nextFragments,
    }));
    setSelectedFragmentId(nextFragments[0]?.id ?? null);
  }, [selectedEntry, selectedFragment, updateSelectedEntry]);

  const handleMoveSelectedFragment = useCallback((direction: -1 | 1): void => {
    if (!selectedEntry || !selectedFragment) {
      return;
    }

    const currentIndex = selectedEntry.fragments.findIndex(
      (fragment) => fragment.id === selectedFragment.id
    );
    const nextIndex = currentIndex + direction;
    if (currentIndex < 0 || nextIndex < 0 || nextIndex >= selectedEntry.fragments.length) {
      return;
    }

    const nextFragments = [...selectedEntry.fragments];
    const [removed] = nextFragments.splice(currentIndex, 1);
    if (!removed) {
      return;
    }

    nextFragments.splice(nextIndex, 0, removed);
    const normalizedFragments = normalizeFragments(nextFragments);
    updateSelectedEntry((entry) => ({
      ...entry,
      fragments: normalizedFragments,
    }));
  }, [selectedEntry, selectedFragment, updateSelectedEntry]);

  const handleSave = useCallback(async (): Promise<void> => {
    if (parsedState.error || !parsedState.store) {
      toast(parsedState.error ?? 'Page content JSON is invalid.', { variant: 'error' });
      return;
    }

    setIsSaving(true);
    const didSave = await withKangurClientError(
      {
        source: 'kangur.admin.page-content',
        action: 'save-store',
        description: 'Saves the Kangur page content store from the admin editor.',
      },
      async () => {
        const saved = await api.post<KangurPageContentStore>(
          '/api/kangur/ai-tutor/page-content',
          parsedState.store
        );
        const serialized = stringifyPageContentStore(parseKangurPageContentStore(saved));
        setEditorValue(serialized);
        setPersistedEditorValue(serialized);
        return true;
      },
      {
        fallback: false,
        onError: (error) => {
          toast(error instanceof Error ? error.message : 'Failed to save Kangur page content.', {
            variant: 'error',
          });
        },
      }
    );

    if (didSave) {
      toast('Kangur page content saved.', { variant: 'success' });
    }
    setIsSaving(false);
  }, [parsedState.error, parsedState.store, toast]);

  return {
    editorValue,
    setEditorValue,
    isLoading,
    isSaving,
    selectedEntryId,
    setSelectedEntryId,
    selectedFragmentId,
    setSelectedFragmentId,
    isDirty,
    parsedState,
    selectedEntry,
    selectedFragment,
    loadStore,
    handleSave,
    handleAddEntry,
    handleDuplicateSelectedEntry,
    handleDeleteSelectedEntry,
    handleMoveSelectedEntry,
    handleResetToDefaults,
    updateSelectedEntry,
    updateSelectedFragment,
    handleAddFragment,
    handleDuplicateSelectedFragment,
    handleDeleteSelectedFragment,
    handleMoveSelectedFragment,
  };
}

'use client';

import { useCallback, useState } from 'react';

import type { KangurTestQuestion } from '@/features/kangur/shared/contracts/kangur-tests';
import { useUpdateSetting } from '@/shared/hooks/use-settings';
import { useToast } from '@/features/kangur/shared/ui';
import { serializeSetting } from '@/features/kangur/shared/utils/settings-json';
import { withKangurClientError } from '@/features/kangur/observability/client';

import {
  applyPublishedQuestionEditPolicy,
  KANGUR_TEST_QUESTIONS_SETTING_KEY,
  createKangurTestQuestion,
  deleteKangurTestQuestion,
  formDataToQuestion,
  type parseKangurTestQuestionStore,
  publishReadyQuestions,
  reorderQuestions,
  shouldDemotePublishedQuestionAfterEdit,
  toQuestionFormData,
  upsertKangurTestQuestion,
  type QuestionFormData,
} from '../../test-suites/questions';
import {
  canonicalizeKangurTestSuites,
  KANGUR_TEST_SUITES_SETTING_KEY,
  demoteInvalidLiveKangurTestSuites,
  demoteKangurTestSuitesToDraft,
  promoteKangurTestSuitesLive,
} from '../../test-suites';
import {
  clearQuestionEditorDraft,
  QUESTION_EDITOR_NEW_DRAFT_SLOT,
} from '../question-editor-drafts';
import { moveItem } from '../utils';
import type { KangurTestSuite } from '@/features/kangur/shared/contracts/kangur-tests';

const buildQuestionEditorSnapshot = (
  question: KangurTestQuestion,
  formData: QuestionFormData
): string =>
  JSON.stringify({
    question,
    formData,
  });

export function useKangurQuestionsMutations(
  suite: KangurTestSuite,
  suites: KangurTestSuite[],
  questionStore: Record<string, KangurTestQuestion>,
  questions: KangurTestQuestion[],
  currentPublishableQuestionIds: string[]
) {
  const updateSetting = useUpdateSetting();
  const { toast } = useToast();

  const [editingQuestion, setEditingQuestion] = useState<KangurTestQuestion | null>(null);
  const [isNewQuestion, setIsNewQuestion] = useState(false);
  const [formData, setFormData] = useState<QuestionFormData | null>(null);
  const [showEditor, setShowEditor] = useState(false);
  const [questionToDelete, setQuestionToDelete] = useState<KangurTestQuestion | null>(null);
  const [discardConfirmOpen, setDiscardConfirmOpen] = useState(false);
  const [initialEditorSnapshot, setInitialEditorSnapshot] = useState<string | null>(null);
  const [localDraftSavedAt, setLocalDraftSavedAt] = useState<string | null>(null);
  const [restorableDraftSavedAt, setRestorableDraftSavedAt] = useState<string | null>(null);

  const openEditor = useCallback(
    (question: KangurTestQuestion, nextIsNewQuestion: boolean): void => {
      const nextFormData = toQuestionFormData(question);
      setEditingQuestion(question);
      setFormData(nextFormData);
      setIsNewQuestion(nextIsNewQuestion);
      setShowEditor(true);
      setDiscardConfirmOpen(false);
      setLocalDraftSavedAt(null);
      setRestorableDraftSavedAt(null);
      setInitialEditorSnapshot(buildQuestionEditorSnapshot(question, nextFormData));
    },
    []
  );

  const closeEditor = useCallback((): void => {
    setShowEditor(false);
    setEditingQuestion(null);
    setFormData(null);
    setIsNewQuestion(false);
    setDiscardConfirmOpen(false);
    setInitialEditorSnapshot(null);
    setLocalDraftSavedAt(null);
    setRestorableDraftSavedAt(null);
  }, []);

  const openCreate = (): void => {
    openEditor(createKangurTestQuestion(suite.id, (questions.length + 1) * 1000), true);
  };

  const openEdit = (q: KangurTestQuestion): void => {
    openEditor(q, false);
  };

  const maybeTakeSuiteOfflineAfterQuestionMutation = useCallback(
    async (nextQuestionStore: ReturnType<typeof parseKangurTestQuestionStore>): Promise<boolean> => {
      const demotion = demoteInvalidLiveKangurTestSuites(suites, nextQuestionStore, {
        suiteIds: [suite.id],
      });

      if (demotion.draftSuiteIds.length === 0) {
        return false;
      }

      await updateSetting.mutateAsync({
        key: KANGUR_TEST_SUITES_SETTING_KEY,
        value: serializeSetting(demotion.suites),
      });

      return true;
    },
    [suite.id, suites, updateSetting]
  );

  const handlePublishReadyForCurrentSuite = useCallback(async (): Promise<void> => {
    const publishResult = await withKangurClientError(
      {
        source: 'kangur.admin.questions',
        action: 'publish-ready-questions',
        description: 'Publishes ready questions for the current test suite.',
        context: { suiteId: suite.id },
      },
      async () => {
        const { store: nextStore, publishedQuestionIds } = publishReadyQuestions(questionStore, {
          suiteId: suite.id,
          questionIds: currentPublishableQuestionIds,
        });
        await updateSetting.mutateAsync({
          key: KANGUR_TEST_QUESTIONS_SETTING_KEY,
          value: serializeSetting(nextStore),
        });
        return { questionCount: publishedQuestionIds.length };
      },
      {
        fallback: null,
        onError: () => {
          toast('Failed to publish ready questions.', { variant: 'error' });
        },
      }
    );

    if (publishResult) {
      const questionCount = publishResult.questionCount;
      toast(
        `Published ${questionCount} ready question${questionCount === 1 ? '' : 's'} in ${suite.title}.`,
        { variant: 'success' }
      );
    }
  }, [currentPublishableQuestionIds, questionStore, suite.id, toast, updateSetting]);

  const handlePublishAndGoLiveCurrentSuite = useCallback(async (): Promise<void> => {
    const publishResult = await withKangurClientError(
      {
        source: 'kangur.admin.questions',
        action: 'publish-and-go-live',
        description: 'Publishes ready questions and marks the suite live.',
        context: { suiteId: suite.id },
      },
      async () => {
        const { store: nextStore, publishedQuestionIds } = publishReadyQuestions(questionStore, {
          suiteId: suite.id,
          questionIds: currentPublishableQuestionIds,
        });
        await updateSetting.mutateAsync({
          key: KANGUR_TEST_QUESTIONS_SETTING_KEY,
          value: serializeSetting(nextStore),
        });

        const { suites: nextSuites } = promoteKangurTestSuitesLive(suites, {
          suiteIds: [suite.id],
        });
        await updateSetting.mutateAsync({
          key: KANGUR_TEST_SUITES_SETTING_KEY,
          value: serializeSetting(canonicalizeKangurTestSuites(nextSuites)),
        });

        return { questionCount: publishedQuestionIds.length };
      },
      {
        fallback: null,
        onError: () => {
          toast('Failed to publish and go live.', { variant: 'error' });
        },
      }
    );

    if (publishResult) {
      const questionCount = publishResult.questionCount;
      toast(
        `Published ${questionCount} ready question${questionCount === 1 ? '' : 's'} and marked ${suite.title} live for learners (1 suite updated).`,
        { variant: 'success' }
      );
    }
  }, [currentPublishableQuestionIds, questionStore, suite.id, suites, toast, updateSetting]);

  const handleGoLiveCurrentSuite = useCallback(async (): Promise<void> => {
    const didGoLive = await withKangurClientError(
      {
        source: 'kangur.admin.questions',
        action: 'go-live-suite',
        description: 'Marks the current suite as live.',
        context: { suiteId: suite.id },
      },
      async () => {
        const { suites: nextSuites } = promoteKangurTestSuitesLive(suites, {
          suiteIds: [suite.id],
        });
        await updateSetting.mutateAsync({
          key: KANGUR_TEST_SUITES_SETTING_KEY,
          value: serializeSetting(canonicalizeKangurTestSuites(nextSuites)),
        });
        return true;
      },
      {
        fallback: false,
        onError: () => {
          toast('Failed to mark suite live.', { variant: 'error' });
        },
      }
    );

    if (didGoLive) {
      toast(`Suite ${suite.title} is now live for learners (1 suite updated).`, {
        variant: 'success',
      });
    }
  }, [suite.id, suites, toast, updateSetting]);

  const handleTakeCurrentSuiteOffline = useCallback(async (): Promise<void> => {
    const didTakeOffline = await withKangurClientError(
      {
        source: 'kangur.admin.questions',
        action: 'take-suite-offline',
        description: 'Demotes the current suite to draft status.',
        context: { suiteId: suite.id },
      },
      async () => {
        const { suites: nextSuites } = demoteKangurTestSuitesToDraft(suites, {
          suiteIds: [suite.id],
        });
        await updateSetting.mutateAsync({
          key: KANGUR_TEST_SUITES_SETTING_KEY,
          value: serializeSetting(canonicalizeKangurTestSuites(nextSuites)),
        });
        return true;
      },
      {
        fallback: false,
        onError: () => {
          toast('Failed to take suite offline.', { variant: 'error' });
        },
      }
    );

    if (didTakeOffline) {
      toast(`Suite ${suite.title} is now offline for learners (1 suite updated).`, {
        variant: 'success',
      });
    }
  }, [suite.id, suites, toast, updateSetting]);

  const handleSave = async (): Promise<void> => {
    if (!editingQuestion || !formData) return;
    const saveResult = await withKangurClientError(
      {
        source: 'kangur.admin.questions',
        action: 'save-question',
        description: 'Saves the current test question draft.',
        context: { suiteId: suite.id, questionId: editingQuestion.id, isNewQuestion },
      },
      async () => {
        const savedDraft = formDataToQuestion(
          formData,
          editingQuestion.id,
          suite.id,
          editingQuestion.sortOrder
        );
        const wasDemotedByPolicy = shouldDemotePublishedQuestionAfterEdit(
          editingQuestion,
          savedDraft
        );
        const saved = applyPublishedQuestionEditPolicy(
          isNewQuestion ? null : editingQuestion,
          savedDraft
        );
        const nextStore = upsertKangurTestQuestion(questionStore, saved);
        await updateSetting.mutateAsync({
          key: KANGUR_TEST_QUESTIONS_SETTING_KEY,
          value: serializeSetting(nextStore),
        });
        const activeDraftQuestionId = isNewQuestion
          ? QUESTION_EDITOR_NEW_DRAFT_SLOT
          : editingQuestion.id;
        clearQuestionEditorDraft(suite.id, activeDraftQuestionId);
        const suiteWasDemoted = await maybeTakeSuiteOfflineAfterQuestionMutation(nextStore);
        return { wasDemotedByPolicy, suiteWasDemoted };
      },
      {
        fallback: null,
        onError: () => {
          toast('Failed to save question.', { variant: 'error' });
        },
      }
    );

    if (saveResult) {
      if (saveResult.wasDemotedByPolicy) {
        toast(
          'Question updated. Learner-facing changes moved this published question back to draft.',
          { variant: 'warning' }
        );
      } else if (saveResult.suiteWasDemoted) {
        toast(
          'Question saved. The live suite was taken offline because its published question set changed.',
          { variant: 'warning' }
        );
      } else {
        toast('Question saved.', { variant: 'success' });
      }
      closeEditor();
    }
  };

  const handleDelete = async (): Promise<void> => {
    if (!questionToDelete) return;
    const deleteResult = await withKangurClientError(
      {
        source: 'kangur.admin.questions',
        action: 'delete-question',
        description: 'Deletes the selected test question.',
        context: { suiteId: suite.id, questionId: questionToDelete.id },
      },
      async () => {
        const nextStore = deleteKangurTestQuestion(questionStore, questionToDelete.id);
        await updateSetting.mutateAsync({
          key: KANGUR_TEST_QUESTIONS_SETTING_KEY,
          value: serializeSetting(nextStore),
        });
        clearQuestionEditorDraft(suite.id, questionToDelete.id);
        const suiteWasDemoted = await maybeTakeSuiteOfflineAfterQuestionMutation(nextStore);
        return { suiteWasDemoted };
      },
      {
        fallback: null,
        onError: () => {
          toast('Failed to delete question.', { variant: 'error' });
        },
      }
    );

    if (deleteResult) {
      if (deleteResult.suiteWasDemoted) {
        toast(
          'Question deleted. The live suite was taken offline because its published question set changed.',
          { variant: 'warning' }
        );
      } else {
        toast('Question deleted.', { variant: 'success' });
      }
      setQuestionToDelete(null);
    }
  };

  const handleDuplicate = async (q: KangurTestQuestion): Promise<void> => {
    const duplicateResult = await withKangurClientError(
      {
        source: 'kangur.admin.questions',
        action: 'duplicate-question',
        description: 'Creates a duplicate of the selected test question.',
        context: { suiteId: suite.id, questionId: q.id },
      },
      async () => {
        const duped: KangurTestQuestion = {
          ...q,
          id: Math.random().toString(36).slice(2, 9), // Fallback if no helper
          sortOrder: q.sortOrder + 500,
          prompt: `${q.prompt} (copy)`,
          editorial: {
            ...q.editorial,
            workflowStatus: 'draft',
            publishedAt: undefined,
          },
        };
        const nextStore = upsertKangurTestQuestion(questionStore, duped);
        await updateSetting.mutateAsync({
          key: KANGUR_TEST_QUESTIONS_SETTING_KEY,
          value: serializeSetting(nextStore),
        });
        const suiteWasDemoted = await maybeTakeSuiteOfflineAfterQuestionMutation(nextStore);
        return { suiteWasDemoted };
      },
      {
        fallback: null,
        onError: () => {
          toast('Failed to duplicate question.', { variant: 'error' });
        },
      }
    );

    if (duplicateResult) {
      if (duplicateResult.suiteWasDemoted) {
        toast(
          'Question duplicated. The live suite was taken offline because its published question set changed.',
          { variant: 'warning' }
        );
      } else {
        toast('Question duplicated.', { variant: 'success' });
      }
    }
  };

  const handleMove = async (fromIndex: number, toIndex: number): Promise<void> => {
    await withKangurClientError(
      {
        source: 'kangur.admin.questions',
        action: 'reorder-questions',
        description: 'Reorders test questions within the suite.',
        context: { suiteId: suite.id, fromIndex, toIndex },
      },
      async () => {
        const moved = reorderQuestions(moveItem(questions, fromIndex, toIndex));
        let nextStore = { ...questionStore };
        for (const q of moved) {
          nextStore = upsertKangurTestQuestion(nextStore, q);
        }
        await updateSetting.mutateAsync({
          key: KANGUR_TEST_QUESTIONS_SETTING_KEY,
          value: serializeSetting(nextStore),
        });
      },
      {
        fallback: undefined,
        onError: () => {
          toast('Failed to reorder questions.', { variant: 'error' });
        },
      }
    );
  };

  return {
    editingQuestion,
    setEditingQuestion,
    isNewQuestion,
    setIsNewQuestion,
    formData,
    setFormData,
    showEditor,
    setShowEditor,
    questionToDelete,
    setQuestionToDelete,
    discardConfirmOpen,
    setDiscardConfirmOpen,
    initialEditorSnapshot,
    setInitialEditorSnapshot,
    localDraftSavedAt,
    setLocalDraftSavedAt,
    restorableDraftSavedAt,
    setRestorableDraftSavedAt,
    openEditor,
    closeEditor,
    openCreate,
    openEdit,
    handlePublishReadyForCurrentSuite,
    handlePublishAndGoLiveCurrentSuite,
    handleGoLiveCurrentSuite,
    handleTakeCurrentSuiteOffline,
    handleSave,
    handleDelete,
    handleDuplicate,
    handleMove,
    isSaving: updateSetting.isPending,
  };
}

'use client';

import { useEffect, useMemo, useRef, useState } from 'react';

import {
  KANGUR_LAUNCH_ROUTE_SETTINGS_KEY,
  KANGUR_NARRATOR_SETTINGS_KEY,
  KANGUR_PARENT_VERIFICATION_SETTINGS_KEY,
  parseKangurLaunchRouteSettings,
  parseKangurParentVerificationEmailSettings,
  parseKangurNarratorSettings,
  type KangurLaunchRoute,
  type KangurNarratorEngine,
  type KangurParentVerificationEmailSettings,
} from '@/features/kangur/settings';
import {
  KANGUR_AI_TUTOR_APP_SETTINGS_KEY,
  KANGUR_AI_TUTOR_SETTINGS_KEY,
  parseKangurAiTutorSettings,
  resolveKangurAiTutorAppSettings,
  resolveKangurAiTutorMotionPresetKind,
  type KangurAiTutorAppSettings,
  type KangurAiTutorGuestIntroMode,
  type KangurAiTutorHomeOnboardingMode,
} from '@/features/kangur/ai-tutor/settings';
import type {
  KangurLessonTtsProbeResponse,
  KangurLessonTtsVoice,
} from '@/features/kangur/tts/contracts';
import { useUpdateSetting } from '@/shared/hooks/use-settings';
import { useAgentPersonas } from '@/shared/hooks/useAgentPersonas';
import { api } from '@/shared/lib/api-client';
import { useSettingsStore } from '@/features/kangur/shared/providers/SettingsStoreProvider';
import { useToast } from '@/features/kangur/shared/ui';
import { serializeSetting } from '@/features/kangur/shared/utils/settings-json';
import { withKangurClientError } from '@/features/kangur/observability/client';

const TEST_NARRATOR_TEMPLATE_TEXT =
  'A bright classroom welcomes curious minds. Here is a short narration sample to verify the chosen voice.';
const TEST_NARRATOR_PROBE_TEXT = 'To jest krótki test narratora Kangur.';

const KANGUR_PARENT_VERIFICATION_RESEND_COOLDOWN_SECONDS_MIN = 1;
const KANGUR_PARENT_VERIFICATION_RESEND_COOLDOWN_SECONDS_MAX = 3600;

const areAiTutorAppSettingsEqual = (
  left: KangurAiTutorAppSettings,
  right: KangurAiTutorAppSettings
): boolean =>
  left.agentPersonaId === right.agentPersonaId &&
  left.motionPresetId === right.motionPresetId &&
  left.dailyMessageLimit === right.dailyMessageLimit &&
  left.guestIntroMode === right.guestIntroMode &&
  left.homeOnboardingMode === right.homeOnboardingMode &&
  left.contextRegistryMaxNodes === right.contextRegistryMaxNodes &&
  left.contextRegistryDepth === right.contextRegistryDepth &&
  left.knowledgeGraphEnabled === right.knowledgeGraphEnabled;

const parseAiTutorDailyMessageLimit = (value: string): number | null => {
  const parsed = Number.parseInt(value, 10);
  if (!Number.isFinite(parsed) || parsed <= 0) {
    return null;
  }

  return Math.min(parsed, 200);
};

const parseParentVerificationCooldownInput = (value: string): number | null => {
  const parsed = Number.parseInt(value, 10);
  if (!Number.isFinite(parsed) || parsed <= 0) {
    return null;
  }

  return Math.min(
    Math.max(parsed, KANGUR_PARENT_VERIFICATION_RESEND_COOLDOWN_SECONDS_MIN),
    KANGUR_PARENT_VERIFICATION_RESEND_COOLDOWN_SECONDS_MAX
  );
};

const formatParentVerificationDisabledUntilInput = (value: string | null): string => {
  if (!value) return '';
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return '';
  const offsetMs = parsed.getTimezoneOffset() * 60_000;
  return new Date(parsed.getTime() - offsetMs).toISOString().slice(0, 16);
};

const parseParentVerificationDisabledUntilInput = (
  value: string
): string | null | undefined => {
  const trimmed = value.trim();
  if (!trimmed) return null;
  const parsed = new Date(trimmed);
  if (Number.isNaN(parsed.getTime())) return undefined;
  return parsed.toISOString();
};

export function useKangurSettings() {
  const settingsStore = useSettingsStore();
  const updateSetting = useUpdateSetting();
  const { toast } = useToast();
  const { data: agentPersonas = [] } = useAgentPersonas();

  const rawNarratorSettings = settingsStore.get(KANGUR_NARRATOR_SETTINGS_KEY);
  const rawAiTutorSettings = settingsStore.get(KANGUR_AI_TUTOR_SETTINGS_KEY);
  const rawAiTutorAppSettings = settingsStore.get(KANGUR_AI_TUTOR_APP_SETTINGS_KEY);
  const rawParentVerificationEmailSettings =
    settingsStore.get(KANGUR_PARENT_VERIFICATION_SETTINGS_KEY);
  const rawLaunchRouteSettings = settingsStore.get(KANGUR_LAUNCH_ROUTE_SETTINGS_KEY);

  const persistedNarratorSettings = useMemo(
    () => parseKangurNarratorSettings(rawNarratorSettings),
    [rawNarratorSettings]
  );
  const aiTutorSettingsStore = useMemo(
    () => parseKangurAiTutorSettings(rawAiTutorSettings),
    [rawAiTutorSettings]
  );
  const persistedAiTutorSettings = useMemo(
    () => resolveKangurAiTutorAppSettings(rawAiTutorAppSettings, aiTutorSettingsStore),
    [rawAiTutorAppSettings, aiTutorSettingsStore]
  );
  const persistedParentVerificationEmailSettings = useMemo(
    () => parseKangurParentVerificationEmailSettings(rawParentVerificationEmailSettings),
    [rawParentVerificationEmailSettings]
  );
  const persistedLaunchRouteSettings = useMemo(
    () => parseKangurLaunchRouteSettings(rawLaunchRouteSettings),
    [rawLaunchRouteSettings]
  );

  const [engine, setEngine] = useState<KangurNarratorEngine>(persistedNarratorSettings.engine);
  const [voice, setVoice] = useState<KangurLessonTtsVoice>(persistedNarratorSettings.voice);
  const [agentPersonaId, setAgentPersonaId] = useState(persistedAiTutorSettings.agentPersonaId ?? '');
  const [motionPresetId, setMotionPresetId] = useState(() => {
    const resolved = resolveKangurAiTutorMotionPresetKind(persistedAiTutorSettings.motionPresetId);
    return resolved === 'default' ? '' : resolved;
  });
  const [dailyMessageLimitInput, setDailyMessageLimitInput] = useState(
    persistedAiTutorSettings.dailyMessageLimit
      ? String(persistedAiTutorSettings.dailyMessageLimit)
      : ''
  );
  const [parentVerificationResendCooldownInput, setParentVerificationResendCooldownInput] =
    useState(
      String(persistedParentVerificationEmailSettings.resendCooldownSeconds)
    );
  const [parentVerificationNotificationsEnabled, setParentVerificationNotificationsEnabled] =
    useState(persistedParentVerificationEmailSettings.notificationsEnabled);
  const [
    parentVerificationRequireEmailVerification,
    setParentVerificationRequireEmailVerification,
  ] = useState(persistedParentVerificationEmailSettings.requireEmailVerification);
  const [parentVerificationRequireCaptcha, setParentVerificationRequireCaptcha] = useState(
    persistedParentVerificationEmailSettings.requireCaptcha
  );
  const [
    parentVerificationNotificationsDisabledUntilInput,
    setParentVerificationNotificationsDisabledUntilInput,
  ] = useState(
    formatParentVerificationDisabledUntilInput(
      persistedParentVerificationEmailSettings.notificationsDisabledUntil
    )
  );
  const [launchRoute, setLaunchRoute] = useState<KangurLaunchRoute>(
    persistedLaunchRouteSettings.route
  );
  const [guestIntroMode, setGuestIntroMode] = useState<KangurAiTutorGuestIntroMode>(
    persistedAiTutorSettings.guestIntroMode
  );
  const [homeOnboardingMode, setHomeOnboardingMode] = useState<KangurAiTutorHomeOnboardingMode>(
    persistedAiTutorSettings.homeOnboardingMode
  );
  const [contextRegistryMaxNodes, setContextRegistryMaxNodes] = useState(
    String(persistedAiTutorSettings.contextRegistryMaxNodes)
  );
  const [contextRegistryDepth, setContextRegistryDepth] = useState(
    String(persistedAiTutorSettings.contextRegistryDepth)
  );
  const [knowledgeGraphEnabled, setKnowledgeGraphEnabled] = useState(
    persistedAiTutorSettings.knowledgeGraphEnabled
  );
  const [copyStatus, setCopyStatus] = useState('Copy text');
  const [narratorProbe, setNarratorProbe] = useState<KangurLessonTtsProbeResponse | null>(null);
  const [isProbingNarrator, setIsProbingNarrator] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const copyTimeoutRef = useRef<number | null>(null);
  const narratorProbeRequestIdRef = useRef(0);
  const lastAutoProbeVoiceRef = useRef<KangurLessonTtsVoice | null>(null);

  useEffect(() => {
    setEngine(persistedNarratorSettings.engine);
    setVoice(persistedNarratorSettings.voice);
  }, [persistedNarratorSettings.engine, persistedNarratorSettings.voice]);

  useEffect(() => {
    setAgentPersonaId(persistedAiTutorSettings.agentPersonaId ?? '');
    const resolved = resolveKangurAiTutorMotionPresetKind(persistedAiTutorSettings.motionPresetId);
    setMotionPresetId(resolved === 'default' ? '' : resolved);
    setDailyMessageLimitInput(
      persistedAiTutorSettings.dailyMessageLimit
        ? String(persistedAiTutorSettings.dailyMessageLimit)
        : ''
    );
    setGuestIntroMode(persistedAiTutorSettings.guestIntroMode);
    setHomeOnboardingMode(persistedAiTutorSettings.homeOnboardingMode);
    setContextRegistryMaxNodes(String(persistedAiTutorSettings.contextRegistryMaxNodes));
    setContextRegistryDepth(String(persistedAiTutorSettings.contextRegistryDepth));
    setKnowledgeGraphEnabled(persistedAiTutorSettings.knowledgeGraphEnabled);
  }, [persistedAiTutorSettings]);

  useEffect(() => {
    setParentVerificationResendCooldownInput(
      String(persistedParentVerificationEmailSettings.resendCooldownSeconds)
    );
    setParentVerificationNotificationsEnabled(
      persistedParentVerificationEmailSettings.notificationsEnabled
    );
    setParentVerificationRequireEmailVerification(
      persistedParentVerificationEmailSettings.requireEmailVerification
    );
    setParentVerificationRequireCaptcha(persistedParentVerificationEmailSettings.requireCaptcha);
    setParentVerificationNotificationsDisabledUntilInput(
      formatParentVerificationDisabledUntilInput(
        persistedParentVerificationEmailSettings.notificationsDisabledUntil
      )
    );
  }, [persistedParentVerificationEmailSettings]);

  useEffect(() => {
    setLaunchRoute(persistedLaunchRouteSettings.route);
  }, [persistedLaunchRouteSettings.route]);

  useEffect(
    () => () => {
      if (copyTimeoutRef.current) {
        safeClearTimeout(copyTimeoutRef.current);
      }
    },
    []
  );

  const handleCopyTemplateText = async (): Promise<void> => {
    if (typeof navigator === 'undefined' || !navigator.clipboard?.writeText) {
      setCopyStatus('Copy not available');
      return;
    }

    const didCopy = await withKangurClientError(
      {
        source: 'kangur.admin.settings',
        action: 'copy-narrator-template',
        description: 'Copies the narrator template text to clipboard.',
      },
      async () => {
        await navigator.clipboard.writeText(TEST_NARRATOR_TEMPLATE_TEXT);
        return true;
      },
      {
        fallback: false,
        onError: () => {
          setCopyStatus('Copy failed');
        },
      }
    );

    if (didCopy) {
      setCopyStatus('Copied!');
      if (copyTimeoutRef.current) {
        safeClearTimeout(copyTimeoutRef.current);
      }
      copyTimeoutRef.current = safeSetTimeout(() => setCopyStatus('Copy text'), 1800);
    }
  };

  const handleProbeNarrator = async ({
    notify = true,
  }: {
    notify?: boolean;
  } = {}): Promise<void> => {
    const probeRequestId = narratorProbeRequestIdRef.current + 1;
    narratorProbeRequestIdRef.current = probeRequestId;
    setNarratorProbe(null);
    setIsProbingNarrator(true);
    const probeResult = await withKangurClientError(
      {
        source: 'kangur.admin.settings',
        action: 'probe-narrator',
        description: 'Runs a narrator TTS probe for the selected voice.',
        context: { voice },
      },
      async () =>
        await api.post<KangurLessonTtsProbeResponse>(
          '/api/kangur/tts/probe',
          {
            voice,
            locale: 'pl-PL',
            text: TEST_NARRATOR_PROBE_TEXT,
          },
          { logError: false }
        ),
      {
        fallback: null,
        onError: (error) => {
          if (narratorProbeRequestIdRef.current !== probeRequestId) {
            return;
          }
          if (notify) {
            toast(error instanceof Error ? error.message : 'Failed to próbę the server narrator.', {
              variant: 'error',
            });
          }
        },
      }
    );

    if (narratorProbeRequestIdRef.current === probeRequestId && probeResult) {
      setNarratorProbe(probeResult);
      if (notify) {
        toast(probeResult.ok ? 'Server narrator is ready.' : 'Server narrator próbę found an issue.', {
          variant: probeResult.ok ? 'success' : 'error',
        });
      }
    }
    if (narratorProbeRequestIdRef.current === probeRequestId) {
      setIsProbingNarrator(false);
    }
  };

  useEffect(() => {
    if (lastAutoProbeVoiceRef.current === voice) {
      return;
    }
    lastAutoProbeVoiceRef.current = voice;
    void handleProbeNarrator({ notify: false });
  }, [voice]);

  const narratorDirty =
    engine !== persistedNarratorSettings.engine || voice !== persistedNarratorSettings.voice;
  const draftAiTutorSettings = useMemo<KangurAiTutorAppSettings>(
    () => ({
      agentPersonaId: agentPersonaId || null,
      motionPresetId: motionPresetId || null,
      dailyMessageLimit: parseAiTutorDailyMessageLimit(dailyMessageLimitInput),
      guestIntroMode,
      homeOnboardingMode,
      contextRegistryMaxNodes: Math.max(1, Math.min(100, parseInt(contextRegistryMaxNodes) || 24)),
      contextRegistryDepth: Math.max(0, Math.min(5, parseInt(contextRegistryDepth) || 1)),
      knowledgeGraphEnabled,
    }),
    [agentPersonaId, dailyMessageLimitInput, guestIntroMode, homeOnboardingMode, motionPresetId, contextRegistryMaxNodes, contextRegistryDepth, knowledgeGraphEnabled]
  );

  const aiTutorSettingsDirty = !areAiTutorAppSettingsEqual(
    draftAiTutorSettings,
    persistedAiTutorSettings
  );
  const parentVerificationEmailDraft = useMemo<KangurParentVerificationEmailSettings>(
    () => {
      const parsedDisabledUntil = parseParentVerificationDisabledUntilInput(
        parentVerificationNotificationsDisabledUntilInput
      );

      return {
        resendCooldownSeconds:
          parseParentVerificationCooldownInput(parentVerificationResendCooldownInput) ??
          persistedParentVerificationEmailSettings.resendCooldownSeconds,
        notificationsEnabled: parentVerificationNotificationsEnabled,
        notificationsDisabledUntil:
          parsedDisabledUntil === undefined
            ? persistedParentVerificationEmailSettings.notificationsDisabledUntil
            : parsedDisabledUntil,
        requireEmailVerification: parentVerificationRequireEmailVerification,
        requireCaptcha: parentVerificationRequireCaptcha,
      };
    },
    [
      parentVerificationNotificationsDisabledUntilInput,
      parentVerificationNotificationsEnabled,
      parentVerificationRequireCaptcha,
      parentVerificationRequireEmailVerification,
      parentVerificationResendCooldownInput,
      persistedParentVerificationEmailSettings,
    ]
  );
  const parentVerificationEmailSettingsDirty =
    parentVerificationEmailDraft.resendCooldownSeconds !==
    persistedParentVerificationEmailSettings.resendCooldownSeconds ||
    parentVerificationEmailDraft.notificationsEnabled !==
    persistedParentVerificationEmailSettings.notificationsEnabled ||
    parentVerificationEmailDraft.notificationsDisabledUntil !==
    persistedParentVerificationEmailSettings.notificationsDisabledUntil ||
    parentVerificationEmailDraft.requireEmailVerification !==
    persistedParentVerificationEmailSettings.requireEmailVerification ||
    parentVerificationEmailDraft.requireCaptcha !==
    persistedParentVerificationEmailSettings.requireCaptcha;
  const parentVerificationNotificationsPausedUntil = useMemo(() => {
    const value = parentVerificationEmailDraft.notificationsDisabledUntil;
    if (!value) return null;
    const untilMs = Date.parse(value);
    if (!Number.isFinite(untilMs) || untilMs <= Date.now()) {
      return null;
    }
    return value;
  }, [parentVerificationEmailDraft.notificationsDisabledUntil]);
  const launchRouteSettingsDirty = launchRoute !== persistedLaunchRouteSettings.route;
  const isDirty =
    narratorDirty ||
    aiTutorSettingsDirty ||
    parentVerificationEmailSettingsDirty ||
    launchRouteSettingsDirty;

  const handleSave = async (): Promise<void> => {
    setIsSaving(true);
    const saveResult = await withKangurClientError(
      {
        source: 'kangur.admin.settings',
        action: 'save-settings',
        description: 'Saves Kangur settings sections.',
      },
      async () => {
        const savedSections: Array<
          | 'narrator'
          | 'ai-tutor'
          | 'parent-verification'
          | 'launch-route'
        > = [];

        if (narratorDirty) {
          await updateSetting.mutateAsync({
            key: KANGUR_NARRATOR_SETTINGS_KEY,
            value: serializeSetting({ engine, voice }),
          });
          savedSections.push('narrator');
        }

        if (aiTutorSettingsDirty) {
          await updateSetting.mutateAsync({
            key: KANGUR_AI_TUTOR_APP_SETTINGS_KEY,
            value: serializeSetting(draftAiTutorSettings),
          });
          savedSections.push('ai-tutor');
        }

        if (parentVerificationEmailSettingsDirty) {
          await updateSetting.mutateAsync({
            key: KANGUR_PARENT_VERIFICATION_SETTINGS_KEY,
            value: serializeSetting(parentVerificationEmailDraft),
          });
          savedSections.push('parent-verification');
        }

        if (launchRouteSettingsDirty) {
          await updateSetting.mutateAsync({
            key: KANGUR_LAUNCH_ROUTE_SETTINGS_KEY,
            value: serializeSetting({ route: launchRoute }),
          });
          savedSections.push('launch-route');
        }

        return savedSections;
      },
      {
        fallback: null,
        onError: (error) => {
          toast(error instanceof Error ? error.message : 'Failed to save Kangur settings.', {
            variant: 'error',
          });
        },
      }
    );

    if (saveResult && saveResult.length > 0) {
      if (saveResult.length > 1) {
        toast('Kangur settings saved.', { variant: 'success' });
      } else if (saveResult[0] === 'narrator') {
        toast('Kangur narrator settings saved.', { variant: 'success' });
      } else if (saveResult[0] === 'ai-tutor') {
        toast('Kangur AI Tutor settings saved.', { variant: 'success' });
      } else if (saveResult[0] === 'parent-verification') {
        toast('Kangur parent verification email settings saved.', {
          variant: 'success',
        });
      } else if (saveResult[0] === 'launch-route') {
        toast('Kangur launch route saved.', {
          variant: 'success',
        });
      }
    }
    setIsSaving(false);
  };

  return {
    engine,
    setEngine,
    voice,
    setVoice,
    agentPersonaId,
    setAgentPersonaId,
    motionPresetId,
    setMotionPresetId,
    dailyMessageLimitInput,
    setDailyMessageLimitInput,
    guestIntroMode,
    setGuestIntroMode,
    homeOnboardingMode,
    setHomeOnboardingMode,
    parentVerificationResendCooldownInput,
    setParentVerificationResendCooldownInput,
    parentVerificationNotificationsEnabled,
    setParentVerificationNotificationsEnabled,
    parentVerificationRequireEmailVerification,
    setParentVerificationRequireEmailVerification,
    parentVerificationRequireCaptcha,
    setParentVerificationRequireCaptcha,
    parentVerificationNotificationsDisabledUntilInput,
    setParentVerificationNotificationsDisabledUntilInput,
    launchRoute,
    setLaunchRoute,
    copyStatus,
    narratorProbe,
    isProbingNarrator,
    isSaving,
    isDirty,
    handleCopyTemplateText,
    handleProbeNarrator,
    handleSave,
    agentPersonas,
    persistedNarratorSettings,
    parentVerificationNotificationsPausedUntil,
    persistedParentVerificationEmailSettings,
    persistedLaunchRouteSettings,
  };
}

'use client';

