  KangurLessonPage,
  KangurLessonRootBlock,
} from '@/features/kangur/shared/contracts/kangur';

import { getLessonRecipeFamily } from '../utils';

export type StarterRecipe = {
  id: string;
  label: string;
  description: string;
  onClick: () => void;
};

export function useKangurStarterRecipes(
  lesson: KangurLesson | null,
  activePage: KangurLessonPage | null,
  updateDocument: (nextBlocks: KangurLessonRootBlock[]) => void,
  addPageFromTemplate: (templateId: KangurLessonDocumentTemplateId) => void
): StarterRecipe[] {
  return useMemo<StarterRecipe[]>(() => {
    const family = getLessonRecipeFamily(lesson?.componentId);
    if (family === 'time') {
      return [
        {
          id: 'time-intro',
          label: 'Add guided intro page',
          description: 'Start with an explanation page that can hold text and one reference visual.',
          onClick: (): void => addPageFromTemplate('text-with-figure'),
        },
        {
          id: 'time-practice',
          label: 'Add practice activity',
          description: 'Create the interactive learner task for clock or calendar practice.',
          onClick: (): void =>
            updateDocument([...(activePage?.blocks ?? []), createKangurLessonActivityBlock()]),
        },
        {
          id: 'time-reference',
          label: 'Add reference illustration',
          description: 'Insert an SVG image block for a worked example or annotated reference.',
          onClick: (): void =>
            updateDocument([...(activePage?.blocks ?? []), createKangurLessonImageBlock()]),
        },
      ];
    }
    if (family === 'arithmetic') {
      return [
        {
          id: 'arithmetic-intro',
          label: 'Start with worked example',
          description: 'Use a text-and-figure page to explain the method before practice.',
          onClick: (): void => addPageFromTemplate('text-with-figure'),
        },
        {
          id: 'arithmetic-practice',
          label: 'Add practice activity',
          description: 'Drop in an interactive task for repeated learner practice.',
          onClick: (): void =>
            updateDocument([...(activePage?.blocks ?? []), createKangurLessonActivityBlock()]),
        },
        {
          id: 'arithmetic-check',
          label: 'Check with a quiz',
          description: 'Finish the page with a short comprehension check.',
          onClick: (): void =>
            updateDocument([...(activePage?.blocks ?? []), createKangurLessonQuizBlock()]),
        },
      ];
    }
    if (family === 'geometry') {
      return [
        {
          id: 'geometry-visual',
          label: 'Add visual explainer page',
          description: 'Open with a diagram-friendly page for definitions and examples.',
          onClick: (): void => addPageFromTemplate('svg-gallery-page'),
        },
        {
          id: 'geometry-diagram',
          label: 'Insert SVG diagram',
          description: 'Add an inline SVG block for a labelled shape or construction.',
          onClick: (): void =>
            updateDocument([...(activePage?.blocks ?? []), createKangurLessonSvgBlock()]),
        },
        {
          id: 'geometry-gallery',
          label: 'Build example gallery',
          description: 'Use a gallery layout to compare multiple shapes or worked examples.',
          onClick: (): void =>
            updateDocument([
              ...(activePage?.blocks ?? []),
              createKangurLessonGridBlockFromTemplate('svg-gallery'),
            ]),
        },
      ];
    }
    return [
      {
        id: 'logic-intro',
        label: 'Start with reasoning prompt',
        description: 'Introduce the pattern or rule with a compact explanation page.',
        onClick: (): void => addPageFromTemplate('article'),
      },
      {
        id: 'logic-hint',
        label: 'Add hint callout',
        description: 'Give learners a scaffold or clue without revealing the answer.',
        onClick: (): void =>
          updateDocument([...(activePage?.blocks ?? []), createKangurLessonCalloutBlock()]),
      },
      {
        id: 'logic-quiz',
        label: 'Add reasoning quiz',
        description: 'Check whether the learner can apply the rule in a new situation.',
        onClick: (): void =>
          updateDocument([...(activePage?.blocks ?? []), createKangurLessonQuizBlock()]),
      },
    ];
  }, [activePage?.blocks, addPageFromTemplate, lesson?.componentId, updateDocument]);
}

import type { LabeledOptionDto } from '@/shared/contracts/base';
import type {
  KangurLesson,
  KangurLessonAgeGroup,
  KangurLessonComponentId,
  KangurLessonSubject,
} from '@/features/kangur/shared/contracts/kangur';
import type { MasterTreeNode } from '@/features/kangur/shared/utils/master-folder-tree-contract';

import { KANGUR_AGE_GROUPS, KANGUR_SUBJECTS } from '@/features/kangur/lessons/lesson-catalog-metadata';
import { KANGUR_LESSON_COMPONENT_OPTIONS, KANGUR_LESSON_SORT_ORDER_GAP } from '../settings';

const KANGUR_LESSON_NODE_PREFIX = 'kangur-lesson:';
const KANGUR_LESSON_GROUP_NODE_PREFIX = 'kangur-lesson-group:';
const KANGUR_LESSON_AGE_GROUP_GROUP_NODE_PREFIX = 'kangur-lesson-age-group-group:';
const KANGUR_LESSON_SUBJECT_GROUP_NODE_PREFIX = 'kangur-lesson-subject-group:';
const KANGUR_LESSON_COMPONENT_GROUP_NODE_PREFIX = 'kangur-lesson-component-group:';

type KangurLessonVisibilityGroup = 'enabled' | 'hidden';

export const toKangurLessonNodeId = (lessonId: string): string =>
  `${KANGUR_LESSON_NODE_PREFIX}${lessonId}`;

export const fromKangurLessonNodeId = (nodeId: string): string | null => {
  if (!nodeId.startsWith(KANGUR_LESSON_NODE_PREFIX)) return null;
  const lessonId = nodeId.slice(KANGUR_LESSON_NODE_PREFIX.length).trim();
  return lessonId || null;
};

const toKangurLessonVisibilityGroupNodeId = (group: KangurLessonVisibilityGroup): string =>
  `${KANGUR_LESSON_GROUP_NODE_PREFIX}${group}`;

const toKangurLessonAgeGroupGroupNodeId = ({
  group,
  ageGroup,
}: {
  group: KangurLessonVisibilityGroup;
  ageGroup: KangurLessonAgeGroup;
}): string => `${KANGUR_LESSON_AGE_GROUP_GROUP_NODE_PREFIX}${group}:${ageGroup}`;

const toKangurLessonSubjectGroupNodeId = ({
  group,
  ageGroup,
  subject,
}: {
  group: KangurLessonVisibilityGroup;
  ageGroup: KangurLessonAgeGroup;
  subject: KangurLessonSubject;
}): string => `${KANGUR_LESSON_SUBJECT_GROUP_NODE_PREFIX}${group}:${ageGroup}:${subject}`;

const toKangurLessonComponentGroupNodeId = ({
  group,
  ageGroup,
  subject,
  componentId,
}: {
  group: KangurLessonVisibilityGroup;
  ageGroup: KangurLessonAgeGroup;
  subject: KangurLessonSubject;
  componentId: KangurLessonComponentId;
}): string =>
  `${KANGUR_LESSON_COMPONENT_GROUP_NODE_PREFIX}${group}:${ageGroup}:${subject}:${componentId}`;

export const buildKangurLessonMasterNodes = (lessons: KangurLesson[]): MasterTreeNode[] =>
  [...lessons]
    .sort((left, right) => {
      const orderDelta = left.sortOrder - right.sortOrder;
      if (orderDelta !== 0) return orderDelta;
      return left.id.localeCompare(right.id);
    })
    .map((lesson, index) => ({
      id: toKangurLessonNodeId(lesson.id),
      type: 'file' as const,
      kind: 'kangur-lesson',
      parentId: null,
      name: lesson.title,
      path: lesson.id,
      sortOrder: (index + 1) * KANGUR_LESSON_SORT_ORDER_GAP,
      metadata: {
        kangurLesson: {
          lessonId: lesson.id,
          componentId: lesson.componentId,
          contentMode: lesson.contentMode,
          enabled: lesson.enabled,
          description: lesson.description,
        },
        search: {
          lessonId: lesson.id,
          componentId: lesson.componentId,
          contentMode: lesson.contentMode,
          ageGroup: lesson.ageGroup,
          subject: lesson.subject,
          title: lesson.title,
          description: lesson.description,
          visibility: lesson.enabled ? 'enabled' : 'hidden',
        },
      },
    }));

const LESSON_VISIBILITY_GROUPS: Array<LabeledOptionDto<KangurLessonVisibilityGroup>> = [
  { value: 'enabled', label: 'Visible lessons' },
  { value: 'hidden', label: 'Hidden lessons' },
];

const LESSON_SUBJECT_GROUPS: Array<LabeledOptionDto<KangurLessonSubject>> = KANGUR_SUBJECTS.map(
  (subject) => ({
    value: subject.id,
    label: subject.label,
  })
);

const LESSON_AGE_GROUPS: Array<LabeledOptionDto<KangurLessonAgeGroup>> = KANGUR_AGE_GROUPS.map(
  (group) => ({
    value: group.id,
    label: group.label,
  })
);

const buildLessonSearchMetadata = (lesson: KangurLesson): Record<string, string> => ({
  lessonId: lesson.id,
  componentId: lesson.componentId,
  contentMode: lesson.contentMode,
  ageGroup: lesson.ageGroup,
  subject: lesson.subject,
  title: lesson.title,
  description: lesson.description,
  visibility: lesson.enabled ? 'enabled' : 'hidden',
});

export const buildKangurLessonCatalogMasterNodes = (lessons: KangurLesson[]): MasterTreeNode[] => {
  const componentLabelById = new Map(
    KANGUR_LESSON_COMPONENT_OPTIONS.map((option): [KangurLessonComponentId, string] => [
      option.value,
      option.label,
    ])
  );
  const nodes: MasterTreeNode[] = [];
  let nextSortOrder = KANGUR_LESSON_SORT_ORDER_GAP;

  LESSON_VISIBILITY_GROUPS.forEach((group, groupIndex) => {
    const groupLessons = lessons
      .filter((lesson) => (group.value === 'enabled' ? lesson.enabled : !lesson.enabled))
      .sort((left, right) => {
        const componentDelta = left.componentId.localeCompare(right.componentId);
        if (componentDelta !== 0) return componentDelta;
        const orderDelta = left.sortOrder - right.sortOrder;
        if (orderDelta !== 0) return orderDelta;
        return left.id.localeCompare(right.id);
      });

    const visibilityNodeId = toKangurLessonVisibilityGroupNodeId(group.value);
    nodes.push({
      id: visibilityNodeId,
      type: 'folder',
      kind: 'kangur-lesson-group',
      parentId: null,
      name: group.label,
      path: group.value,
      sortOrder: (groupIndex + 1) * KANGUR_LESSON_SORT_ORDER_GAP,
      metadata: {
        kangurLessonGroup: {
          kind: 'visibility',
          visibility: group.value,
          lessonCount: groupLessons.length,
        },
        search: {
          visibility: group.value,
          groupLabel: group.label,
          lessonCount: String(groupLessons.length),
        },
      },
    });

    LESSON_AGE_GROUPS.forEach((ageGroup, ageGroupIndex) => {
      const ageGroupLessons = groupLessons.filter((lesson) => lesson.ageGroup === ageGroup.value);
      const ageGroupNodeId = toKangurLessonAgeGroupGroupNodeId({
        group: group.value,
        ageGroup: ageGroup.value,
      });
      nodes.push({
        id: ageGroupNodeId,
        type: 'folder',
        kind: 'kangur-lesson-age-group-group',
        parentId: visibilityNodeId,
        name: ageGroup.label,
        path: `${group.value}/${ageGroup.value}`,
        sortOrder: (ageGroupIndex + 1) * KANGUR_LESSON_SORT_ORDER_GAP,
        metadata: {
          kangurLessonGroup: {
            kind: 'ageGroup',
            visibility: group.value,
            ageGroup: ageGroup.value,
            lessonCount: ageGroupLessons.length,
          },
          search: {
            visibility: group.value,
            ageGroup: ageGroup.value,
            groupLabel: ageGroup.label,
            lessonCount: String(ageGroupLessons.length),
          },
        },
      });

      LESSON_SUBJECT_GROUPS.forEach((subject, subjectIndex) => {
        const subjectLessons = ageGroupLessons.filter((lesson) => lesson.subject === subject.value);
        const subjectNodeId = toKangurLessonSubjectGroupNodeId({
          group: group.value,
          ageGroup: ageGroup.value,
          subject: subject.value,
        });
        nodes.push({
          id: subjectNodeId,
          type: 'folder',
          kind: 'kangur-lesson-subject-group',
          parentId: ageGroupNodeId,
          name: subject.label,
          path: `${group.value}/${ageGroup.value}/${subject.value}`,
          sortOrder: (subjectIndex + 1) * KANGUR_LESSON_SORT_ORDER_GAP,
          metadata: {
            kangurLessonGroup: {
              kind: 'subject',
              visibility: group.value,
              ageGroup: ageGroup.value,
              subject: subject.value,
              lessonCount: subjectLessons.length,
            },
            search: {
              visibility: group.value,
              ageGroup: ageGroup.value,
              subject: subject.value,
              groupLabel: subject.label,
              lessonCount: String(subjectLessons.length),
            },
          },
        });

        const componentIds = [
          ...new Set(subjectLessons.map((lesson): KangurLessonComponentId => lesson.componentId)),
        ];
        componentIds.forEach((componentId, componentIndex) => {
          const componentLessons = subjectLessons.filter(
            (lesson) => lesson.componentId === componentId
          );
          const componentLabel = componentLabelById.get(componentId) ?? componentId;
          const componentNodeId = toKangurLessonComponentGroupNodeId({
            group: group.value,
            ageGroup: ageGroup.value,
            subject: subject.value,
            componentId,
          });
          nodes.push({
            id: componentNodeId,
            type: 'folder',
            kind: 'kangur-lesson-component-group',
            parentId: subjectNodeId,
            name: componentLabel,
            path: `${group.value}/${ageGroup.value}/${subject.value}/${componentId}`,
            sortOrder: (componentIndex + 1) * KANGUR_LESSON_SORT_ORDER_GAP,
            metadata: {
              kangurLessonGroup: {
                kind: 'component',
                visibility: group.value,
                ageGroup: ageGroup.value,
                subject: subject.value,
                componentId,
                lessonCount: componentLessons.length,
              },
              search: {
                visibility: group.value,
                ageGroup: ageGroup.value,
                subject: subject.value,
                componentId,
                groupLabel: componentLabel,
                lessonCount: String(componentLessons.length),
              },
            },
          });

          componentLessons.forEach((lesson) => {
            nodes.push({
              id: toKangurLessonNodeId(lesson.id),
              type: 'file' as const,
              kind: 'kangur-lesson',
              parentId: componentNodeId,
              name: lesson.title,
              path: `${group.value}/${ageGroup.value}/${subject.value}/${componentId}/${lesson.id}`,
              sortOrder: nextSortOrder,
              metadata: {
                kangurLesson: {
                  lessonId: lesson.id,
                  componentId: lesson.componentId,
                  contentMode: lesson.contentMode,
                  enabled: lesson.enabled,
                  description: lesson.description,
                },
                search: buildLessonSearchMetadata(lesson),
              },
            });
            nextSortOrder += KANGUR_LESSON_SORT_ORDER_GAP;
          });
        });
      });
    });
  });

  return nodes;
};

export const resolveKangurLessonOrderFromNodes = (
  nextNodes: MasterTreeNode[],
  lessonById: Map<string, KangurLesson>
): KangurLesson[] => {
  const orderedLessons = nextNodes
    .filter((node) => node.type === 'file' && node.kind === 'kangur-lesson')
    .sort((left, right) => left.sortOrder - right.sortOrder)
    .flatMap((node) => {
      const lessonId = fromKangurLessonNodeId(node.id);
      if (!lessonId) return [];
      const lesson = lessonById.get(lessonId);
      return lesson ? [lesson] : [];
    });

  if (orderedLessons.length === 0) {
    return [...lessonById.values()]
      .sort((left, right) => left.sortOrder - right.sortOrder)
      .map((lesson, index) => ({
        ...lesson,
        sortOrder: (index + 1) * KANGUR_LESSON_SORT_ORDER_GAP,
      }));
  }

  return orderedLessons.map((lesson, index) => ({
    ...lesson,
    sortOrder: (index + 1) * KANGUR_LESSON_SORT_ORDER_GAP,
  }));
};

import type { KangurTestSuite } from '@/features/kangur/shared/contracts/kangur-tests';
import type { MasterTreeNode } from '@/features/kangur/shared/utils/master-folder-tree-contract';
import type { LabeledOptionDto } from '@/shared/contracts/base';

import { KANGUR_TEST_SUITE_SORT_ORDER_GAP } from '../test-suites';

const SUITE_NODE_PREFIX = 'kangur-test-suite:';
const SUITE_GROUP_NODE_PREFIX = 'kangur-test-suite-group:';
const SUITE_CATEGORY_GROUP_NODE_PREFIX = 'kangur-test-suite-category-group:';

type SuiteVisibilityGroup = 'enabled' | 'disabled';

export const toKangurTestSuiteNodeId = (suiteId: string): string =>
  `${SUITE_NODE_PREFIX}${suiteId}`;

export const fromKangurTestSuiteNodeId = (nodeId: string): string | null => {
  if (!nodeId.startsWith(SUITE_NODE_PREFIX)) return null;
  const suiteId = nodeId.slice(SUITE_NODE_PREFIX.length).trim();
  return suiteId || null;
};

export const buildKangurTestSuiteMasterNodes = (suites: KangurTestSuite[]): MasterTreeNode[] =>
  [...suites]
    .sort((a, b) => {
      const delta = a.sortOrder - b.sortOrder;
      return delta !== 0 ? delta : a.id.localeCompare(b.id);
    })
    .map((suite, index) => ({
      id: toKangurTestSuiteNodeId(suite.id),
      type: 'file' as const,
      kind: 'kangur-test-suite',
      parentId: null,
      name: suite.title,
      path: suite.id,
      sortOrder: (index + 1) * KANGUR_TEST_SUITE_SORT_ORDER_GAP,
      metadata: {
        kangurTestSuite: {
          suiteId: suite.id,
          category: suite.category,
          year: suite.year,
          gradeLevel: suite.gradeLevel,
          enabled: suite.enabled,
        },
        search: {
          suiteId: suite.id,
          title: suite.title,
          description: suite.description,
          category: suite.category,
          gradeLevel: suite.gradeLevel,
          year: suite.year !== null ? String(suite.year) : '',
          visibility: suite.enabled ? 'enabled' : 'disabled',
        },
      },
    }));

const SUITE_VISIBILITY_GROUPS: Array<LabeledOptionDto<SuiteVisibilityGroup>> = [
  { value: 'enabled', label: 'Active suites' },
  { value: 'disabled', label: 'Disabled suites' },
];

const normalizeSuiteGroupLabel = (value: string): string => {
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : 'custom';
};

const toKangurTestSuiteCategoryGroupNodeId = (
  visibility: SuiteVisibilityGroup,
  category: string
): string =>
  `${SUITE_CATEGORY_GROUP_NODE_PREFIX}${visibility}:${encodeURIComponent(
    normalizeSuiteGroupLabel(category)
  )}`;

export const buildKangurTestSuiteCatalogMasterNodes = (
  suites: KangurTestSuite[],
  groupTitleBySuiteId?: Map<string, string>
): MasterTreeNode[] => {
  const nodes: MasterTreeNode[] = [];
  let nextSortOrder = KANGUR_TEST_SUITE_SORT_ORDER_GAP;

  SUITE_VISIBILITY_GROUPS.forEach((group, groupIndex) => {
    const groupSuites = suites
      .filter((s) => (group.value === 'enabled' ? s.enabled : !s.enabled))
      .sort((a, b) => {
        const catDelta = a.category.localeCompare(b.category);
        if (catDelta !== 0) return catDelta;
        const orderDelta = a.sortOrder - b.sortOrder;
        return orderDelta !== 0 ? orderDelta : a.id.localeCompare(b.id);
      });

    const visibilityNodeId = `${SUITE_GROUP_NODE_PREFIX}${group.value}`;
    nodes.push({
      id: visibilityNodeId,
      type: 'folder',
      kind: 'kangur-test-suite-group',
      parentId: null,
      name: group.label,
      path: group.value,
      sortOrder: (groupIndex + 1) * KANGUR_TEST_SUITE_SORT_ORDER_GAP,
      metadata: {
        kangurTestSuiteGroup: { visibility: group.value, suiteCount: groupSuites.length },
        search: { visibility: group.value, groupLabel: group.label },
      },
    });

    const suitesByCategory = new Map<string, KangurTestSuite[]>();
    groupSuites.forEach((suite) => {
      const category = normalizeSuiteGroupLabel(
        groupTitleBySuiteId?.get(suite.id) ?? suite.category
      );
      const categorySuites = suitesByCategory.get(category) ?? [];
      categorySuites.push(suite);
      suitesByCategory.set(category, categorySuites);
    });

    Array.from(suitesByCategory.keys())
      .sort((a, b) => a.localeCompare(b))
      .forEach((category) => {
        const categoryNodeId = toKangurTestSuiteCategoryGroupNodeId(group.value, category);
        const categorySuites = suitesByCategory.get(category) ?? [];

        nodes.push({
          id: categoryNodeId,
          type: 'folder',
          kind: 'kangur-test-suite-category-group',
          parentId: visibilityNodeId,
          name: category,
          path: `${group.value}/${category}`,
          sortOrder: nextSortOrder,
          metadata: {
            kangurTestSuiteCategoryGroup: {
              visibility: group.value,
              category,
              suiteCount: categorySuites.length,
            },
            search: {
              visibility: group.value,
              category,
              groupLabel: category,
            },
          },
        });
        nextSortOrder += KANGUR_TEST_SUITE_SORT_ORDER_GAP;

        categorySuites.forEach((suite) => {
          nodes.push({
            id: toKangurTestSuiteNodeId(suite.id),
            type: 'file' as const,
            kind: 'kangur-test-suite',
            parentId: categoryNodeId,
            name: suite.title,
            path: `${group.value}/${category}/${suite.id}`,
            sortOrder: nextSortOrder,
            metadata: {
              kangurTestSuite: {
                suiteId: suite.id,
                category: suite.category,
                year: suite.year,
                gradeLevel: suite.gradeLevel,
                enabled: suite.enabled,
              },
              search: {
                suiteId: suite.id,
                title: suite.title,
                description: suite.description,
                category: suite.category,
                gradeLevel: suite.gradeLevel,
                year: suite.year !== null ? String(suite.year) : '',
                visibility: group.value,
              },
            },
          });
          nextSortOrder += KANGUR_TEST_SUITE_SORT_ORDER_GAP;
        });
      });
  });

  return nodes;
};

export const resolveKangurTestSuiteOrderFromNodes = (
  nextNodes: MasterTreeNode[],
  suiteById: Map<string, KangurTestSuite>
): KangurTestSuite[] => {
  const ordered = nextNodes
    .filter((n) => n.type === 'file' && n.kind === 'kangur-test-suite')
    .sort((a, b) => a.sortOrder - b.sortOrder)
    .flatMap((n) => {
      const suiteId = fromKangurTestSuiteNodeId(n.id);
      if (!suiteId) return [];
      const suite = suiteById.get(suiteId);
      return suite ? [suite] : [];
    });

  if (ordered.length === 0) {
    return [...suiteById.values()].sort((a, b) => a.sortOrder - b.sortOrder);
  }

  return ordered.map((suite, index) => ({
    ...suite,
    sortOrder: (index + 1) * KANGUR_TEST_SUITE_SORT_ORDER_GAP,
  }));
};

import type { KangurLesson, KangurLessonDocument } from '@/features/kangur/shared/contracts/kangur';
import { withKangurClientErrorSync } from '@/features/kangur/observability/client';

const LESSON_CONTENT_EDITOR_DRAFT_STORAGE_PREFIX = 'kangur-lesson-editor-draft:v1:';

type LessonContentEditorLocalDraft = {
  version: 1;
  lesson: KangurLesson;
  document: KangurLessonDocument;
  savedAt: string;
};

const getLessonContentEditorDraftStorageKey = (lessonId: string): string =>
  `${LESSON_CONTENT_EDITOR_DRAFT_STORAGE_PREFIX}${lessonId}`;

export const readLessonContentEditorDraft = (
  lessonId: string
): LessonContentEditorLocalDraft | null => {
  if (typeof window === 'undefined') return null;

  return withKangurClientErrorSync(
    {
      source: 'kangur.admin.lesson-content-editor-drafts',
      action: 'read',
      description: 'Reads the lesson content editor draft from local storage.',
      context: { lessonId },
    },
    () => {
      const raw = window.localStorage.getItem(getLessonContentEditorDraftStorageKey(lessonId));
      if (!raw) return null;
      const parsed = JSON.parse(raw) as LessonContentEditorLocalDraft;
      if (
        parsed?.version !== 1 ||
        !parsed.lesson ||
        !parsed.document ||
        typeof parsed.savedAt !== 'string'
      ) {
        return null;
      }
      return parsed;
    },
    { fallback: null }
  );
};

export const writeLessonContentEditorDraft = ({
  lesson,
  document,
  savedAt = new Date().toISOString(),
}: {
  lesson: KangurLesson;
  document: KangurLessonDocument;
  savedAt?: string;
}): string | null => {
  if (typeof window === 'undefined') return null;

  return withKangurClientErrorSync(
    {
      source: 'kangur.admin.lesson-content-editor-drafts',
      action: 'write',
      description: 'Persists the lesson content editor draft in local storage.',
      context: { lessonId: lesson.id },
    },
    () => {
      window.localStorage.setItem(
        getLessonContentEditorDraftStorageKey(lesson.id),
        JSON.stringify({
          version: 1,
          lesson,
          document,
          savedAt,
        } satisfies LessonContentEditorLocalDraft)
      );
      return savedAt;
    },
    { fallback: null }
  );
};

export const clearLessonContentEditorDraft = (lessonId: string): void => {
  if (typeof window === 'undefined') return;

  withKangurClientErrorSync(
    {
      source: 'kangur.admin.lesson-content-editor-drafts',
      action: 'clear',
      description: 'Clears the lesson content editor draft from local storage.',
      context: { lessonId },
    },
    () => {
      window.localStorage.removeItem(getLessonContentEditorDraftStorageKey(lessonId));
    },
    { fallback: undefined }
  );
};

