export const getQuestionWorkflowLabel = (
  workflowStatus: KangurTestQuestionWorkflowStatus,
  locale: string | null | undefined = 'en'
): string => {
  const resolvedLocale = resolveKangurAdminLocale(locale);

  return QUESTION_AUTHORING_MESSAGES[resolvedLocale].workflowLabels[workflowStatus];
};

const VISUAL_PROMPT_PATTERN =
  /(patrz|rysun(?:ek|ku)?|obraz(?:ek|ku)?|diagram|schemat|widoczne|zobacz|plansz|tabel|figu|klo(?:cek|cki)|plytk|płytk)/i;

const normalizeChoiceText = (value: string): string => value.trim().replace(/\s+/g, ' ').toLowerCase();

const hasIllustrationContent = (illustration: KangurQuestionIllustration): boolean => {
  if (illustration.type === 'none') {
    return false;
  }

  if (illustration.type === 'single') {
    return illustration.svgContent.trim().length > 0;
  }

  return illustration.panels.some((panel) => panel.svgContent.trim().length > 0);
};

const hasChoiceSvg = (choices: KangurTestChoice[]): boolean =>
  choices.some((choice) => choice.svgContent?.trim().length > 0);

const hasChoiceSvgWithoutDescription = (choices: KangurTestChoice[]): boolean =>
  choices.some(
    (choice) =>
      choice.svgContent?.trim().length > 0 && (choice.description?.trim().length ?? 0) === 0
  );

const hasDuplicateNormalizedChoiceText = (choices: KangurTestChoice[]): boolean => {
  const seen = new Set<string>();
  for (const choice of choices) {
    const normalized = normalizeChoiceText(choice.text);
    if (!normalized) {
      continue;
    }
    if (seen.has(normalized)) {
      return true;
    }
    seen.add(normalized);
  }
  return false;
};

const hasDuplicateLabels = (choices: KangurTestChoice[]): boolean => {
  const seen = new Set<string>();
  for (const choice of choices) {
    const normalized = choice.label.trim().toUpperCase();
    if (!normalized) {
      continue;
    }
    if (seen.has(normalized)) {
      return true;
    }
    seen.add(normalized);
  }
  return false;
};

const getLegacyFixMessage = (
  editorial: KangurTestQuestionEditorial,
  locale: KangurAdminLocaleDto
): string =>
  editorial.note?.trim() || QUESTION_AUTHORING_MESSAGES[locale].issues.legacy_fix_required;

const buildIssues = (
  draft: QuestionAuthoringDraftLike,
  locale: KangurAdminLocaleDto
): QuestionAuthoringIssue[] => {
  const issues: QuestionAuthoringIssue[] = [];
  const localizedMessages = QUESTION_AUTHORING_MESSAGES[locale].issues;
  const prompt = draft.prompt.trim();
  const explanation = (draft.explanation ?? '').trim();
  const hasVisualSupport =
    hasIllustrationContent(draft.illustration) || hasChoiceSvg(draft.choices);

  if (!prompt) {
    issues.push({
      code: 'missing_prompt',
      severity: 'blocker',
      message: localizedMessages.missing_prompt,
    });
  }

  if (draft.choices.length < 2) {
    issues.push({
      code: 'not_enough_choices',
      severity: 'blocker',
      message: localizedMessages.not_enough_choices,
    });
  }

  if (draft.choices.some((choice) => choice.label.trim().length === 0)) {
    issues.push({
      code: 'missing_choice_label',
      severity: 'blocker',
      message: localizedMessages.missing_choice_label,
    });
  }

  if (hasDuplicateLabels(draft.choices)) {
    issues.push({
      code: 'duplicate_choice_labels',
      severity: 'blocker',
      message: localizedMessages.duplicate_choice_labels,
    });
  }

  if (draft.choices.some((choice) => choice.text.trim().length === 0)) {
    issues.push({
      code: 'empty_choice_text',
      severity: 'blocker',
      message: localizedMessages.empty_choice_text,
    });
  }

  if (hasDuplicateNormalizedChoiceText(draft.choices)) {
    issues.push({
      code: 'duplicate_choice_text',
      severity: 'blocker',
      message: localizedMessages.duplicate_choice_text,
    });
  }

  if (!draft.choices.some((choice) => choice.label === draft.correctChoiceLabel)) {
    issues.push({
      code: 'missing_correct_choice',
      severity: 'blocker',
      message: localizedMessages.missing_correct_choice,
    });
  }

  if (
    draft.presentation.layout !== 'classic' &&
    !hasIllustrationContent(draft.illustration)
  ) {
    issues.push({
      code: 'split_layout_without_illustration',
      severity: 'blocker',
      message: localizedMessages.split_layout_without_illustration,
    });
  }

  if (draft.editorial.reviewStatus === 'needs-fix') {
    issues.push({
      code: 'legacy_fix_required',
      severity: 'blocker',
      message: getLegacyFixMessage(draft.editorial, locale),
    });
  }

  if (!explanation) {
    issues.push({
      code: 'missing_explanation',
      severity: 'warning',
      message: localizedMessages.missing_explanation,
    });
  }

  if (prompt && VISUAL_PROMPT_PATTERN.test(prompt) && !hasVisualSupport) {
    issues.push({
      code: 'visual_prompt_without_visuals',
      severity: 'warning',
      message: localizedMessages.visual_prompt_without_visuals,
    });
  }

  if (hasChoiceSvgWithoutDescription(draft.choices)) {
    issues.push({
      code: 'choice_svg_without_note',
      severity: 'warning',
      message: localizedMessages.choice_svg_without_note,
    });
  }

  if (draft.editorial.reviewStatus === 'needs-review') {
    issues.push({
      code: 'legacy_review_required',
      severity: 'warning',
      message:
        draft.editorial.note?.trim() ||
        localizedMessages.legacy_review_required,
    });
  }

  const hasWarnings = issues.some((issue) => issue.severity === 'warning');
  if (draft.editorial.workflowStatus === 'ready' && hasWarnings) {
    issues.push({
      code: 'ready_workflow_requires_clean_review',
      severity: 'blocker',
      message: localizedMessages.ready_workflow_requires_clean_review,
    });
  }

  if (draft.editorial.workflowStatus === 'published' && hasWarnings) {
    issues.push({
      code: 'published_workflow_requires_clean_review',
      severity: 'blocker',
      message: localizedMessages.published_workflow_requires_clean_review,
    });
  }

  return issues;
};

const resolveQuestionAuthoringStatus = (
  blockers: QuestionAuthoringIssue[],
  warnings: QuestionAuthoringIssue[]
): QuestionAuthoringStatus => {
  if (blockers.length > 0) return 'needs-fix';
  if (warnings.length > 0) return 'needs-review';
  return 'ready';
};

const resolveWorkflowDefaultNextAction = (
  workflowStatus: KangurTestQuestionWorkflowStatus,
  localizedMessages: (typeof QUESTION_AUTHORING_MESSAGES)[KangurAdminLocaleDto]
): string => {
  if (workflowStatus === 'published') {
    return localizedMessages.publishedClean;
  }
  if (workflowStatus === 'ready') {
    return localizedMessages.readyToPublish;
  }
  return localizedMessages.savedDraft;
};

const resolveQuestionAuthoringNextAction = (args: {
  draft: QuestionAuthoringDraftLike | KangurTestQuestion;
  blockers: QuestionAuthoringIssue[];
  warnings: QuestionAuthoringIssue[];
  localizedMessages: (typeof QUESTION_AUTHORING_MESSAGES)[KangurAdminLocaleDto];
}): string =>
  args.blockers[0]?.message ??
  args.warnings[0]?.message ??
  resolveWorkflowDefaultNextAction(args.draft.editorial.workflowStatus, args.localizedMessages);

export const getQuestionAuthoringSummary = (
  draft: QuestionAuthoringDraftLike | KangurTestQuestion,
  locale: string | null | undefined = 'en'
): QuestionAuthoringSummary => {
  const resolvedLocale = resolveKangurAdminLocale(locale);
  const localizedMessages = QUESTION_AUTHORING_MESSAGES[resolvedLocale];
  const issues = buildIssues(draft, resolvedLocale);
  const blockers = issues.filter((issue) => issue.severity === 'blocker');
  const warnings = issues.filter((issue) => issue.severity === 'warning');
  const status = resolveQuestionAuthoringStatus(blockers, warnings);
  const nextAction = resolveQuestionAuthoringNextAction({
    draft,
    blockers,
    warnings,
    localizedMessages,
  });

  return {
    status,
    blockers,
    warnings,
    nextAction,
    workflowStatus: draft.editorial.workflowStatus,
  };
};

import type { IdLabelOption } from '@/shared/contracts/base';

import type { QuestionFormData } from '../test-suites/questions';
import { resolveKangurAdminLocale } from './kangur-admin-locale';
import type { QuestionAuthoringIssue } from './question-authoring-insights';

export type QuestionAuthoringRepairId =
  | 'auto-label-choices'
  | 'set-first-choice-correct'
  | 'switch-layout-classic'
  | 'add-explanation-starter'
  | 'add-svg-choice-notes';

export type QuestionAuthoringRepairAction = IdLabelOption<QuestionAuthoringRepairId>;

const CHOICE_LABELS = 'ABCDEFGHIJ'.split('');

const uniqueRepairs = (
  repairs: QuestionAuthoringRepairAction[]
): QuestionAuthoringRepairAction[] => {
  const seen = new Set<QuestionAuthoringRepairId>();
  return repairs.filter((repair) => {
    if (seen.has(repair.id)) {
      return false;
    }
    seen.add(repair.id);
    return true;
  });
};

export const getQuestionAuthoringRepairActions = (
  issues: readonly QuestionAuthoringIssue[],
  locale: string | null | undefined = 'en'
): QuestionAuthoringRepairAction[] => {
  const resolvedLocale = resolveKangurAdminLocale(locale);
  const labelsByLocale = {
    en: {
      'auto-label-choices': 'Auto-label choices',
      'set-first-choice-correct': 'Use first choice as correct',
      'switch-layout-classic': 'Switch to classic layout',
      'add-explanation-starter': 'Add explanation starter',
      'add-svg-choice-notes': 'Add starter notes for SVG choices',
    },
    pl: {
      'auto-label-choices': 'Auto-etykietuj odpowiedzi',
      'set-first-choice-correct': 'Użyj pierwszej odpowiedzi jako poprawnej',
      'switch-layout-classic': 'Przełącz na klasyczny układ',
      'add-explanation-starter': 'Dodaj starter wyjaśnienia',
      'add-svg-choice-notes': 'Dodaj starter notatek dla odpowiedzi SVG',
    },
    uk: {
      'auto-label-choices': 'Автоматично позначити варіанти',
      'set-first-choice-correct': 'Використати перший варіант як правильний',
      'switch-layout-classic': 'Перемкнутися на класичний макет',
      'add-explanation-starter': 'Додати старт пояснення',
      'add-svg-choice-notes': 'Додати стартові нотатки для SVG-варіантів',
    },
  } as const;

  return uniqueRepairs(
    issues.flatMap<QuestionAuthoringRepairAction>((issue) => {
      switch (issue.code) {
        case 'missing_choice_label':
        case 'duplicate_choice_labels':
          return [
            {
              id: 'auto-label-choices',
              label: labelsByLocale[resolvedLocale]['auto-label-choices'],
            },
          ];
        case 'missing_correct_choice':
          return [
            {
              id: 'set-first-choice-correct',
              label: labelsByLocale[resolvedLocale]['set-first-choice-correct'],
            },
          ];
        case 'split_layout_without_illustration':
          return [
            {
              id: 'switch-layout-classic',
              label: labelsByLocale[resolvedLocale]['switch-layout-classic'],
            },
          ];
        case 'missing_explanation':
          return [
            {
              id: 'add-explanation-starter',
              label: labelsByLocale[resolvedLocale]['add-explanation-starter'],
            },
          ];
        case 'choice_svg_without_note':
          return [
            {
              id: 'add-svg-choice-notes',
              label: labelsByLocale[resolvedLocale]['add-svg-choice-notes'],
            },
          ];
        default:
          return [];
      }
    })
  );
};

export const applyQuestionAuthoringRepair = (
  formData: QuestionFormData,
  repairId: QuestionAuthoringRepairId,
  locale: string | null | undefined = 'en'
): QuestionFormData => {
  const resolvedLocale = resolveKangurAdminLocale(locale);

  switch (repairId) {
    case 'auto-label-choices': {
      const choices = formData.choices.map((choice, index) => ({
        ...choice,
        label: CHOICE_LABELS[index] ?? String.fromCharCode(65 + index),
      }));
      const oldCorrectIndex = formData.choices.findIndex(
        (choice) => choice.label === formData.correctChoiceLabel
      );
      return {
        ...formData,
        choices,
        correctChoiceLabel:
          oldCorrectIndex >= 0
            ? (choices[oldCorrectIndex]?.label ?? formData.correctChoiceLabel)
            : formData.correctChoiceLabel,
      };
    }
    case 'set-first-choice-correct':
      return {
        ...formData,
        correctChoiceLabel: formData.choices[0]?.label ?? '',
      };
    case 'switch-layout-classic':
      return {
        ...formData,
        presentation: {
          ...formData.presentation,
          layout: 'classic',
        },
      };
    case 'add-explanation-starter': {
      const correctChoice = formData.choices.find(
        (choice) => choice.label === formData.correctChoiceLabel
      );
      const explanation =
        correctChoice?.text.trim()
          ? resolvedLocale === 'uk'
            ? `Правильна відповідь: ${correctChoice.label}: ${correctChoice.text}. Додайте тут покрокове пояснення.`
            : resolvedLocale === 'pl'
              ? `Poprawna odpowiedź to ${correctChoice.label}: ${correctChoice.text}. Dodaj tutaj wypracowane uzasadnienie.`
              : `The correct answer is ${correctChoice.label}: ${correctChoice.text}. Add the worked reasoning here.`
          : resolvedLocale === 'uk'
            ? 'Поясніть, чому правильна відповідь працює і чому інші варіанти не підходять.'
            : resolvedLocale === 'pl'
              ? 'Wyjaśnij, dlaczego poprawna odpowiedź działa i dlaczego pozostałe opcje nie pasują.'
              : 'Explain why the correct answer works and why the other options do not.';
      return {
        ...formData,
        explanation,
      };
    }
    case 'add-svg-choice-notes':
      return {
        ...formData,
        choices: formData.choices.map((choice) =>
          choice.svgContent?.trim().length > 0 && (choice.description?.trim().length ?? 0) === 0
            ? {
              ...choice,
              description: choice.label.trim()
                ? resolvedLocale === 'uk'
                  ? `Опишіть, що показано у варіанті ${choice.label}.`
                  : resolvedLocale === 'pl'
                    ? `Opisz, co pokazano w odpowiedzi ${choice.label}.`
                    : `Describe what is shown in option ${choice.label}.`
                : resolvedLocale === 'uk'
                  ? 'Опишіть, що показано в цьому варіанті.'
                  : resolvedLocale === 'pl'
                    ? 'Opisz, co pokazano w tej odpowiedzi.'
                    : 'Describe what is shown in this option.',
            }
            : choice
        ),
      };
    default:
      return formData;
  }
};

import type { KangurTestQuestion } from '@/features/kangur/shared/contracts/kangur-tests';

import type { QuestionFormData } from '../test-suites/questions';
import { withKangurClientErrorSync } from '@/features/kangur/observability/client';

const QUESTION_EDITOR_DRAFT_STORAGE_PREFIX = 'kangur-question-editor-draft:v1:';

export const QUESTION_EDITOR_NEW_DRAFT_SLOT = '__new__';

type QuestionEditorLocalDraft = {
  version: 1;
  suiteId: string;
  questionId: string;
  isNewQuestion: boolean;
  question: KangurTestQuestion;
  formData: QuestionFormData;
  savedAt: string;
};

const getQuestionEditorDraftStorageKey = (suiteId: string, questionId: string): string =>
  `${QUESTION_EDITOR_DRAFT_STORAGE_PREFIX}${suiteId}:${questionId}`;

export const readQuestionEditorDraft = (
  suiteId: string,
  questionId: string
): QuestionEditorLocalDraft | null => {
  if (typeof window === 'undefined') return null;

  return withKangurClientErrorSync(
    {
      source: 'kangur.admin.question-editor-drafts',
      action: 'read',
      description: 'Reads the question editor draft from local storage.',
      context: { suiteId, questionId },
    },
    () => {
      const raw = window.localStorage.getItem(getQuestionEditorDraftStorageKey(suiteId, questionId));
      if (!raw) return null;
      const parsed = JSON.parse(raw) as QuestionEditorLocalDraft;
      if (
        parsed?.version !== 1 ||
        parsed.suiteId !== suiteId ||
        parsed.questionId !== questionId ||
        typeof parsed.isNewQuestion !== 'boolean' ||
        !parsed.question ||
        !parsed.formData ||
        typeof parsed.savedAt !== 'string'
      ) {
        return null;
      }
      return parsed;
    },
    { fallback: null }
  );
};

export const writeQuestionEditorDraft = ({
  suiteId,
  questionId,
  isNewQuestion,
  question,
  formData,
  savedAt = new Date().toISOString(),
}: {
  suiteId: string;
  questionId: string;
  isNewQuestion: boolean;
  question: KangurTestQuestion;
  formData: QuestionFormData;
  savedAt?: string;
}): string | null => {
  if (typeof window === 'undefined') return null;

  return withKangurClientErrorSync(
    {
      source: 'kangur.admin.question-editor-drafts',
      action: 'write',
      description: 'Persists the question editor draft in local storage.',
      context: { suiteId, questionId, isNewQuestion },
    },
    () => {
      window.localStorage.setItem(
        getQuestionEditorDraftStorageKey(suiteId, questionId),
        JSON.stringify({
          version: 1,
          suiteId,
          questionId,
          isNewQuestion,
          question,
          formData,
          savedAt,
        } satisfies QuestionEditorLocalDraft)
      );
      return savedAt;
    },
    { fallback: null }
  );
};

export const clearQuestionEditorDraft = (suiteId: string, questionId: string): void => {
  if (typeof window === 'undefined') return;

  withKangurClientErrorSync(
    {
      source: 'kangur.admin.question-editor-drafts',
      action: 'clear',
      description: 'Clears the question editor draft from local storage.',
      context: { suiteId, questionId },
    },
    () => {
      window.localStorage.removeItem(getQuestionEditorDraftStorageKey(suiteId, questionId));
    },
    { fallback: undefined }
  );
};

